/// Subcommands for `ee playbook`.
#[derive(Clone, Debug, PartialEq, Subcommand)]
pub enum PlaybookCommand {
    /// Extract repeated semantic memories into procedural-rule curation candidates.
    Extract(PlaybookExtractArgs),
    /// List procedural rules in portable playbook form.
    List(PlaybookListArgs),
    /// Export procedural rules as a portable playbook artifact.
    Export(PlaybookExportArgs),
    /// Import a portable playbook artifact.
    Import(PlaybookImportArgs),
}

/// Arguments for `ee playbook extract`.
#[derive(Clone, Debug, Parser, PartialEq)]
pub struct PlaybookExtractArgs {
    /// Optional database path. Defaults to `<workspace>/.ee/ee.db`.
    #[arg(long, value_name = "PATH")]
    pub database: Option<PathBuf>,

    /// Only scan semantic memories created at or after this RFC 3339 timestamp.
    #[arg(long, value_name = "RFC3339")]
    pub since: Option<String>,

    /// Maximum number of semantic memories to scan.
    #[arg(long, default_value_t = 100)]
    pub limit: u32,

    /// Preview candidate creation without writing curation rows or audit.
    #[arg(long, action = ArgAction::SetTrue)]
    pub dry_run: bool,

    /// Actor recorded in audit metadata.
    #[arg(long, value_name = "ACTOR")]
    pub actor: Option<String>,
}

/// Arguments for `ee playbook list`.
#[derive(Clone, Debug, Parser, PartialEq)]
pub struct PlaybookListArgs {
    /// Optional database path. Defaults to `<workspace>/.ee/ee.db`.
    #[arg(long, value_name = "PATH")]
    pub database: Option<PathBuf>,

    /// Include tombstoned rules.
    #[arg(long, action = ArgAction::SetTrue)]
    pub include_tombstoned: bool,

    /// Maximum number of rules to list.
    #[arg(long, default_value_t = 100)]
    pub limit: u32,

    /// Number of rules to skip after deterministic ordering.
    #[arg(long, default_value_t = 0)]
    pub offset: u32,
}

/// Arguments for `ee playbook export`.
#[derive(Clone, Debug, Parser, PartialEq)]
pub struct PlaybookExportArgs {
    /// Optional database path. Defaults to `<workspace>/.ee/ee.db`.
    #[arg(long, value_name = "PATH")]
    pub database: Option<PathBuf>,

    /// Destination playbook JSON file. Existing files are never overwritten.
    #[arg(long = "out", value_name = "PATH")]
    pub output_path: PathBuf,

    /// Include tombstoned rules.
    #[arg(long, action = ArgAction::SetTrue)]
    pub include_tombstoned: bool,

    /// Maximum number of rules to export.
    #[arg(long, default_value_t = 1000)]
    pub limit: u32,

    /// Preview the export without writing files.
    #[arg(long, action = ArgAction::SetTrue)]
    pub dry_run: bool,
}

/// Arguments for `ee playbook import`.
#[derive(Clone, Debug, Parser, PartialEq)]
pub struct PlaybookImportArgs {
    /// Source playbook JSON file.
    #[arg(long = "source", value_name = "PATH")]
    pub source_path: PathBuf,

    /// Optional database path. Defaults to `<workspace>/.ee/ee.db`.
    #[arg(long, value_name = "PATH")]
    pub database: Option<PathBuf>,

    /// Apply the import. Without this flag, import is a dry run.
    #[arg(long, action = ArgAction::SetTrue)]
    pub apply: bool,

    /// Actor recorded in audit metadata when --apply is used.
    #[arg(long, value_name = "ACTOR")]
    pub actor: Option<String>,
}

/// Subcommands for `ee perf`.
#[derive(Clone, Debug, Eq, PartialEq, Subcommand)]
pub enum PerfCommand {
    /// Compare two normalized performance artifact summaries.
    Compare(PerfCompareArgs),
    /// Check performance budget posture for one normalized report.
    #[command(subcommand)]
    Budget(PerfBudgetCommand),
}

/// Subcommands for `ee perf budget`.
#[derive(Clone, Debug, Eq, PartialEq, Subcommand)]
pub enum PerfBudgetCommand {
    /// Check a normalized performance report against a named profile.
    Check(PerfBudgetCheckArgs),
}

/// Arguments for `ee perf compare`.
#[derive(Clone, Debug, Eq, Parser, PartialEq)]
pub struct PerfCompareArgs {
    /// Baseline normalized artifact summary JSON.
    #[arg(long, value_name = "PATH")]
    pub baseline: PathBuf,

    /// Candidate normalized artifact summary JSON.
    #[arg(long, value_name = "PATH")]
    pub candidate: PathBuf,
}

/// Arguments for `ee perf budget check`.
#[derive(Clone, Debug, Eq, Parser, PartialEq)]
pub struct PerfBudgetCheckArgs {
    /// Runtime/profile budget name expected by the report.
    #[arg(long, value_name = "PROFILE")]
    pub profile: String,

    /// Normalized performance artifact summary JSON.
    #[arg(long, value_name = "PATH")]
    pub report: PathBuf,
}

/// Subcommands for `ee config`.
#[derive(Clone, Debug, Eq, PartialEq, Subcommand)]
pub enum ConfigCommand {
    /// Show merged config values, optionally filtered by pattern.
    Show(ConfigShowArgs),
    /// Get one config key with source attribution.
    Get(ConfigGetArgs),
    /// Set one workspace config key in `.ee/config.toml`.
    Set(ConfigSetArgs),
}

/// Arguments for `ee config show`.
#[derive(Clone, Debug, Default, Eq, Parser, PartialEq)]
pub struct ConfigShowArgs {
    /// Optional key or glob-style namespace pattern, such as graph.*.
    pub pattern: Option<String>,

    /// Config path to inspect. Defaults to <workspace>/.ee/config.toml.
    #[arg(long, value_name = "PATH")]
    pub config: Option<PathBuf>,
}

/// Arguments for `ee config get`.
#[derive(Clone, Debug, Eq, Parser, PartialEq)]
pub struct ConfigGetArgs {
    /// Exact config key to read, such as graph.ppr.alpha.
    pub key: String,

    /// Config path to inspect. Defaults to <workspace>/.ee/config.toml.
    #[arg(long, value_name = "PATH")]
    pub config: Option<PathBuf>,
}

/// Arguments for `ee config set`.
#[derive(Clone, Debug, Eq, Parser, PartialEq)]
pub struct ConfigSetArgs {
    /// Exact config key to write, such as graph.ppr.alpha.
    pub key: String,

    /// New scalar value.
    pub value: String,

    /// Config path to update. Defaults to <workspace>/.ee/config.toml.
    #[arg(long, value_name = "PATH")]
    pub config: Option<PathBuf>,

    /// Report the planned write without mutating the config file.
    #[arg(long, action = ArgAction::SetTrue)]
    pub dry_run: bool,
}

/// Subcommands for `ee profile`.
#[derive(Clone, Debug, Eq, PartialEq, Subcommand)]
pub enum ProfileCommand {
    /// Plan or apply `.ee/config.toml` operating profile changes.
    #[command(subcommand)]
    Config(ProfileConfigCommand),
}

/// Subcommands for `ee profile config`.
#[derive(Clone, Debug, Eq, PartialEq, Subcommand)]
pub enum ProfileConfigCommand {
    /// Show exact profile TOML changes without writing.
    Plan(ProfileConfigPlanArgs),
    /// Write profile TOML changes unless `--dry-run` is set.
    Apply(ProfileConfigApplyArgs),
}

/// Arguments for `ee profile config plan`.
#[derive(Clone, Debug, Default, Eq, Parser, PartialEq)]
pub struct ProfileConfigPlanArgs {
    /// Override the host-adaptive recommendation.
    #[arg(long, value_name = "PROFILE", value_parser = parse_operating_profile)]
    pub profile: Option<OperatingProfile>,

    /// Config path to plan. Defaults to <workspace>/.ee/config.toml.
    #[arg(long, value_name = "PATH")]
    pub config: Option<PathBuf>,
}

/// Arguments for `ee profile config apply`.
#[derive(Clone, Debug, Default, Eq, Parser, PartialEq)]
pub struct ProfileConfigApplyArgs {
    /// Override the host-adaptive recommendation.
    #[arg(long, value_name = "PROFILE", value_parser = parse_operating_profile)]
    pub profile: Option<OperatingProfile>,

    /// Config path to update. Defaults to <workspace>/.ee/config.toml.
    #[arg(long, value_name = "PATH")]
    pub config: Option<PathBuf>,

    /// Report the planned write without mutating the config file.
    #[arg(long, action = ArgAction::SetTrue)]
    pub dry_run: bool,
}

/// Subcommands for `ee procedure`.
#[derive(Clone, Debug, Eq, PartialEq, Subcommand)]
pub enum ProcedureCommand {
    /// Propose a new procedure from recorder runs or evidence.
    Propose(ProcedureProposeArgs),
    /// Show details of a procedure.
    Show(ProcedureShowArgs),
    /// List procedures with optional filters.
    List(ProcedureListArgs),
    /// Export a procedure as Markdown, playbook, or a render-only skill capsule.
    Export(ProcedureExportArgs),
    /// Plan promotion through curation and audit paths without mutating state.
    Promote(ProcedurePromoteArgs),
    /// Retire a procedure with an audited reason.
    Retire(ProcedureRetireArgs),
    /// Verify a procedure against eval fixtures, repro packs, or claim evidence.
    Verify(ProcedureVerifyArgs),
    /// Detect failed-verification, stale-evidence, and dependency-contract drift.
    Drift(ProcedureDriftArgs),
}

/// Arguments for `ee procedure propose`.
#[derive(Clone, Debug, Eq, Parser, PartialEq)]
pub struct ProcedureProposeArgs {
    /// Title for the proposed procedure.
    #[arg(long, value_name = "TEXT")]
    pub title: String,

    /// Summary description of what the procedure accomplishes.
    #[arg(long, value_name = "TEXT")]
    pub summary: Option<String>,

    /// Source recorder run IDs to derive the procedure from.
    #[arg(long = "source-run", value_name = "RUN_ID")]
    pub source_runs: Vec<String>,

    /// Evidence IDs supporting this procedure.
    #[arg(long = "evidence", value_name = "ID")]
    pub evidence_ids: Vec<String>,

    /// Report the proposal without creating.
    #[arg(long, action = ArgAction::SetTrue)]
    pub dry_run: bool,
}

/// Arguments for `ee procedure show`.
#[derive(Clone, Debug, Eq, Parser, PartialEq)]
pub struct ProcedureShowArgs {
    /// Procedure ID to show.
    #[arg(value_name = "PROCEDURE_ID")]
    pub procedure_id: String,

    /// Include step details.
    #[arg(long, action = ArgAction::SetTrue, default_value_t = true)]
    pub include_steps: bool,

    /// Include verification history.
    #[arg(long, action = ArgAction::SetTrue)]
    pub include_verification: bool,
}

/// Arguments for `ee procedure list`.
#[derive(Clone, Debug, Default, Eq, Parser, PartialEq)]
pub struct ProcedureListArgs {
    /// Filter by status: candidate, verified, retired.
    #[arg(long, value_name = "STATUS")]
    pub status: Option<String>,

    /// Maximum number of results.
    #[arg(long, short = 'n', default_value_t = 20)]
    pub limit: u32,

    /// Include step counts in output.
    #[arg(long, action = ArgAction::SetTrue)]
    pub include_steps: bool,
}

/// Arguments for `ee procedure export`.
#[derive(Clone, Debug, Eq, Parser, PartialEq)]
pub struct ProcedureExportArgs {
    /// Procedure ID to export.
    #[arg(value_name = "PROCEDURE_ID")]
    pub procedure_id: String,

    /// Export artifact format: markdown, playbook, skill-capsule.
    #[arg(long = "export-format", default_value = "markdown")]
    pub export_format: String,

    /// Output file path (defaults to stdout).
    #[arg(long, short = 'o', value_name = "PATH")]
    pub output: Option<PathBuf>,
}

/// Arguments for `ee procedure promote`.
#[derive(Clone, Debug, Eq, Parser, PartialEq)]
pub struct ProcedurePromoteArgs {
    /// Procedure ID to promote.
    #[arg(value_name = "PROCEDURE_ID")]
    pub procedure_id: String,

    /// Target maturity: validated, mature, or retired.
    #[arg(long = "to", value_name = "MATURITY")]
    pub to_maturity: Option<String>,

    /// Build the promotion, curation, and audit plan without writing anything.
    #[arg(long, action = ArgAction::SetTrue)]
    pub dry_run: bool,

    /// Actor to include in the planned audit record.
    #[arg(long, value_name = "ACTOR")]
    pub actor: Option<String>,

    /// Review reason to include in the curation candidate.
    #[arg(long, value_name = "TEXT")]
    pub reason: Option<String>,
}

/// Arguments for `ee procedure retire`.
#[derive(Clone, Debug, Eq, Parser, PartialEq)]
pub struct ProcedureRetireArgs {
    /// Procedure ID to retire.
    #[arg(value_name = "PROCEDURE_ID")]
    pub procedure_id: String,

    /// Reason for retirement.
    #[arg(long, value_name = "TEXT")]
    pub reason: String,

    /// Actor to include in the audit record.
    #[arg(long, value_name = "ACTOR")]
    pub actor: Option<String>,
}

/// Arguments for `ee procedure verify`.
#[derive(Clone, Debug, Eq, Parser, PartialEq)]
pub struct ProcedureVerifyArgs {
    /// Procedure ID to verify.
    #[arg(value_name = "PROCEDURE_ID")]
    pub procedure_id: String,

    /// Source kind: eval_fixture, repro_pack, claim_evidence, recorder_run.
    #[arg(long, value_name = "KIND", default_value = "eval_fixture")]
    pub source_kind: String,

    /// Specific source IDs to verify against.
    #[arg(long = "source", value_name = "ID")]
    pub source_ids: Vec<String>,

    /// Report verification without recording.
    #[arg(long, action = ArgAction::SetTrue)]
    pub dry_run: bool,

    /// Allow verification failures without returning error exit code.
    #[arg(long, action = ArgAction::SetTrue)]
    pub allow_failure: bool,
}

/// Arguments for `ee procedure drift`.
#[derive(Clone, Debug, Eq, Parser, PartialEq)]
pub struct ProcedureDriftArgs {
    /// Procedure ID to inspect for drift.
    #[arg(value_name = "PROCEDURE_ID")]
    pub procedure_id: String,

    /// Fixed RFC 3339 check timestamp for deterministic reports.
    #[arg(long, value_name = "RFC3339")]
    pub checked_at: Option<String>,

    /// Evidence older than this many days is stale.
    #[arg(long, default_value_t = 30)]
    pub staleness_threshold_days: u32,

    /// Failed verification ID to include as a high-severity drift signal.
    #[arg(long, value_name = "VERIFICATION_ID")]
    pub failed_verification: Option<String>,

    /// Source IDs checked by the failed verification.
    #[arg(long = "failed-source", value_name = "SOURCE_ID")]
    pub failed_sources: Vec<String>,

    /// Evidence freshness observation as `ID|LAST_SEEN_AT|SOURCE_KIND`.
    #[arg(long = "evidence", value_name = "ID|LAST_SEEN_AT|SOURCE_KIND")]
    pub evidence: Vec<String>,

    /// Dependency contract observation as `NAME|SURFACE|EXPECTED|ACTUAL|COMPATIBILITY`.
    #[arg(
        long = "dependency-contract",
        value_name = "NAME|SURFACE|EXPECTED|ACTUAL|COMPATIBILITY"
    )]
    pub dependency_contracts: Vec<String>,
}

/// Subcommands for `ee recorder`.
#[derive(Clone, Debug, PartialEq, Subcommand)]
pub enum RecorderCommand {
    /// Start a new recording session.
    Start(RecorderStartArgs),
    /// Record an event to an active session.
    Event(RecorderEventArgs),
    /// Finish a recording session.
    Finish(RecorderFinishArgs),
    /// Tail recent events from a recording session.
    Tail(RecorderTailArgs),
    /// Follow recorder events as JSON lines.
    Follow(RecorderFollowArgs),
    /// Plan a read-only recorder import from connector output.
    Import(RecorderImportArgs),
    /// Query recorded events from the event store.
    #[command(subcommand)]
    Events(RecorderEventsCommand),
}

/// Subcommands for `ee recorder events`.
#[derive(Clone, Debug, PartialEq, Subcommand)]
pub enum RecorderEventsCommand {
    /// List recorded events with optional filters.
    List(RecorderEventsListArgs),
}

/// Arguments for `ee recorder events list`.
#[derive(Clone, Debug, Eq, Parser, PartialEq)]
pub struct RecorderEventsListArgs {
    /// Filter events to those after this RFC 3339 timestamp.
    #[arg(long, value_name = "RFC3339")]
    pub since: Option<String>,

    /// Filter events by source type (hook, cli, manual).
    #[arg(long, value_name = "SOURCE")]
    pub source: Option<String>,

    /// Filter events by run ID.
    #[arg(long, value_name = "RUN_ID")]
    pub run_id: Option<String>,

    /// Maximum number of events to return.
    #[arg(long, default_value_t = 100)]
    pub limit: u32,

    /// Workspace path.
    #[arg(long, short = 'w', default_value = ".")]
    pub workspace: PathBuf,

    /// Optional explicit database path.
    #[arg(long)]
    pub database: Option<PathBuf>,
}

/// Arguments for `ee recorder start`.
#[derive(Clone, Debug, Eq, Parser, PartialEq)]
pub struct RecorderStartArgs {
    /// Agent identifier.
    #[arg(long, value_name = "AGENT_ID")]
    pub agent_id: String,

    /// Optional session identifier for correlation.
    #[arg(long, value_name = "SESSION_ID")]
    pub session_id: Option<String>,

    /// Optional workspace identifier.
    #[arg(long, value_name = "WORKSPACE_ID")]
    pub workspace_id: Option<String>,

    /// Report what would be done without creating the session.
    #[arg(long, action = ArgAction::SetTrue)]
    pub dry_run: bool,
}

/// Arguments for `ee recorder event`.
#[derive(Clone, Debug, Eq, Parser, PartialEq)]
pub struct RecorderEventArgs {
    /// Run ID to add event to.
    #[arg(value_name = "RUN_ID")]
    pub run_id: String,

    /// Type of event: tool_call, tool_result, user_message, assistant_message, error, state_change.
    #[arg(long, value_name = "TYPE")]
    pub event_type: String,

    /// Optional payload content (or read from stdin).
    #[arg(long, value_name = "PAYLOAD")]
    pub payload: Option<String>,

    /// Redact the payload content.
    #[arg(long, action = ArgAction::SetTrue)]
    pub redact: bool,

    /// Previous event hash for recorder hash-chain continuity.
    #[arg(long, value_name = "BLAKE3_HASH")]
    pub previous_event_hash: Option<String>,

    /// Maximum accepted payload size in bytes.
    #[arg(long, default_value_t = crate::core::recorder::DEFAULT_MAX_RECORDER_PAYLOAD_BYTES)]
    pub max_payload_bytes: usize,

    /// Report what would be done without recording.
    #[arg(long, action = ArgAction::SetTrue)]
    pub dry_run: bool,
}

/// Arguments for `ee recorder finish`.
#[derive(Clone, Debug, Eq, Parser, PartialEq)]
pub struct RecorderFinishArgs {
    /// Run ID to finish.
    #[arg(value_name = "RUN_ID")]
    pub run_id: String,

    /// Final status: completed, abandoned.
    #[arg(long, default_value = "completed")]
    pub status: String,

    /// Report what would be done without finishing.
    #[arg(long, action = ArgAction::SetTrue)]
    pub dry_run: bool,
}

/// Arguments for `ee recorder tail`.
#[derive(Clone, Debug, Eq, Parser, PartialEq)]
pub struct RecorderTailArgs {
    /// Optional run ID to tail. Omit to tail across all runs.
    #[arg(value_name = "RUN_ID")]
    pub run_id: Option<String>,

    /// Only include events at or after this RFC 3339 timestamp.
    #[arg(long, value_name = "RFC3339")]
    pub since: Option<String>,

    /// Number of events to return.
    #[arg(long, short = 'n', default_value_t = 10)]
    pub limit: u32,

    /// Starting sequence number.
    #[arg(long)]
    pub from_sequence: Option<u64>,

    /// Follow mode alias. Prefer `ee recorder follow`.
    #[arg(long, short = 'f', hide = true)]
    pub follow: bool,

    /// Output format for follow mode (jsonl for machine-readable stream).
    #[arg(long = "tail-format", value_name = "FORMAT", hide = true)]
    pub tail_format: Option<String>,

    /// Simple filter expression: `key=value AND key=value`.
    #[arg(long, value_name = "EXPR")]
    pub filter: Option<String>,

    /// Optional explicit database path. Defaults to `<workspace>/.ee/ee.db`.
    #[arg(long, value_name = "PATH")]
    pub database: Option<PathBuf>,
}

/// Arguments for `ee recorder follow`.
#[derive(Clone, Debug, Eq, Parser, PartialEq)]
pub struct RecorderFollowArgs {
    /// Optional run ID to follow.
    #[arg(long, value_name = "RUN_ID")]
    pub run_id: Option<String>,

    /// Only emit events at or after this RFC 3339 timestamp.
    #[arg(long, value_name = "RFC3339")]
    pub since: Option<String>,

    /// Simple filter expression: `key=value AND key=value`.
    #[arg(long, value_name = "EXPR")]
    pub filter: Option<String>,

    /// Maximum events read per poll.
    #[arg(long, default_value_t = 100)]
    pub limit: u32,

    /// Poll interval in milliseconds.
    #[arg(long, default_value_t = 250)]
    pub poll_ms: u64,

    /// Emit line-delimited JSON. Follow mode always writes one JSON object per event.
    #[arg(long = "json-lines", action = ArgAction::SetTrue)]
    pub json_lines: bool,

    /// Stop after this many idle milliseconds; intended for deterministic tests.
    #[arg(long, hide = true)]
    pub idle_timeout_ms: Option<u64>,

    /// Optional explicit database path. Defaults to `<workspace>/.ee/ee.db`.
    #[arg(long, value_name = "PATH")]
    pub database: Option<PathBuf>,
}

/// Arguments for `ee recorder import`.
#[derive(Clone, Debug, Eq, Parser, PartialEq)]
pub struct RecorderImportArgs {
    /// Import source type: cass, eidetic_legacy, recorder, manual.
    #[arg(long, default_value = "cass", value_name = "TYPE")]
    pub source_type: String,

    /// Stable external source identifier, such as a CASS session path.
    #[arg(long, value_name = "SOURCE_ID")]
    pub source_id: String,

    /// Connector JSON input file; for CASS, pass saved `cass view --json` output.
    #[arg(long, value_name = "PATH")]
    pub input: Option<PathBuf>,

    /// Agent ID to attach to the planned imported recorder run.
    #[arg(long, value_name = "AGENT_ID")]
    pub agent_id: Option<String>,

    /// Optional session identifier for correlation.
    #[arg(long, value_name = "SESSION_ID")]
    pub session_id: Option<String>,

    /// Optional workspace identifier for correlation.
    #[arg(long, value_name = "WORKSPACE_ID")]
    pub workspace_id: Option<String>,

    /// Maximum source events to map into the dry-run plan.
    #[arg(long, default_value_t = crate::core::recorder::DEFAULT_RECORDER_IMPORT_LIMIT)]
    pub max_events: usize,

    /// Maximum accepted source payload size in bytes.
    #[arg(long, default_value_t = crate::core::recorder::DEFAULT_MAX_RECORDER_PAYLOAD_BYTES)]
    pub max_payload_bytes: usize,

    /// Force all mapped source payloads through redaction before hashing.
    #[arg(long, action = ArgAction::SetTrue)]
    pub redact: bool,

    /// Required: render the import plan without writing recorder storage.
    #[arg(long, action = ArgAction::SetTrue)]
    pub dry_run: bool,
}

/// Subcommands for `ee rationale`.
