/// Arguments for `ee search`.
///
/// Eq is dropped because `relevance_floor: Option<f32>` (B1) cannot satisfy
/// it. PartialEq is preserved — sufficient for clap derive needs and
/// existing tests that compare arg structs.
#[derive(Clone, Debug, Parser, PartialEq)]
pub struct SearchArgs {
    /// Query string to search for.
    #[arg(value_name = "QUERY")]
    pub query: String,

    /// Maximum number of results to return.
    #[arg(long, short = 'n', default_value_t = 10)]
    pub limit: u32,

    /// Retrieval speed/quality budget: instant, default, or quality.
    #[arg(long, value_parser = parse_speed_mode_arg, default_value = "default")]
    pub speed: crate::search::SpeedMode,

    /// Database path. Defaults to <workspace>/.ee/ee.db.
    #[arg(long, value_name = "PATH")]
    pub database: Option<PathBuf>,

    /// Index output directory. Defaults to <workspace>/.ee/index/.
    #[arg(long, value_name = "PATH")]
    pub index_dir: Option<PathBuf>,

    /// Include score explanations in output.
    #[arg(long, action = ArgAction::SetTrue)]
    pub explain: bool,

    /// Include tombstoned memories in search results.
    #[arg(long, action = ArgAction::SetTrue)]
    pub include_tombstoned: bool,

    /// Evaluate validity windows at this RFC3339 timestamp.
    #[arg(long, value_name = "RFC3339", value_parser = parse_rfc3339_arg)]
    pub as_of: Option<chrono::DateTime<chrono::Utc>>,

    /// Include memories whose valid_to is before the validity reference time.
    #[arg(long, action = ArgAction::SetTrue)]
    pub include_expired: bool,

    /// Include memories whose valid_from is after the validity reference time.
    #[arg(long, action = ArgAction::SetTrue)]
    pub include_future: bool,

    /// Include memories marked with stale validity status when present in index metadata.
    #[arg(long, action = ArgAction::SetTrue)]
    pub include_stale: bool,

    /// Emit a redaction-safe query performance report instead of search hits.
    #[arg(long, action = ArgAction::SetTrue)]
    pub explain_performance: bool,

    /// Minimum score (0.0..=1.0) for a hit to be included in `results`.
    /// Below-floor candidates are dropped and counted in
    /// `metrics.candidatesBelowFloor`. Default is `0.05`. Pass `0.0` to
    /// disable filtering. Bead bd-17c65.2.1 (B1).
    #[arg(long, value_name = "FLOAT")]
    pub relevance_floor: Option<f32>,

    /// Search arm selection for diagnostics: lexical_only, semantic_only, or hybrid.
    #[arg(long, value_parser = parse_search_source_mode_arg, default_value = "hybrid")]
    pub source_mode: SearchSourceMode,

    /// Fail instead of falling back when the requested source mode is unavailable.
    #[arg(long, action = ArgAction::SetTrue)]
    pub strict_source_mode: bool,

    /// Trust lane to apply before returning memories: self, team, workspace, verified, or swarm.
    #[arg(long, value_parser = parse_memory_scope_arg, default_value = "swarm")]
    pub memory_scope: MemoryScope,

    /// Fail closed when relevant evidence exists outside the requested memory scope.
    #[arg(long, action = ArgAction::SetTrue)]
    pub strict_scope: bool,

    /// Mesh command mode: off, cache, revisable, or blocking.
    #[arg(long = "mesh", value_parser = parse_mesh_command_mode_arg, default_value = "off")]
    pub mesh_mode: MeshCommandMode,
}

