fn args_contain_format_flag(args: &[OsString]) -> bool {
    for arg in args.iter().skip(1) {
        if arg == OsStr::new("--") {
            return false;
        }
        let Some(arg) = arg.to_str() else {
            continue;
        };
        if arg == "--format" || arg.starts_with("--format=") {
            return true;
        }
    }
    false
}

fn args_contain_fields_flag(args: &[OsString]) -> bool {
    for arg in args.iter().skip(1) {
        if arg == OsStr::new("--") {
            return false;
        }
        let Some(arg) = arg.to_str() else {
            continue;
        };
        if arg == "--fields" || arg.starts_with("--fields=") {
            return true;
        }
    }
    false
}

fn handle_hook_preflight_shell<W, E>(
    cli: &Cli,
    args: &PreflightShellArgs,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    let options = crate::hooks::PreflightHookShellOptions {
        shell: Some(args.shell.into_hook_shell()),
        ee_binary_path: args.ee_binary.clone(),
        install_dir: args.install_dir.clone(),
    };
    let report = match crate::hooks::generate_preflight_shell_snippet(&options) {
        Ok(report) => report,
        Err(error) => {
            return write_domain_error(&error, cli.wants_json(), stdout, stderr);
        }
    };
    match cli.renderer() {
        output::Renderer::Human | output::Renderer::Markdown => {
            // Humans want the snippet itself (ready to paste). The JSON
            // envelope is one --json away.
            write_stdout(stdout, &report.snippet)
        }
        output::Renderer::Toon => {
            let json = serde_json::json!({
                "schema": crate::models::RESPONSE_SCHEMA_V1,
                "success": true,
                "data": report,
            });
            write_stdout(
                stdout,
                &(output::render_toon_from_json(&json.to_string()) + "\n"),
            )
        }
        output::Renderer::Json
        | output::Renderer::Jsonl
        | output::Renderer::Compact
        | output::Renderer::Hook => {
            let json = serde_json::json!({
                "schema": crate::models::RESPONSE_SCHEMA_V1,
                "success": true,
                "data": report,
            });
            write_stdout(stdout, &(json.to_string() + "\n"))
        }
    }
}

fn handle_mcp_validate<W>(cli: &Cli, args: &McpValidateArgs, stdout: &mut W) -> ProcessExitCode
where
    W: Write,
{
    let report = mcp_validate_report(args);
    match cli.renderer() {
        output::Renderer::Human | output::Renderer::Markdown => {
            write_stdout(stdout, &mcp_validate_human(&report))
        }
        output::Renderer::Toon => {
            let json = serde_json::json!({
                "schema": crate::models::RESPONSE_SCHEMA_V1,
                "success": true,
                "data": report,
            });
            write_stdout(
                stdout,
                &(output::render_toon_from_json(&json.to_string()) + "\n"),
            )
        }
        output::Renderer::Json
        | output::Renderer::Jsonl
        | output::Renderer::Compact
        | output::Renderer::Hook => {
            let json = serde_json::json!({
                "schema": crate::models::RESPONSE_SCHEMA_V1,
                "success": true,
                "data": report,
            });
            write_stdout(stdout, &(json.to_string() + "\n"))
        }
    }
}

fn mcp_validate_report(args: &McpValidateArgs) -> serde_json::Value {
    let manifest_json = output::render_mcp_manifest_json();
    let schema_source = args
        .manifest_schema
        .as_ref()
        .map_or_else(|| "embedded".to_owned(), |path| path.display().to_string());
    let schema_text = match args.manifest_schema.as_ref() {
        Some(path) => match fs::read_to_string(path) {
            Ok(text) => text,
            Err(error) => {
                return serde_json::json!({
                    "command": "mcp validate",
                    "manifestSchema": output::MCP_MANIFEST_SCHEMA_V1,
                    "schemaSource": schema_source,
                    "status": "invalid",
                    "valid": false,
                    "adapterFeatureEnabled": cfg!(feature = "mcp"),
                    "capabilityGap": default_mcp_capability_gap(),
                    "checks": [],
                    "validationErrors": [format!("schema_read_failed: {error}")],
                });
            }
        },
        None => include_str!("../../docs/schemas/ee.mcp.manifest.v1.json").to_owned(),
    };

    let mut checks = Vec::new();
    let mut errors = Vec::new();
    let schema = parse_json_check("schema_json_parse", &schema_text, &mut checks, &mut errors);
    let manifest = parse_json_check(
        "manifest_json_parse",
        &manifest_json,
        &mut checks,
        &mut errors,
    );

    if let Some(schema) = schema.as_ref() {
        let schema_id_matches_manifest = schema.get("title").and_then(serde_json::Value::as_str)
            == Some(output::MCP_MANIFEST_SCHEMA_V1)
            && schema
                .get("$id")
                .and_then(serde_json::Value::as_str)
                .is_some_and(|id| id.ends_with("/ee.mcp.manifest.v1.json"));
        push_check(
            "schema_id_matches_manifest",
            schema_id_matches_manifest,
            &mut checks,
            &mut errors,
        );
    }

    let adapter_feature_enabled = manifest
        .as_ref()
        .and_then(|value| value.pointer("/data/adapter/featureEnabled"))
        .and_then(serde_json::Value::as_bool)
        .unwrap_or(cfg!(feature = "mcp"));

    if let Some(manifest) = manifest.as_ref() {
        push_check(
            "manifest_response_success",
            manifest.get("success").and_then(serde_json::Value::as_bool) == Some(true),
            &mut checks,
            &mut errors,
        );
        push_check(
            "manifest_data_schema_matches",
            manifest
                .pointer("/data/schema")
                .and_then(serde_json::Value::as_str)
                == Some(output::MCP_MANIFEST_SCHEMA_V1),
            &mut checks,
            &mut errors,
        );
        push_check(
            "manifest_schema_registry_source",
            manifest
                .pointer("/data/registry/schemaSource")
                .and_then(serde_json::Value::as_str)
                == Some("public_schemas"),
            &mut checks,
            &mut errors,
        );
        let schemas_include_manifest = manifest
            .pointer("/data/schemas")
            .and_then(serde_json::Value::as_array)
            .is_some_and(|schemas| {
                schemas.iter().any(|schema| {
                    schema.get("id").and_then(serde_json::Value::as_str)
                        == Some(output::MCP_MANIFEST_SCHEMA_V1)
                })
            });
        push_check(
            "manifest_schema_list_includes_self",
            schemas_include_manifest,
            &mut checks,
            &mut errors,
        );

        if !adapter_feature_enabled {
            push_check(
                "default_build_uses_capability_gap",
                manifest
                    .pointer("/data/capabilityGap/code")
                    .and_then(serde_json::Value::as_str)
                    == Some("mcp_feature_disabled"),
                &mut checks,
                &mut errors,
            );
            let degraded_empty = manifest
                .pointer("/data/degraded")
                .and_then(serde_json::Value::as_array)
                .is_some_and(Vec::is_empty);
            push_check(
                "default_build_keeps_degraded_empty",
                degraded_empty,
                &mut checks,
                &mut errors,
            );
        }
    }

    if let (Some(manifest), Some(schema)) = (manifest.as_ref(), schema.as_ref()) {
        match validate_json_schema_subset(manifest, schema, schema, "$") {
            Ok(()) => push_check(
                "manifest_matches_json_schema",
                true,
                &mut checks,
                &mut errors,
            ),
            Err(error) => {
                checks.push(serde_json::json!({
                    "name": "manifest_matches_json_schema",
                    "valid": false,
                    "detail": error,
                }));
                errors.push("manifest_matches_json_schema".to_owned());
            }
        }
    }

    let valid = errors.is_empty();
    serde_json::json!({
        "command": "mcp validate",
        "manifestSchema": output::MCP_MANIFEST_SCHEMA_V1,
        "schemaSource": schema_source,
        "status": if valid { "valid" } else { "invalid" },
        "valid": valid,
        "adapterFeatureEnabled": adapter_feature_enabled,
        "capabilityGap": if adapter_feature_enabled {
            serde_json::Value::Null
        } else {
            default_mcp_capability_gap()
        },
        "checks": checks,
        "validationErrors": errors,
    })
}

fn parse_json_check(
    name: &str,
    text: &str,
    checks: &mut Vec<serde_json::Value>,
    errors: &mut Vec<String>,
) -> Option<serde_json::Value> {
    match serde_json::from_str::<serde_json::Value>(text) {
        Ok(value) => {
            checks.push(serde_json::json!({"name": name, "valid": true}));
            Some(value)
        }
        Err(error) => {
            checks.push(serde_json::json!({"name": name, "valid": false}));
            errors.push(format!("{name}: {error}"));
            None
        }
    }
}

fn validate_json_schema_subset(
    value: &serde_json::Value,
    schema: &serde_json::Value,
    root_schema: &serde_json::Value,
    path: &str,
) -> Result<(), String> {
    if let Some(reference) = schema.get("$ref").and_then(serde_json::Value::as_str) {
        let target = resolve_local_schema_ref(root_schema, reference)?;
        return validate_json_schema_subset(value, target, root_schema, path);
    }

    if let Some(options) = schema.get("oneOf").and_then(serde_json::Value::as_array) {
        if options.iter().any(|candidate| {
            validate_json_schema_subset(value, candidate, root_schema, path).is_ok()
        }) {
            return Ok(());
        }
        return Err(format!("{path} did not match any oneOf branch"));
    }

    if let Some(expected) = schema.get("const") {
        if value != expected {
            return Err(format!("{path} expected const {expected}, got {value}"));
        }
    }

    let expected_types = schema_json_types(schema);
    if !expected_types.is_empty() {
        if !expected_types
            .iter()
            .any(|expected_type| schema_json_type_matches(value, expected_type))
        {
            return Err(format!(
                "{path} expected type {:?}, got {}",
                expected_types,
                schema_json_type_name(value)
            ));
        }
        if value.is_null() {
            return Ok(());
        }
    }

    if let Some(object) = value.as_object() {
        if let Some(required) = schema.get("required").and_then(serde_json::Value::as_array) {
            for field in required {
                let field = field
                    .as_str()
                    .ok_or_else(|| format!("{path} schema required entry is not a string"))?;
                if !object.contains_key(field) {
                    return Err(format!("{path} missing required field {field}"));
                }
            }
        }

        let properties = schema
            .get("properties")
            .and_then(serde_json::Value::as_object);
        for (key, child) in object {
            let child_path = format!("{path}.{key}");
            if let Some(property_schema) = properties.and_then(|props| props.get(key)) {
                validate_json_schema_subset(child, property_schema, root_schema, &child_path)?;
                continue;
            }
            match schema.get("additionalProperties") {
                Some(serde_json::Value::Bool(false)) => {
                    return Err(format!("{path} contains unexpected field {key}"));
                }
                Some(serde_json::Value::Object(_)) => {
                    validate_json_schema_subset(
                        child,
                        &schema["additionalProperties"],
                        root_schema,
                        &child_path,
                    )?;
                }
                Some(serde_json::Value::Bool(true)) | None => {}
                Some(other) => {
                    return Err(format!("{path} unsupported additionalProperties: {other}"));
                }
            }
        }
    }

    if let Some(items) = value.as_array() {
        if let Some(item_schema) = schema.get("items") {
            for (index, item) in items.iter().enumerate() {
                validate_json_schema_subset(
                    item,
                    item_schema,
                    root_schema,
                    &format!("{path}[{index}]"),
                )?;
            }
        }
    }

    Ok(())
}

fn resolve_local_schema_ref<'a>(
    root: &'a serde_json::Value,
    reference: &str,
) -> Result<&'a serde_json::Value, String> {
    let pointer = reference
        .strip_prefix('#')
        .ok_or_else(|| format!("only local JSON Schema refs are supported, got {reference}"))?;
    root.pointer(pointer)
        .ok_or_else(|| format!("schema reference {reference} did not resolve"))
}

fn schema_json_types(schema: &serde_json::Value) -> Vec<&str> {
    match schema.get("type") {
        Some(serde_json::Value::String(kind)) => vec![kind.as_str()],
        Some(serde_json::Value::Array(kinds)) => {
            kinds.iter().filter_map(serde_json::Value::as_str).collect()
        }
        _ => Vec::new(),
    }
}

fn schema_json_type_matches(value: &serde_json::Value, expected: &str) -> bool {
    match expected {
        "null" => value.is_null(),
        "boolean" => value.is_boolean(),
        "number" => value.is_number(),
        "integer" => value.as_i64().is_some() || value.as_u64().is_some(),
        "string" => value.is_string(),
        "array" => value.is_array(),
        "object" => value.is_object(),
        _ => false,
    }
}

fn schema_json_type_name(value: &serde_json::Value) -> &'static str {
    match value {
        serde_json::Value::Null => "null",
        serde_json::Value::Bool(_) => "boolean",
        serde_json::Value::Number(number)
            if number.as_i64().is_some() || number.as_u64().is_some() =>
        {
            "integer"
        }
        serde_json::Value::Number(_) => "number",
        serde_json::Value::String(_) => "string",
        serde_json::Value::Array(_) => "array",
        serde_json::Value::Object(_) => "object",
    }
}

fn push_check(
    name: &str,
    valid: bool,
    checks: &mut Vec<serde_json::Value>,
    errors: &mut Vec<String>,
) {
    checks.push(serde_json::json!({"name": name, "valid": valid}));
    if !valid {
        errors.push(name.to_owned());
    }
}

fn default_mcp_capability_gap() -> serde_json::Value {
    serde_json::json!({
        "code": "mcp_feature_disabled",
        "severity": "low",
        "message": "MCP stdio adapter feature is not enabled in this build.",
        "repair": "Build ee with the mcp feature enabled, or use the CLI surfaces directly.",
        "feature": "mcp",
        "capabilitiesCommand": "ee capabilities --json",
    })
}

fn mcp_validate_human(report: &serde_json::Value) -> String {
    let status = report
        .get("status")
        .and_then(serde_json::Value::as_str)
        .unwrap_or("unknown");
    let schema = report
        .get("manifestSchema")
        .and_then(serde_json::Value::as_str)
        .unwrap_or(output::MCP_MANIFEST_SCHEMA_V1);
    let source = report
        .get("schemaSource")
        .and_then(serde_json::Value::as_str)
        .unwrap_or("embedded");
    let adapter = if report
        .get("adapterFeatureEnabled")
        .and_then(serde_json::Value::as_bool)
        .unwrap_or(false)
    {
        "enabled"
    } else {
        "disabled"
    };
    let mut output = format!(
        "ee mcp validate\n\nStatus: {status}\nManifest schema: {schema}\nSchema source: {source}\nAdapter feature: {adapter}\n"
    );
    if let Some(errors) = report
        .get("validationErrors")
        .and_then(serde_json::Value::as_array)
        .filter(|errors| !errors.is_empty())
    {
        output.push_str("\nValidation errors:\n");
        for error in errors {
            if let Some(error) = error.as_str() {
                output.push_str(&format!("  - {error}\n"));
            }
        }
    }
    output
}

fn handle_eval_list<W, E>(
    cli: &Cli,
    fixture_dir: Option<&std::path::Path>,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    let default_dir = std::path::PathBuf::from(crate::eval::DEFAULT_FIXTURE_DIR);
    let dir = fixture_dir.unwrap_or(&default_dir);

    match crate::eval::list_fixtures(dir) {
        Ok(entries) => {
            if cli.wants_json() {
                let json = serde_json::json!({
                    "schema": crate::models::RESPONSE_SCHEMA_V1,
                    "success": true,
                    "data": {
                        "command": "eval list",
                        "fixtures": entries,
                        "fixtureCount": entries.len(),
                        "fixtureDir": dir.display().to_string()
                    }
                });
                let _ = stdout.write_all(json.to_string().as_bytes());
                let _ = stdout.write_all(b"\n");
            } else {
                let _ = writeln!(
                    stdout,
                    "Available evaluation fixtures ({}):\n",
                    entries.len()
                );
                for entry in &entries {
                    let _ = writeln!(stdout, "  {} ({})", entry.fixture_id, entry.fixture_family);
                    let _ = writeln!(stdout, "    Journey: {}", entry.journey);
                    let _ = writeln!(
                        stdout,
                        "    Memories: {}, Queries: {}",
                        entry.memory_count, entry.query_count
                    );
                    let _ = writeln!(stdout);
                }
            }
            ProcessExitCode::Success
        }
        Err(e) => write_domain_error(&e, cli.wants_json(), stdout, stderr),
    }
}

fn collect_eval_run_reports(
    scenario_id: Option<&str>,
    dir: &std::path::Path,
) -> Result<Vec<crate::eval::EvalRunReport>, DomainError> {
    let start = std::time::Instant::now();
    let fixtures = crate::eval::discover_fixtures(dir)?;
    if fixtures.is_empty() {
        return Err(crate::models::DomainError::Configuration {
            message: "No fixtures found in fixture directory".into(),
            repair: Some(format!("Add fixtures to {}", dir.display())),
        });
    }

    let target_fixtures = if let Some(id) = scenario_id {
        fixtures
            .into_iter()
            .filter(|fixture| fixture.fixture_id == id || fixture.fixture_family == id)
            .collect::<Vec<_>>()
    } else {
        fixtures
    };

    if target_fixtures.is_empty() {
        return Err(crate::models::DomainError::NotFound {
            resource: "fixture".into(),
            id: scenario_id.unwrap_or("*").into(),
            repair: Some("ee eval list".into()),
        });
    }

    let mut reports = Vec::with_capacity(target_fixtures.len());
    for fixture in &target_fixtures {
        let source = crate::eval::load_source_memories(&fixture.source_memory_path)?;
        let per_query = run_eval_retrieval_queries(&source)?;
        let fixture_metrics = crate::eval::compute_fixture_metrics(&fixture.fixture_id, per_query);

        let mut report = crate::eval::EvalRunReport::new(
            fixture.fixture_id.clone(),
            fixture.fixture_family.clone(),
        );
        report.metrics = fixture_metrics;
        report.duration_ms = start.elapsed().as_secs_f64() * 1000.0;
        report.status = if report.metrics.mean_precision_at_1 >= 0.5 {
            crate::eval::EvalRunStatus::Passed
        } else {
            crate::eval::EvalRunStatus::Failed
        };
        report.data_hash = crate::eval::compute_data_hash(&report);
        reports.push(report);
    }

    Ok(reports)
}

fn handle_eval_run<W, E>(
    cli: &Cli,
    scenario_id: Option<&str>,
    fixture_dir: Option<&std::path::Path>,
    _science: bool,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    let default_dir = std::path::PathBuf::from(crate::eval::DEFAULT_FIXTURE_DIR);
    let dir = fixture_dir.unwrap_or(&default_dir);
    let reports = match collect_eval_run_reports(scenario_id, dir) {
        Ok(reports) => reports,
        Err(error) => return write_domain_error(&error, cli.wants_json(), stdout, stderr),
    };

    if cli.wants_json() {
        let json = if reports.len() == 1 {
            serde_json::json!({
                "schema": crate::models::RESPONSE_SCHEMA_V1,
                "success": true,
                "data": {
                    "command": "eval run",
                    "report": reports.first()
                }
            })
        } else {
            serde_json::json!({
                "schema": crate::models::RESPONSE_SCHEMA_V1,
                "success": true,
                "data": {
                    "command": "eval run",
                    "reports": reports,
                    "fixtureCount": reports.len()
                }
            })
        };
        let _ = stdout.write_all(json.to_string().as_bytes());
        let _ = stdout.write_all(b"\n");
    } else {
        for report in &reports {
            let _ = writeln!(
                stdout,
                "Fixture: {} ({})",
                report.fixture_id, report.fixture_family
            );
            let _ = writeln!(stdout, "  Status: {}", report.status.as_str());
            let _ = writeln!(
                stdout,
                "  Queries evaluated: {}",
                report.metrics.queries_evaluated
            );
            let _ = writeln!(
                stdout,
                "  Mean P@1:   {:.3}",
                report.metrics.mean_precision_at_1
            );
            let _ = writeln!(
                stdout,
                "  Mean P@5:   {:.3}",
                report.metrics.mean_precision_at_5
            );
            let _ = writeln!(
                stdout,
                "  Mean nDCG@5: {:.3}",
                report.metrics.mean_ndcg_at_5
            );
            let _ = writeln!(stdout, "  Mean MRR:   {:.3}", report.metrics.mean_mrr);
            let _ = writeln!(stdout, "  Duration:   {:.1}ms", report.duration_ms);
            let _ = writeln!(stdout, "  Data hash:  {}", report.data_hash);
            let _ = writeln!(stdout);
        }
    }

    ProcessExitCode::Success
}

fn handle_eval_report<W, E>(
    cli: &Cli,
    scenario_id: Option<&str>,
    fixture_dir: Option<&std::path::Path>,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    let default_dir = std::path::PathBuf::from(crate::eval::DEFAULT_FIXTURE_DIR);
    let dir = fixture_dir.unwrap_or(&default_dir);
    let reports = match collect_eval_run_reports(scenario_id, dir) {
        Ok(reports) => reports,
        Err(error) => return write_domain_error(&error, cli.wants_json(), stdout, stderr),
    };
    let summary = eval_report_summary(&reports);
    let data_hashes = reports
        .iter()
        .map(|report| {
            serde_json::json!({
                "fixtureId": report.fixture_id,
                "fixtureFamily": report.fixture_family,
                "dataHash": report.data_hash,
            })
        })
        .collect::<Vec<_>>();
    let first_failure = eval_report_first_failure(&reports);
    let report_status = summary
        .get("status")
        .and_then(serde_json::Value::as_str)
        .unwrap_or("unknown")
        .to_owned();

    if cli.wants_json() {
        let json = serde_json::json!({
            "schema": crate::models::RESPONSE_SCHEMA_V1,
            "success": true,
            "data": {
                "command": "eval report",
                "schema": "ee.eval.report_summary.v1",
                "fixtureDir": dir.display().to_string(),
                "scenarioFilter": scenario_id,
                "status": report_status,
                "fixtureCount": reports.len(),
                "summary": summary,
                "dataHashes": data_hashes,
                "firstFailure": first_failure,
                "reports": reports,
            }
        });
        let _ = stdout.write_all(json.to_string().as_bytes());
        let _ = stdout.write_all(b"\n");
    } else {
        let _ = writeln!(
            stdout,
            "Eval report: {}",
            report_status.to_ascii_uppercase()
        );
        let _ = writeln!(stdout, "  Fixture dir: {}", dir.display());
        let _ = writeln!(stdout, "  Fixtures: {}", reports.len());
        for report in &reports {
            let _ = writeln!(
                stdout,
                "  - {}: {} (data hash {})",
                report.fixture_id,
                report.status.as_str(),
                report.data_hash
            );
        }
        if let Some(first_failure) = first_failure {
            let fixture = first_failure
                .get("fixtureId")
                .and_then(serde_json::Value::as_str)
                .unwrap_or("<unknown>");
            let query = first_failure
                .get("query")
                .and_then(serde_json::Value::as_str)
                .unwrap_or("<fixture>");
            let _ = writeln!(stdout, "  First failure: {fixture} / {query}");
        }
    }

    ProcessExitCode::Success
}

fn eval_report_summary(reports: &[crate::eval::EvalRunReport]) -> serde_json::Value {
    let mut passed_count = 0_u32;
    let mut failed_count = 0_u32;
    let mut error_count = 0_u32;
    let mut queries_evaluated = 0_u32;
    let mut mean_precision_at_1 = 0.0;
    let mut mean_precision_at_5 = 0.0;
    let mut mean_ndcg_at_5 = 0.0;
    let mut mean_mrr = 0.0;

    for report in reports {
        match report.status {
            crate::eval::EvalRunStatus::Passed => passed_count += 1,
            crate::eval::EvalRunStatus::Failed => failed_count += 1,
            crate::eval::EvalRunStatus::Error => error_count += 1,
            crate::eval::EvalRunStatus::Pending | crate::eval::EvalRunStatus::Running => {}
        }
        queries_evaluated = queries_evaluated.saturating_add(report.metrics.queries_evaluated);
        mean_precision_at_1 += report.metrics.mean_precision_at_1;
        mean_precision_at_5 += report.metrics.mean_precision_at_5;
        mean_ndcg_at_5 += report.metrics.mean_ndcg_at_5;
        mean_mrr += report.metrics.mean_mrr;
    }

    let fixture_count = reports.len() as f64;
    if fixture_count > 0.0 {
        mean_precision_at_1 /= fixture_count;
        mean_precision_at_5 /= fixture_count;
        mean_ndcg_at_5 /= fixture_count;
        mean_mrr /= fixture_count;
    }
    let status = if error_count > 0 {
        "error"
    } else if failed_count > 0 {
        "failed"
    } else {
        "passed"
    };

    serde_json::json!({
        "status": status,
        "passedCount": passed_count,
        "failedCount": failed_count,
        "errorCount": error_count,
        "queriesEvaluated": queries_evaluated,
        "meanPrecisionAt1": mean_precision_at_1,
        "meanPrecisionAt5": mean_precision_at_5,
        "meanNdcgAt5": mean_ndcg_at_5,
        "meanMrr": mean_mrr,
    })
}

fn eval_report_first_failure(reports: &[crate::eval::EvalRunReport]) -> Option<serde_json::Value> {
    for report in reports {
        if report.status == crate::eval::EvalRunStatus::Passed {
            continue;
        }
        let query = report.metrics.per_query.iter().find(|query| {
            query.precision_at_1 < 1.0 || query.recall_at_5 < 1.0 || query.mrr == 0.0
        });
        let reason_codes = eval_report_failure_reason_codes(report, query);
        return Some(serde_json::json!({
            "fixtureId": report.fixture_id,
            "fixtureFamily": report.fixture_family,
            "status": report.status.as_str(),
            "dataHash": report.data_hash,
            "query": query.map(|query| query.query.as_str()),
            "expectedIds": query.map(|query| query.expected_ids.clone()).unwrap_or_default(),
            "retrievedIds": query.map(|query| query.retrieved_ids.clone()).unwrap_or_default(),
            "precisionAt1": query.map(|query| query.precision_at_1),
            "recallAt5": query.map(|query| query.recall_at_5),
            "mrr": query.map(|query| query.mrr),
            "reasonCodes": reason_codes,
        }));
    }
    None
}

fn eval_report_failure_reason_codes(
    report: &crate::eval::EvalRunReport,
    query: Option<&crate::eval::QueryMetrics>,
) -> Vec<&'static str> {
    let mut codes = Vec::new();
    match report.status {
        crate::eval::EvalRunStatus::Failed => codes.push("fixture_status_failed"),
        crate::eval::EvalRunStatus::Error => codes.push("fixture_status_error"),
        crate::eval::EvalRunStatus::Pending => codes.push("fixture_status_pending"),
        crate::eval::EvalRunStatus::Running => codes.push("fixture_status_running"),
        crate::eval::EvalRunStatus::Passed => {}
    }
    if let Some(query) = query {
        if query.precision_at_1 < 1.0 {
            codes.push("top_result_not_relevant");
        }
        if query.recall_at_5 < 1.0 {
            codes.push("expected_memory_missing_from_top5");
        }
        if query.mrr == 0.0 {
            codes.push("no_relevant_result_returned");
        }
    } else if report.metrics.queries_evaluated == 0 {
        codes.push("no_queries_evaluated");
    }
    codes
}

fn handle_eval_pack_quality_run<W, E>(
    cli: &Cli,
    fixture_filter: Option<&str>,
    case_filter: Option<&str>,
    fixture_dir: Option<&std::path::Path>,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    let default_dir = std::path::PathBuf::from(crate::eval::DEFAULT_FIXTURE_DIR);
    let dir = fixture_dir.unwrap_or(&default_dir);

    let fixtures = match crate::eval::discover_fixtures(dir) {
        Ok(fixtures) => fixtures,
        Err(error) => return write_domain_error(&error, cli.wants_json(), stdout, stderr),
    };

    if fixtures.is_empty() {
        let error = DomainError::Configuration {
            message: "No fixtures found in fixture directory".into(),
            repair: Some(format!("Add fixtures to {}", dir.display())),
        };
        return write_domain_error(&error, cli.wants_json(), stdout, stderr);
    }

    let target_fixtures: Vec<_> = if let Some(filter) = fixture_filter {
        fixtures
            .into_iter()
            .filter(|fixture| fixture.fixture_id == filter || fixture.fixture_family == filter)
            .collect()
    } else {
        fixtures
    };

    if target_fixtures.is_empty() {
        let error = DomainError::NotFound {
            resource: "fixture".into(),
            id: fixture_filter.unwrap_or("*").into(),
            repair: Some("ee eval list --json".into()),
        };
        return write_domain_error(&error, cli.wants_json(), stdout, stderr);
    }

    let mut reports = Vec::new();
    let mut artifact_paths = Vec::new();
    let mut degraded_branches = Vec::new();

    for fixture in &target_fixtures {
        let scenario = match crate::eval::load_scenario(&fixture.scenario_path) {
            Ok(scenario) => scenario,
            Err(error) => return write_domain_error(&error, cli.wants_json(), stdout, stderr),
        };
        let source = match crate::eval::load_source_memories(&fixture.source_memory_path) {
            Ok(source) => source,
            Err(error) => return write_domain_error(&error, cli.wants_json(), stdout, stderr),
        };
        if let Err(error) = crate::eval::validate_fixture_scenario(&scenario, &source) {
            return write_domain_error(&error, cli.wants_json(), stdout, stderr);
        }

        let Some(expectations) = &scenario.pack_quality_expectations else {
            continue;
        };
        let cases = expectations
            .cases
            .iter()
            .filter(|case| {
                case_filter
                    .is_none_or(|filter| case.case_id == filter || case.scenario_id == filter)
            })
            .cloned()
            .collect::<Vec<_>>();
        if cases.is_empty() {
            continue;
        }

        let materialized = match crate::eval::materialize_source_memories(&source) {
            Ok(memories) => memories,
            Err(error) => return write_domain_error(&error, cli.wants_json(), stdout, stderr),
        };
        let actuals = match pack_quality_actuals_for_cases(
            &fixture.path,
            &scenario,
            &source,
            &materialized,
            &cases,
        ) {
            Ok(actuals) => actuals,
            Err(error) => return write_domain_error(&error, cli.wants_json(), stdout, stderr),
        };

        artifact_paths.extend(pack_quality_artifact_paths(fixture, &scenario, &cases));
        degraded_branches.extend(pack_quality_degraded_branch_reports(
            fixture, &scenario, &cases,
        ));
        reports.push(crate::eval::evaluate_pack_quality(
            &fixture.fixture_id,
            &cases,
            &actuals,
        ));
    }

    if reports.is_empty() {
        let id = case_filter.or(fixture_filter).unwrap_or("*");
        let error = DomainError::NotFound {
            resource: "pack-quality case".into(),
            id: id.into(),
            repair: Some("ee eval run --pack-quality --json".into()),
        };
        return write_domain_error(&error, cli.wants_json(), stdout, stderr);
    }

    let passed = reports
        .iter()
        .all(|report| report.aggregate_verdict.is_passing());
    let has_regression = reports.iter().any(|report| report.cases_regression > 0);
    let exit = if passed {
        ProcessExitCode::Success
    } else if has_regression {
        ProcessExitCode::EvalFailure
    } else {
        ProcessExitCode::UnsatisfiedDegradedMode
    };

    if cli.wants_json() {
        let data = if reports.len() == 1 {
            serde_json::json!({
                "command": "eval run",
                "mode": "pack_quality",
                "fixtureDir": dir.display().to_string(),
                "scenarioFilter": case_filter,
                "report": reports.first(),
                "artifactPaths": artifact_paths,
                "degradedBranches": degraded_branches
            })
        } else {
            serde_json::json!({
                "command": "eval run",
                "mode": "pack_quality",
                "fixtureDir": dir.display().to_string(),
                "scenarioFilter": case_filter,
                "reports": reports,
                "fixtureCount": reports.len(),
                "artifactPaths": artifact_paths,
                "degradedBranches": degraded_branches
            })
        };
        let json = serde_json::json!({
            "schema": crate::models::RESPONSE_SCHEMA_V1,
            "success": passed,
            "data": data
        });
        let _ = stdout.write_all(json.to_string().as_bytes());
        let _ = stdout.write_all(b"\n");
    } else {
        for report in &reports {
            let _ = writeln!(stdout, "Fixture: {}", report.fixture_id);
            let _ = writeln!(
                stdout,
                "  Pack quality: {}",
                report.aggregate_verdict.as_str()
            );
            let _ = writeln!(stdout, "  Cases: {}", report.cases_total);
            let _ = writeln!(stdout, "  Within: {}", report.cases_within);
            let _ = writeln!(stdout, "  Drift: {}", report.cases_drift);
            let _ = writeln!(stdout, "  Regression: {}", report.cases_regression);
            let _ = writeln!(stdout, "  Inconclusive: {}", report.cases_inconclusive);
            let _ = writeln!(stdout);
        }
    }

    exit
}

fn pack_quality_actuals_for_cases(
    fixture_path: &Path,
    scenario: &crate::eval::FixtureScenario,
    source: &crate::eval::SourceMemoryFile,
    memories: &[crate::eval::SourceMemory],
    cases: &[crate::eval::PackQualityCase],
) -> Result<Vec<crate::eval::PackQualityActual>, DomainError> {
    if memories.is_empty() {
        return Err(DomainError::Configuration {
            message: format!("eval fixture {} contains no memories", source.fixture_id),
            repair: Some("Add source memories or generated tiers before running eval.".into()),
        });
    }

    let tempdir = tempfile::Builder::new()
        .prefix("ee-eval-pack-quality-")
        .tempdir()
        .map_err(|error| DomainError::Storage {
            message: format!("failed to create pack-quality eval index tempdir: {error}"),
            repair: Some("Check TMPDIR and filesystem permissions.".to_owned()),
        })?;
    let index_dir = tempdir.path().join("index");
    build_eval_search_index_from_memories(&index_dir, &source.fixture_id, memories)?;
    let workspace_path = tempdir.path().to_path_buf();

    let mut actuals = Vec::with_capacity(cases.len());
    for case in cases {
        let query = pack_quality_case_query(fixture_path, case)?;
        let degradation_codes = pack_quality_actual_degradation_codes(scenario, case);
        let speed = if degradation_codes
            .iter()
            .any(|code| code == "semantic_disabled")
        {
            SpeedMode::Instant
        } else {
            SpeedMode::Default
        };
        let limit = pack_quality_selection_limit(case, memories.len());
        let report = run_search(&SearchOptions {
            workspace_path: workspace_path.clone(),
            database_path: None,
            index_dir: Some(index_dir.clone()),
            query: query.clone(),
            limit,
            speed,
            explain: false,
            as_of: None,
            include_tombstoned: false,
            include_expired: false,
            include_future: false,
            include_stale: false,
            relevance_floor: None,
            source_mode: SearchSourceMode::Hybrid,
            strict_source_mode: false,
            memory_scope: MemoryScope::Swarm,
            strict_scope: false,
        })
        .map_err(|error| DomainError::SearchIndex {
            message: format!("pack-quality eval search failed for `{query}`: {error}"),
            repair: error.repair_hint().map(str::to_owned),
        })?;
        let selected_memory_ids = report
            .results
            .into_iter()
            .map(|hit| hit.doc_id)
            .collect::<Vec<_>>();

        actuals.push(crate::eval::PackQualityActual {
            tokens_used: estimate_pack_quality_tokens(&selected_memory_ids, memories),
            provenance_density: pack_quality_provenance_density(&selected_memory_ids, memories),
            redaction_leaks: detect_pack_quality_redaction_leaks(
                &selected_memory_ids,
                memories,
                &case.forbidden_redaction_leaks,
            ),
            degradation_codes,
            selected_memory_ids,
        });
    }

    Ok(actuals)
}

fn pack_quality_case_query(
    fixture_path: &Path,
    case: &crate::eval::PackQualityCase,
) -> Result<String, DomainError> {
    match case.query_surface.kind.as_str() {
        "inline_query" => case
            .query_surface
            .query
            .as_ref()
            .map(|query| query.trim().to_string())
            .filter(|query| !query.is_empty())
            .ok_or_else(|| DomainError::Configuration {
                message: format!("pack-quality case `{}` has no inline query", case.case_id),
                repair: Some("Fix the eval fixture query_surface.query field.".into()),
            }),
        "query_file" => {
            let raw_path =
                case.query_surface
                    .path
                    .as_ref()
                    .ok_or_else(|| DomainError::Configuration {
                        message: format!(
                            "pack-quality case `{}` has no query file path",
                            case.case_id
                        ),
                        repair: Some("Fix the eval fixture query_surface.path field.".into()),
                    })?;
            let query_path = resolve_pack_quality_query_path(fixture_path, raw_path);
            load_query_file(&query_path)
                .map(|request| request.query)
                .map_err(query_file_error_to_domain)
        }
        other => Err(DomainError::Configuration {
            message: format!(
                "pack-quality case `{}` has unsupported query surface `{other}`",
                case.case_id
            ),
            repair: Some("Use inline_query or query_file in pack-quality fixtures.".into()),
        }),
    }
}

fn resolve_pack_quality_query_path(fixture_path: &Path, raw_path: &str) -> PathBuf {
    let path = PathBuf::from(raw_path);
    if path.is_absolute() || path.exists() {
        return path;
    }
    if let Some(file_name) = path.file_name() {
        let sibling = fixture_path.join(file_name);
        if sibling.exists() {
            return sibling;
        }
    }
    fixture_path.join(path)
}

fn query_file_error_to_domain(error: QueryFileError) -> DomainError {
    DomainError::Configuration {
        message: error.message,
        repair: error.repair,
    }
}

fn pack_quality_selection_limit(case: &crate::eval::PackQualityCase, memory_count: usize) -> u32 {
    let requested = case
        .expected_selected_memory_ids
        .len()
        .max(1)
        .min(memory_count);
    u32::try_from(requested).unwrap_or(u32::MAX)
}

fn pack_quality_actual_degradation_codes(
    scenario: &crate::eval::FixtureScenario,
    case: &crate::eval::PackQualityCase,
) -> Vec<String> {
    scenario
        .degraded_branches
        .iter()
        .filter(|branch| branch.preserves_success_signal)
        .filter(|branch| {
            case.allowed_degradation_codes
                .iter()
                .any(|code| code == &branch.code)
        })
        .map(|branch| branch.code.clone())
        .collect()
}

fn estimate_pack_quality_tokens(
    selected_memory_ids: &[String],
    memories: &[crate::eval::SourceMemory],
) -> u32 {
    let mut estimated: usize = 0;
    for memory_id in selected_memory_ids {
        if let Some(memory) = memories.iter().find(|memory| memory.id == *memory_id) {
            estimated = estimated.saturating_add(memory.content.len().div_ceil(4));
            estimated = estimated.saturating_add(24);
        }
    }
    u32::try_from(estimated).unwrap_or(u32::MAX)
}

fn pack_quality_provenance_density(
    selected_memory_ids: &[String],
    memories: &[crate::eval::SourceMemory],
) -> f64 {
    if selected_memory_ids.is_empty() {
        return 0.0;
    }

    let with_provenance = selected_memory_ids
        .iter()
        .filter(|memory_id| {
            memories
                .iter()
                .find(|memory| memory.id == **memory_id)
                .and_then(|memory| memory.provenance_uri.as_deref())
                .is_some_and(|uri| !uri.trim().is_empty())
        })
        .count();

    if selected_memory_ids.is_empty() {
        0.0
    } else {
        with_provenance as f64 / selected_memory_ids.len() as f64
    }
}

fn detect_pack_quality_redaction_leaks(
    selected_memory_ids: &[String],
    memories: &[crate::eval::SourceMemory],
    forbidden_leaks: &[String],
) -> Vec<String> {
    let mut leaks = BTreeSet::new();
    for memory_id in selected_memory_ids {
        let Some(memory) = memories.iter().find(|memory| memory.id == *memory_id) else {
            continue;
        };
        for forbidden in forbidden_leaks {
            if pack_quality_leak_present(&memory.content, forbidden) {
                leaks.insert(forbidden.clone());
            }
        }
    }
    leaks.into_iter().collect()
}

fn pack_quality_leak_present(content: &str, forbidden: &str) -> bool {
    let lower_content = content.to_ascii_lowercase();
    match forbidden {
        "systemPrompt" => lower_content.contains("system prompt"),
        "ignorePreviousInstructions" => lower_content.contains("ignore previous instructions"),
        other => lower_content.contains(&other.to_ascii_lowercase()),
    }
}

fn pack_quality_artifact_paths(
    fixture: &crate::eval::DiscoveredFixture,
    scenario: &crate::eval::FixtureScenario,
    cases: &[crate::eval::PackQualityCase],
) -> Vec<serde_json::Value> {
    cases
        .iter()
        .filter_map(|case| {
            scenario
                .command_sequence
                .iter()
                .find(|step| step.step == case.command_step)
                .map(|step| {
                    serde_json::json!({
                        "fixtureId": fixture.fixture_id,
                        "caseId": case.case_id,
                        "scenarioId": case.scenario_id,
                        "commandStep": case.command_step,
                        "stdout": step.stdout_artifact_path,
                        "stderr": step.stderr_artifact_path
                    })
                })
        })
        .collect()
}

fn pack_quality_degraded_branch_reports(
    fixture: &crate::eval::DiscoveredFixture,
    scenario: &crate::eval::FixtureScenario,
    cases: &[crate::eval::PackQualityCase],
) -> Vec<serde_json::Value> {
    scenario
        .degraded_branches
        .iter()
        .filter(|branch| {
            cases.iter().any(|case| {
                case.allowed_degradation_codes
                    .iter()
                    .any(|code| code == &branch.code)
            })
        })
        .map(|branch| {
            serde_json::json!({
                "fixtureId": fixture.fixture_id,
                "code": branch.code,
                "description": branch.description,
                "repairAction": branch.repair_action,
                "preservesSuccessSignal": branch.preserves_success_signal,
                "executed": true,
                "mode": if branch.code == "semantic_disabled" {
                    "lexical_only"
                } else {
                    "declared_fixture_branch"
                }
            })
        })
        .collect()
}

fn build_query_expectations(
    memories: &[crate::eval::SourceMemory],
) -> BTreeMap<String, Vec<String>> {
    let mut expectations: BTreeMap<String, Vec<String>> = BTreeMap::new();
    for memory in memories {
        for query in &memory.expected_query_match {
            expectations
                .entry(query.clone())
                .or_default()
                .push(memory.id.clone());
        }
    }

    expectations
}

fn run_eval_retrieval_queries(
    source: &crate::eval::SourceMemoryFile,
) -> Result<Vec<crate::eval::QueryMetrics>, DomainError> {
    let memories = crate::eval::materialize_source_memories(source)?;
    let query_expectations = build_query_expectations(&memories);
    if query_expectations.is_empty() {
        return Ok(Vec::new());
    }

    let tempdir = tempfile::Builder::new()
        .prefix("ee-eval-index-")
        .tempdir()
        .map_err(|error| DomainError::Storage {
            message: format!("failed to create eval index tempdir: {error}"),
            repair: Some("Check TMPDIR and filesystem permissions.".to_owned()),
        })?;
    let index_dir = tempdir.path().join("index");
    build_eval_search_index(&index_dir, source)?;

    let workspace_path = tempdir.path().to_path_buf();
    let limit = u32::try_from(memories.len().max(5)).unwrap_or(u32::MAX);
    let mut per_query = Vec::with_capacity(query_expectations.len());
    for (query, expected_ids) in query_expectations {
        let report = run_search(&SearchOptions {
            workspace_path: workspace_path.clone(),
            database_path: None,
            index_dir: Some(index_dir.clone()),
            query: query.clone(),
            limit,
            speed: SpeedMode::Default,
            explain: false,
            as_of: None,
            include_tombstoned: false,
            include_expired: false,
            include_future: false,
            include_stale: false,
            relevance_floor: None,
            source_mode: SearchSourceMode::Hybrid,
            strict_source_mode: false,
            memory_scope: MemoryScope::Swarm,
            strict_scope: false,
        })
        .map_err(|error| DomainError::SearchIndex {
            message: format!("eval fixture search failed for `{query}`: {error}"),
            repair: error.repair_hint().map(str::to_owned),
        })?;
        let retrieved_ids = report
            .results
            .into_iter()
            .map(|hit| hit.doc_id)
            .collect::<Vec<_>>();
        per_query.push(crate::eval::compute_query_metrics(
            &query,
            &expected_ids,
            &retrieved_ids,
        ));
    }

    Ok(per_query)
}

fn build_eval_search_index(
    index_dir: &Path,
    source: &crate::eval::SourceMemoryFile,
) -> Result<(), DomainError> {
    let memories = crate::eval::materialize_source_memories(source)?;
    build_eval_search_index_from_memories(index_dir, &source.fixture_id, &memories)
}

fn build_eval_search_index_from_memories(
    index_dir: &Path,
    fixture_id: &str,
    memories: &[crate::eval::SourceMemory],
) -> Result<(), DomainError> {
    let documents = memories
        .iter()
        .map(eval_source_memory_document)
        .map(CanonicalSearchDocument::into_indexable)
        .collect::<Vec<_>>();
    if documents.is_empty() {
        return Err(DomainError::Configuration {
            message: format!("eval fixture {fixture_id} contains no memories"),
            repair: Some(
                "Add memories to source_memory.json before running retrieval eval.".into(),
            ),
        });
    }

    let index_dir = index_dir.to_path_buf();
    crate::core::run_cli_future(async move {
        let cx = asupersync::Cx::for_testing();
        IndexBuilder::new(&index_dir)
            .with_embedder_stack(eval_embedder_stack())
            .add_documents(documents)
            .build(&cx)
            .await
    })
    .map_err(|error| DomainError::SearchIndex {
        message: format!("eval fixture index runtime failed: {error}"),
        repair: Some("Re-run eval after checking Asupersync runtime health.".to_owned()),
    })?
    .map_err(|error| DomainError::SearchIndex {
        message: format!("eval fixture index build failed: {error}"),
        repair: Some("Inspect source_memory.json for invalid indexable content.".to_owned()),
    })
    .and_then(|stats| {
        if stats.errors.is_empty() {
            Ok(())
        } else {
            let details = stats
                .errors
                .iter()
                .map(|(id, error)| format!("{id}: {error}"))
                .collect::<Vec<_>>()
                .join("; ");
            Err(DomainError::SearchIndex {
                message: format!("eval fixture index skipped documents: {details}"),
                repair: Some("Fix invalid fixture memory records before running eval.".to_owned()),
            })
        }
    })
}

fn eval_embedder_stack() -> EmbedderStack {
    let fast_embedder = Arc::new(HashEmbedder::default_256()) as Arc<dyn Embedder>;
    let quality_embedder = Arc::new(HashEmbedder::default_384()) as Arc<dyn Embedder>;
    EmbedderStack::from_parts(fast_embedder, Some(quality_embedder))
}

fn eval_source_memory_document(memory: &crate::eval::SourceMemory) -> CanonicalSearchDocument {
    let title = memory.tags.join(" ");
    let mut document = CanonicalSearchDocument::new(
        memory.id.as_str(),
        memory.content.as_str(),
        DocumentSource::Memory,
    )
    .with_level(memory.level.as_str())
    .with_kind(memory.kind.as_str())
    .with_tags(memory.tags.iter().map(String::as_str))
    .with_metadata_entry("trustClass", memory.trust_class.as_str())
    .with_metadata_entry("confidence", memory.confidence.to_string())
    .with_metadata_entry("utility", memory.utility.to_string())
    .with_metadata_entry("importance", memory.importance.to_string());
    if !title.trim().is_empty() {
        document = document.with_title(title);
    }
    if let Some(uri) = memory.provenance_uri.as_deref() {
        document = document.with_metadata_entry("provenanceUri", uri);
    }
    document
}

fn handle_focus<W, E>(
    cli: &Cli,
    command: &FocusCommand,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    let workspace_path = cli.resolve_workspace();
    let result = match command {
        FocusCommand::Show(_) => show_focus(&FocusShowOptions { workspace_path }),
        FocusCommand::Set(args) => set_focus(&FocusSetOptions {
            workspace_path,
            memory_ids: args.memory_ids.clone(),
            focal_memory_id: args.focal.clone(),
            pinned_memory_ids: args.pinned_memory_ids.clone(),
            capacity: args.capacity,
            reason: args.reason.clone(),
            provenance: args.provenance.clone(),
            scope: focus_scope(
                args.task_frame_id.clone(),
                args.recorder_run_id.clone(),
                args.handoff_id.clone(),
                args.profile.clone(),
            ),
        }),
        FocusCommand::Add(args) => add_focus(&FocusAddOptions {
            workspace_path,
            memory_ids: args.memory_ids.clone(),
            focal_memory_id: args.focal.clone(),
            pinned_memory_ids: args.pinned_memory_ids.clone(),
            capacity: args.capacity,
            reason: args.reason.clone(),
            provenance: args.provenance.clone(),
            scope: focus_scope(
                args.task_frame_id.clone(),
                args.recorder_run_id.clone(),
                args.handoff_id.clone(),
                args.profile.clone(),
            ),
        }),
        FocusCommand::Remove(args) => remove_focus(&FocusRemoveOptions {
            workspace_path,
            memory_ids: args.memory_ids.clone(),
            provenance: args.provenance.clone(),
        }),
        FocusCommand::Clear(args) => clear_focus(&FocusClearOptions {
            workspace_path,
            capacity: args.capacity,
            provenance: args.provenance.clone(),
            scope: focus_scope(
                args.task_frame_id.clone(),
                args.recorder_run_id.clone(),
                args.handoff_id.clone(),
                args.profile.clone(),
            ),
        }),
        FocusCommand::Explain(_) => explain_focus(&FocusExplainOptions { workspace_path }),
    };

    match result {
        Ok(report) => write_focus_report(cli, &report, stdout),
        Err(error) => write_domain_error(&error, cli.wants_json(), stdout, stderr),
    }
}

fn focus_scope(
    task_frame_id: Option<String>,
    recorder_run_id: Option<String>,
    handoff_id: Option<String>,
    profile: Option<String>,
) -> FocusScope {
    FocusScope {
        task_frame_id,
        recorder_run_id,
        handoff_id,
        profile,
    }
}

fn write_focus_report<W>(cli: &Cli, report: &FocusReport, stdout: &mut W) -> ProcessExitCode
where
    W: Write,
{
    match cli.renderer() {
        output::Renderer::Human | output::Renderer::Markdown => {
            write_stdout(stdout, &render_focus_human(report))
        }
        output::Renderer::Toon => write_stdout(
            stdout,
            &(output::render_toon_from_json(&focus_response_json(report)) + "\n"),
        ),
        output::Renderer::Json
        | output::Renderer::Jsonl
        | output::Renderer::Compact
        | output::Renderer::Hook => write_stdout(stdout, &(focus_response_json(report) + "\n")),
    }
}

fn focus_response_json(report: &FocusReport) -> String {
    serde_json::json!({
        "schema": crate::models::RESPONSE_SCHEMA_V1,
        "success": true,
        "data": report.data_json(),
    })
    .to_string()
}

fn render_focus_human(report: &FocusReport) -> String {
    let focal = report
        .state
        .focal_memory_id
        .map(|id| id.to_string())
        .unwrap_or_else(|| "-".to_owned());
    format!(
        "Focus: {} memories / capacity {}\n  Focal: {}\n  Mutated: {}\n  State hash: {}\n",
        report.state.item_count(),
        report.state.capacity,
        focal,
        report.mutated,
        report.state_hash
    )
}

fn handle_task_frame<W, E>(
    cli: &Cli,
    command: &TaskFrameCommand,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    let workspace_path = cli.resolve_workspace();
    let result = match command {
        TaskFrameCommand::Create(args) => {
            parse_task_frame_status(&args.status).and_then(|status| {
                create_task_frame(&TaskFrameCreateOptions {
                    workspace_path,
                    goal: args.goal.clone(),
                    actor: args.actor.clone(),
                    status,
                    current_focus: args.current_focus.clone(),
                    blockers: args.blockers.clone(),
                    evidence_links: task_frame_evidence_links(
                        &args.memory_ids,
                        &args.context_pack_ids,
                        &args.recorder_run_ids,
                        &args.handoff_ids,
                    ),
                    created_at: args.created_at.clone(),
                    dry_run: args.dry_run,
                })
            })
        }
        TaskFrameCommand::Show(args) => show_task_frame(&TaskFrameShowOptions {
            workspace_path,
            frame_id: args.frame_id.clone(),
            active: args.active,
        }),
        TaskFrameCommand::Update(args) => args
            .status
            .as_deref()
            .map(parse_task_frame_status)
            .transpose()
            .and_then(|status| {
                update_task_frame(&TaskFrameUpdateOptions {
                    workspace_path,
                    frame_id: args.frame_id.clone(),
                    status,
                    current_focus: args.current_focus.clone(),
                    blockers: args.blockers.clone(),
                    evidence_links: task_frame_evidence_links(
                        &args.memory_ids,
                        &args.context_pack_ids,
                        &args.recorder_run_ids,
                        &args.handoff_ids,
                    ),
                    updated_at: args.updated_at.clone(),
                    dry_run: args.dry_run,
                })
            }),
        TaskFrameCommand::Close(args) => parse_task_frame_status(&args.status).and_then(|status| {
            close_task_frame(&TaskFrameCloseOptions {
                workspace_path,
                frame_id: args.frame_id.clone(),
                status,
                reason: args.reason.clone(),
                closed_at: args.closed_at.clone(),
                dry_run: args.dry_run,
            })
        }),
        TaskFrameCommand::Subgoal(TaskFrameSubgoalCommand::Add(args)) => {
            parse_task_frame_status(&args.status).and_then(|status| {
                add_task_subgoal(&TaskSubgoalAddOptions {
                    workspace_path,
                    frame_id: args.frame_id.clone(),
                    parent_id: args.parent.clone(),
                    title: args.title.clone(),
                    status,
                    blockers: args.blockers.clone(),
                    created_at: args.created_at.clone(),
                    dry_run: args.dry_run,
                })
            })
        }
    };

    match result {
        Ok(report) => write_task_frame_report(cli, &report, stdout),
        Err(error) => write_domain_error(&error, cli.wants_json(), stdout, stderr),
    }
}

fn parse_task_frame_status(raw: &str) -> Result<TaskFrameStatus, DomainError> {
    TaskFrameStatus::from_str(raw)
}

fn task_frame_evidence_links(
    memory_ids: &[String],
    context_pack_ids: &[String],
    recorder_run_ids: &[String],
    handoff_ids: &[String],
) -> Vec<TaskEvidenceLink> {
    let mut links = Vec::new();
    push_task_frame_evidence(&mut links, "memory", memory_ids);
    push_task_frame_evidence(&mut links, "context_pack", context_pack_ids);
    push_task_frame_evidence(&mut links, "recorder_run", recorder_run_ids);
    push_task_frame_evidence(&mut links, "handoff", handoff_ids);
    links
}

fn push_task_frame_evidence(links: &mut Vec<TaskEvidenceLink>, kind: &str, ids: &[String]) {
    links.extend(ids.iter().map(|id| TaskEvidenceLink {
        kind: kind.to_owned(),
        id: id.clone(),
    }));
}

fn write_task_frame_report<W>(
    cli: &Cli,
    report: &TaskFrameReport,
    stdout: &mut W,
) -> ProcessExitCode
where
    W: Write,
{
    match cli.renderer() {
        output::Renderer::Human | output::Renderer::Markdown => {
            write_stdout(stdout, &render_task_frame_human(report))
        }
        output::Renderer::Toon => write_stdout(
            stdout,
            &(output::render_toon_from_json(&task_frame_response_json(report)) + "\n"),
        ),
        output::Renderer::Json
        | output::Renderer::Jsonl
        | output::Renderer::Compact
        | output::Renderer::Hook => {
            write_stdout(stdout, &(task_frame_response_json(report) + "\n"))
        }
    }
}

fn task_frame_response_json(report: &TaskFrameReport) -> String {
    serde_json::json!({
        "schema": crate::models::RESPONSE_SCHEMA_V1,
        "success": true,
        "data": report.data_json(),
    })
    .to_string()
}

fn render_task_frame_human(report: &TaskFrameReport) -> String {
    if let Some(frame) = &report.frame {
        return format!(
            "Task frame: {}\n  Goal: {}\n  Status: {}\n  Subgoals: {} active / {} total\n  Mutated: {}\n  Store: {}\n",
            frame.id,
            frame.root_goal,
            frame.status.as_str(),
            frame.active_subgoal_count(),
            frame.subgoals.len(),
            report.mutated,
            report.store_path
        );
    }

    format!(
        "Task frames: {} total\n  Mutated: {}\n  Store: {}\n",
        report.frames.len(),
        report.mutated,
        report.store_path
    )
}

fn normalize_outcome_quarantine_args(mut args: Vec<OsString>) -> Vec<OsString> {
    let mut index = 0;
    while index + 1 < args.len() {
        if args[index] == "outcome" && args[index + 1] == "quarantine" {
            args[index] = OsString::from("outcome-quarantine");
            args.remove(index + 1);
            break;
        }
        index += 1;
    }
    args
}

