fn science_status_data_json(report: &crate::science::ScienceStatusReport) -> serde_json::Value {
    let capabilities: Vec<_> = report
        .capabilities
        .iter()
        .map(|capability| {
            serde_json::json!({
                "name": capability.name,
                "state": capability.state.as_str(),
                "requiredFeature": capability.required_feature,
                "degradationCode": capability.degradation_code,
                "description": capability.description,
            })
        })
        .collect();
    let degradations: Vec<_> = report
        .degradations
        .iter()
        .map(|degradation| {
            serde_json::json!({
                "code": degradation.code,
                "severity": degradation.severity,
                "message": degradation.message,
                "repair": degradation.repair,
            })
        })
        .collect();
    serde_json::json!({
        "command": report.command,
        "schema": report.schema,
        "subsystem": report.subsystem,
        "status": report.status.as_str(),
        "available": report.available,
        "feature": {
            "name": report.feature.name,
            "enabled": report.feature.enabled,
            "description": report.feature.description,
        },
        "capabilities": capabilities,
        "degradations": degradations,
        "nextActions": report.next_actions,
    })
}

fn science_status_human(report: &crate::science::ScienceStatusReport) -> String {
    let mut out = String::from("ee analyze science-status\n\n");
    out.push_str(&format!("Status: {}\n", report.status.as_str()));
    out.push_str(&format!("Available: {}\n", report.available));
    out.push_str(&format!(
        "Feature: {} ({})\n",
        report.feature.name,
        if report.feature.enabled {
            "enabled"
        } else {
            "disabled"
        }
    ));
    out.push_str("\nCapabilities:\n");
    for capability in &report.capabilities {
        out.push_str(&format!(
            "  - {}: {} ({})\n",
            capability.name,
            capability.state.as_str(),
            capability.description
        ));
    }
    if !report.degradations.is_empty() {
        out.push_str("\nDegraded:\n");
        for degradation in &report.degradations {
            out.push_str(&format!(
                "  - {}: {} (repair: {})\n",
                degradation.code, degradation.message, degradation.repair
            ));
        }
    }
    if !report.next_actions.is_empty() {
        out.push_str("\nNext:\n");
        for action in &report.next_actions {
            out.push_str(&format!("  {}\n", action));
        }
    }
    out
}

fn aggregate_cli_degraded_json<I>(entries: I) -> Vec<serde_json::Value>
where
    I: IntoIterator<Item = DegradationAggregationInput>,
{
    aggregate_degraded_entries(entries)
        .into_iter()
        .map(|entry| {
            serde_json::json!({
                "code": entry.code,
                "severity": entry.severity,
                "message": entry.message,
                "repair": entry.repair,
                "sources": entry.sources,
            })
        })
        .collect()
}

fn aggregate_why_degraded_json(
    source: &'static str,
    degraded: &[crate::core::why::WhyDegradation],
) -> Vec<serde_json::Value> {
    aggregate_cli_degraded_json(degraded.iter().map(|entry| {
        DegradationAggregationInput::new(
            source,
            entry.code,
            entry.severity,
            entry.message.as_str(),
            entry.repair.as_deref().unwrap_or_default(),
        )
    }))
}

fn aggregate_drift_degraded_json(
    degradations: &[crate::science::DriftDegradation],
) -> Vec<serde_json::Value> {
    aggregate_cli_degraded_json(degradations.iter().map(|d| {
        DegradationAggregationInput::new(
            "science_drift",
            d.code.clone(),
            d.severity.clone(),
            d.message.clone(),
            d.repair.clone(),
        )
    }))
}

fn aggregate_clustering_degraded_json(
    degradations: &[crate::science::ClusteringDegradation],
) -> Vec<serde_json::Value> {
    aggregate_cli_degraded_json(degradations.iter().map(|d| {
        DegradationAggregationInput::new(
            "science_clustering",
            d.code.clone(),
            d.severity.clone(),
            d.message.clone(),
            d.repair.clone(),
        )
    }))
}

fn aggregate_backup_export_degraded_json(
    degraded: &[crate::core::backup::BackupDegradation],
) -> Vec<serde_json::Value> {
    aggregate_degraded_entries(degraded.iter().map(|entry| {
        DegradationAggregationInput::new(
            "backup_export",
            entry.code.clone(),
            entry.severity.clone(),
            entry.message.clone(),
            entry.next_action.clone(),
        )
    }))
    .into_iter()
    .map(|entry| {
        serde_json::json!({
            "code": entry.code,
            "severity": entry.severity,
            "message": entry.message,
            "nextAction": entry.repair,
            "sources": entry.sources,
        })
    })
    .collect()
}

fn handle_analyze_drift<W>(cli: &Cli, args: &AnalyzeDriftArgs, stdout: &mut W) -> ProcessExitCode
where
    W: Write,
{
    let workspace_path = cli.resolve_workspace();
    let options = crate::science::DriftAnalysisOptions {
        baseline_snapshot: args.baseline.clone(),
        current_snapshot: args.current.clone(),
        workspace: workspace_path,
        threshold: args.threshold,
        detailed: args.detailed,
        max_input_bytes: args.max_input_bytes,
        metric_budget: args.metric_budget,
    };
    let report = crate::science::analyze_drift(&options);
    let data = report.data_json();
    let success = report.degradations.is_empty();

    match cli.renderer() {
        output::Renderer::Human | output::Renderer::Markdown => {
            write_stdout(stdout, &report.human_summary());
        }
        output::Renderer::Toon => {
            write_stdout(
                stdout,
                &(output::render_toon_from_json(
                    &serde_json::json!({
                        "schema": crate::models::RESPONSE_SCHEMA_V1,
                        "success": success,
                        "data": data,
                    })
                    .to_string(),
                ) + "\n"),
            );
        }
        output::Renderer::Json
        | output::Renderer::Jsonl
        | output::Renderer::Compact
        | output::Renderer::Hook => {
            if success {
                write_stdout(
                    stdout,
                    &(serde_json::json!({
                        "schema": crate::models::RESPONSE_SCHEMA_V1,
                        "success": true,
                        "data": data,
                    })
                    .to_string()
                        + "\n"),
                );
            } else {
                let degraded = aggregate_drift_degraded_json(&report.degradations);
                write_stdout(
                    stdout,
                    &(serde_json::json!({
                        "schema": crate::models::RESPONSE_SCHEMA_V1,
                        "success": false,
                        "data": data,
                        "degraded": degraded,
                    })
                    .to_string()
                        + "\n"),
                );
            }
        }
    }
    if success {
        ProcessExitCode::Success
    } else {
        ProcessExitCode::UnsatisfiedDegradedMode
    }
}

