fn handle_perf_command<W, E>(
    cli: &Cli,
    command: &PerfCommand,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    match command {
        PerfCommand::Compare(args) => handle_perf_compare(cli, args, stdout, stderr),
        PerfCommand::Budget(PerfBudgetCommand::Check(args)) => {
            handle_perf_budget_check(cli, args, stdout, stderr)
        }
    }
}

