fn run_recorder_follow_loop<W, E>(
    cli: &Cli,
    conn: &crate::db::DbConnection,
    options: crate::core::recorder::RecorderTailOptions,
    poll_ms: u64,
    idle_timeout_ms: Option<u64>,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    let mut seen_event_ids = BTreeSet::new();
    let poll_interval = Duration::from_millis(poll_ms.max(10));
    let mut idle_started = Instant::now();

    loop {
        match crate::core::recorder::poll_follow_events_from_store(conn, &options, &seen_event_ids)
        {
            Ok(crate::core::recorder::TailFollowResult::Events(events)) => {
                idle_started = Instant::now();
                for event in events {
                    seen_event_ids.insert(event.event_id.clone());
                    if let Err(error) = stdout.write_all((event.to_jsonl() + "\n").as_bytes()) {
                        let domain_error = DomainError::Storage {
                            message: format!("Failed to write recorder follow event: {error}"),
                            repair: Some("Check stdout consumer and retry.".to_owned()),
                        };
                        return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
                    }
                }
                if let Err(error) = stdout.flush() {
                    let domain_error = DomainError::Storage {
                        message: format!("Failed to flush recorder follow output: {error}"),
                        repair: Some("Check stdout consumer and retry.".to_owned()),
                    };
                    return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
                }
            }
            Ok(crate::core::recorder::TailFollowResult::RunCompleted { .. }) => {
                return ProcessExitCode::Success;
            }
            Ok(crate::core::recorder::TailFollowResult::RunNotFound) => {
                let error = DomainError::NotFound {
                    resource: "recorder run".to_owned(),
                    id: options
                        .run_id
                        .clone()
                        .unwrap_or_else(|| "<filtered>".to_owned()),
                    repair: Some(
                        "Use `ee recorder tail --json` to inspect available events.".to_owned(),
                    ),
                };
                return write_domain_error(&error, cli.wants_json(), stdout, stderr);
            }
            Ok(crate::core::recorder::TailFollowResult::Waiting { .. })
            | Ok(crate::core::recorder::TailFollowResult::StoreUnavailable { .. }) => {
                if idle_timeout_ms
                    .is_some_and(|timeout| idle_started.elapsed() >= Duration::from_millis(timeout))
                {
                    return ProcessExitCode::Success;
                }
                std::thread::sleep(poll_interval);
            }
            Err(error) => return write_domain_error(&error, cli.wants_json(), stdout, stderr),
        }
    }
}

fn handle_recorder_import<W, E>(
    cli: &Cli,
    args: &RecorderImportArgs,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    if !args.dry_run {
        let error = crate::core::recorder::RecorderImportError {
            code: crate::core::recorder::RecorderImportErrorCode::DryRunRequired,
            message: "Recorder import requires --dry-run until the CLI wires non-dry-run imports to the persisted recorder store.".to_owned(),
            repair: "Use ee recorder import --source-id <source> --dry-run --json.".to_owned(),
            details: Box::new(serde_json::json!({
                "dryRun": false,
            })),
        };
        return write_recorder_import_error(cli.wants_json(), stdout, stderr, &error);
    }

    let source_type = match args.source_type.parse::<crate::models::ImportSourceType>() {
        Ok(source_type) => source_type,
        Err(_) => {
            let error = crate::core::recorder::RecorderImportError {
                code: crate::core::recorder::RecorderImportErrorCode::InvalidSourceType,
                message: format!(
                    "Invalid recorder import source type '{}'.",
                    args.source_type
                ),
                repair: "Use one of: cass, eidetic_legacy, recorder, manual.".to_string(),
                details: Box::new(serde_json::json!({
                    "sourceType": args.source_type
                })),
            };
            return write_recorder_import_error(cli.wants_json(), stdout, stderr, &error);
        }
    };

    let input_json = match args.input.as_ref() {
        Some(path) => match fs::read_to_string(path) {
            Ok(contents) => Some(contents),
            Err(error) => {
                let import_error = crate::core::recorder::RecorderImportError {
                    code: crate::core::recorder::RecorderImportErrorCode::InvalidInputJson,
                    message: format!(
                        "Failed to read recorder import input '{}': {error}.",
                        path.display()
                    ),
                    repair: "Check the --input path and pass a readable CASS view JSON file."
                        .to_string(),
                    details: Box::new(serde_json::json!({
                        "inputPath": path.to_string_lossy()
                    })),
                };
                return write_recorder_import_error(
                    cli.wants_json(),
                    stdout,
                    stderr,
                    &import_error,
                );
            }
        },
        None => None,
    };

    let options = crate::core::recorder::RecorderImportOptions {
        source_type,
        source_id: args.source_id.clone(),
        input_json,
        input_path: args
            .input
            .as_ref()
            .map(|path| path.to_string_lossy().into_owned()),
        agent_id: args.agent_id.clone(),
        session_id: args.session_id.clone(),
        workspace_id: args.workspace_id.clone(),
        max_events: args.max_events,
        redact: args.redact,
        max_payload_bytes: args.max_payload_bytes,
        dry_run: args.dry_run,
    };

    let report = match crate::core::recorder::plan_recorder_import(&options) {
        Ok(report) => report,
        Err(error) => {
            return write_recorder_import_error(cli.wants_json(), stdout, stderr, &error);
        }
    };

    match cli.renderer() {
        output::Renderer::Human | output::Renderer::Markdown => {
            write_stdout(stdout, &report.human_summary())
        }
        output::Renderer::Toon => write_stdout(stdout, &(report.human_summary() + "\n")),
        output::Renderer::Json
        | output::Renderer::Jsonl
        | output::Renderer::Compact
        | output::Renderer::Hook => {
            let json = serde_json::json!({
                "schema": crate::models::RESPONSE_SCHEMA_V1,
                "success": true,
                "data": report.data_json(),
            });
            write_stdout(stdout, &(json.to_string() + "\n"))
        }
    }
}

fn write_recorder_import_error<W, E>(
    wants_json: bool,
    stdout: &mut W,
    stderr: &mut E,
    error: &crate::core::recorder::RecorderImportError,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    if wants_json {
        let json = serde_json::json!({
            "schema": crate::models::ERROR_SCHEMA_V2,
            "error": error.data_json(),
        });
        let _ = stdout.write_all((json.to_string() + "\n").as_bytes());
    } else {
        let _ = writeln!(stderr, "error: {}", error.message);
        let _ = writeln!(stderr, "\nNext:\n  {}", error.repair);
    }
    ProcessExitCode::Usage
}

// ============================================================================
// Recorder Events List Handler
// ============================================================================

fn handle_recorder_events_list<W, E>(
    cli: &Cli,
    args: &RecorderEventsListArgs,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    use crate::core::recorder::{
        RECORDER_EVENTS_LIST_SCHEMA_V1, RecorderEventsListOptions, RecorderEventsListReport,
    };
    use crate::db::DbConnection;

    let workspace_path = cli
        .workspace
        .clone()
        .unwrap_or_else(|| args.workspace.clone());
    let database_path = args
        .database
        .clone()
        .unwrap_or_else(|| workspace_path.join(".ee").join("ee.db"));

    if !database_path.exists() {
        let domain_error = DomainError::Storage {
            message: format!("Database not found at {}", database_path.display()),
            repair: Some("ee init --workspace .".to_string()),
        };
        return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
    }

    let conn = match DbConnection::open_file(&database_path) {
        Ok(c) => c,
        Err(e) => {
            let domain_error = DomainError::Storage {
                message: format!("Failed to open database: {e}"),
                repair: Some("ee status --json".to_string()),
            };
            return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
        }
    };

    if args.limit == 0 {
        let domain_error = DomainError::Usage {
            message: "--limit must be greater than zero".to_owned(),
            repair: Some(
                "Pass --limit with a positive integer (default: 100), or omit it.".to_owned(),
            ),
        };
        return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
    }

    let options = RecorderEventsListOptions {
        since: args.since.clone(),
        source: args.source.clone(),
        run_id: args.run_id.clone(),
        limit: args.limit,
    };

    let events = match crate::core::recorder::list_recorder_events(&conn, &options) {
        Ok(e) => e,
        Err(e) => {
            return write_domain_error(&e, cli.wants_json(), stdout, stderr);
        }
    };

    let report = RecorderEventsListReport {
        schema: RECORDER_EVENTS_LIST_SCHEMA_V1,
        events,
        filters: options,
    };

    match cli.renderer() {
        output::Renderer::Human | output::Renderer::Markdown => {
            write_stdout(stdout, &report.human_summary())
        }
        output::Renderer::Toon => {
            let json = recorder_events_list_response_json(&report);
            write_stdout(stdout, &(output::render_toon_from_json(&json) + "\n"))
        }
        output::Renderer::Json
        | output::Renderer::Jsonl
        | output::Renderer::Compact
        | output::Renderer::Hook => {
            let json = recorder_events_list_response_json(&report);
            write_stdout(stdout, &(json + "\n"))
        }
    }
}

fn recorder_events_list_response_json(
    report: &crate::core::recorder::RecorderEventsListReport,
) -> String {
    serde_json::json!({
        "schema": crate::models::RESPONSE_SCHEMA_V1,
        "success": true,
        "data": report.data_json(),
    })
    .to_string()
}

// ============================================================================
// EE-RATIONALE-TRACE-001: Rationale Trace Handlers
// ============================================================================

fn handle_rationale_attach<W, E>(
    cli: &Cli,
    args: &RationaleAttachArgs,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    use crate::models::{RationaleTrace, RationaleTraceKind};

    let workspace_path = cli.resolve_workspace();
    let database_path = args
        .database
        .clone()
        .unwrap_or_else(|| workspace_path.join(".ee").join("ee.db"));

    if !database_path.exists() {
        let domain_error = DomainError::Storage {
            message: format!("Database not found at {}", database_path.display()),
            repair: Some("ee init --workspace .".to_string()),
        };
        return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
    }

    let kind = match args.kind.parse::<RationaleTraceKind>() {
        Ok(k) => k,
        Err(_) => {
            let domain_error = DomainError::Usage {
                message: format!("Invalid rationale kind '{}'", args.kind),
                repair: Some("Use one of: hypothesis, decision, question, rejected_alternative, observation, conclusion".to_string()),
            };
            return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
        }
    };

    let valid_target_types = [
        "memory",
        "context_pack",
        "recorder_run",
        "recorder_event",
        "causal_trace",
    ];
    if !valid_target_types.contains(&args.target_type.as_str()) {
        let domain_error = DomainError::Usage {
            message: format!("Invalid target type '{}'", args.target_type),
            repair: Some(
                "Use one of: memory, context_pack, recorder_run, recorder_event, causal_trace"
                    .to_string(),
            ),
        };
        return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
    }

    let now = chrono::Utc::now().to_rfc3339();
    let trace_id = format!("rat_{}", uuid::Uuid::now_v7());

    let mut trace = match RationaleTrace::new(&trace_id, kind, &args.author, &args.summary, &now) {
        Ok(t) => t,
        Err(e) => {
            let domain_error = DomainError::Usage {
                message: format!("Invalid rationale trace: {e}"),
                repair: Some(
                    "Ensure summary does not contain private chain-of-thought markers or secrets"
                        .to_string(),
                ),
            };
            return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
        }
    };

    if let Some(confidence) = args.confidence {
        trace.confidence_basis_points = confidence.min(10000);
    }

    if let Some(ref uris) = args.evidence_uris {
        trace.evidence_uris = uris.split(',').map(|s| s.trim().to_string()).collect();
    }

    match args.target_type.as_str() {
        "memory" => trace.linked_memory_ids.push(args.target_id.clone()),
        "context_pack" => trace.linked_context_pack_ids.push(args.target_id.clone()),
        "recorder_run" => trace.linked_recorder_run_ids.push(args.target_id.clone()),
        "recorder_event" => trace.linked_recorder_event_ids.push(args.target_id.clone()),
        "causal_trace" => trace.linked_causal_trace_ids.push(args.target_id.clone()),
        _ => {}
    }

    if args.dry_run {
        let output = serde_json::json!({
            "schema": crate::models::RESPONSE_SCHEMA_V1,
            "success": true,
            "dryRun": true,
            "data": {
                "traceId": trace_id,
                "kind": args.kind,
                "targetType": args.target_type,
                "targetId": args.target_id,
                "author": args.author,
                "summary": args.summary,
            }
        });
        return write_stdout(stdout, &(output.to_string() + "\n"));
    }

    let conn = match crate::db::DbConnection::open_file(&database_path) {
        Ok(c) => c,
        Err(e) => {
            let domain_error = DomainError::Storage {
                message: format!("Failed to open database: {e}"),
                repair: Some("ee init --workspace .".to_string()),
            };
            return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
        }
    };

    let workspace_id = crate::core::curate::stable_workspace_id(&workspace_path);

    let audit_details = serde_json::json!({
        "targetType": &args.target_type,
        "targetId": &args.target_id,
        "kind": &args.kind,
        "evidenceUriCount": trace.evidence_uris.len(),
    })
    .to_string();
    let audit_input = crate::db::AuditedRationaleTraceInput {
        workspace_id: workspace_id.clone(),
        trace,
        actor: Some(args.author.clone()),
        details: Some(audit_details),
    };

    if let Err(e) = conn.insert_rationale_trace_audited(&audit_input) {
        let domain_error = DomainError::Storage {
            message: format!("Failed to store rationale trace: {e}"),
            repair: Some("ee db migrate".to_string()),
        };
        return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
    }

    let output = serde_json::json!({
        "schema": crate::models::RESPONSE_SCHEMA_V1,
        "success": true,
        "data": {
            "traceId": trace_id,
            "kind": args.kind,
            "targetType": args.target_type,
            "targetId": args.target_id,
            "author": args.author,
            "createdAt": now,
        }
    });
    write_stdout(stdout, &(output.to_string() + "\n"))
}

fn handle_rationale_show<W, E>(
    cli: &Cli,
    args: &RationaleShowArgs,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    let workspace_path = cli.resolve_workspace();
    let database_path = args
        .database
        .clone()
        .unwrap_or_else(|| workspace_path.join(".ee").join("ee.db"));

    if !database_path.exists() {
        let domain_error = DomainError::Storage {
            message: format!("Database not found at {}", database_path.display()),
            repair: Some("ee init --workspace .".to_string()),
        };
        return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
    }

    let conn = match crate::db::DbConnection::open_file(&database_path) {
        Ok(c) => c,
        Err(e) => {
            let domain_error = DomainError::Storage {
                message: format!("Failed to open database: {e}"),
                repair: Some("ee init --workspace .".to_string()),
            };
            return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
        }
    };

    match conn.get_rationale_trace(&args.trace_id) {
        Ok(Some(stored)) => {
            let output = serde_json::json!({
                "schema": crate::models::RESPONSE_SCHEMA_V1,
                "success": true,
                "data": {
                    "traceId": stored.trace.trace_id,
                    "workspaceId": stored.workspace_id,
                    "kind": stored.trace.kind.as_str(),
                    "author": stored.trace.author,
                    "summary": stored.trace.summary,
                    "posture": stored.trace.posture.as_str(),
                    "confidenceBasisPoints": stored.trace.confidence_basis_points,
                    "visibility": stored.trace.visibility.as_str(),
                    "evidenceUris": stored.trace.evidence_uris,
                    "linkedMemoryIds": stored.trace.linked_memory_ids,
                    "linkedContextPackIds": stored.trace.linked_context_pack_ids,
                    "linkedRecorderRunIds": stored.trace.linked_recorder_run_ids,
                    "linkedRecorderEventIds": stored.trace.linked_recorder_event_ids,
                    "linkedCausalTraceIds": stored.trace.linked_causal_trace_ids,
                    "createdAt": stored.trace.created_at,
                }
            });
            write_stdout(stdout, &(output.to_string() + "\n"))
        }
        Ok(None) => {
            let domain_error = DomainError::NotFound {
                resource: "rationale_trace".to_string(),
                id: args.trace_id.clone(),
                repair: Some("ee rationale list --target-type memory --target-id <id>".to_string()),
            };
            write_domain_error(&domain_error, cli.wants_json(), stdout, stderr)
        }
        Err(e) => {
            let domain_error = DomainError::Storage {
                message: format!("Failed to query rationale trace: {e}"),
                repair: Some("ee db migrate".to_string()),
            };
            write_domain_error(&domain_error, cli.wants_json(), stdout, stderr)
        }
    }
}

fn handle_rationale_list<W, E>(
    cli: &Cli,
    args: &RationaleListArgs,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    let workspace_path = cli.resolve_workspace();
    let database_path = args
        .database
        .clone()
        .unwrap_or_else(|| workspace_path.join(".ee").join("ee.db"));

    if !database_path.exists() {
        let domain_error = DomainError::Storage {
            message: format!("Database not found at {}", database_path.display()),
            repair: Some("ee init --workspace .".to_string()),
        };
        return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
    }

    let conn = match crate::db::DbConnection::open_file(&database_path) {
        Ok(c) => c,
        Err(e) => {
            let domain_error = DomainError::Storage {
                message: format!("Failed to open database: {e}"),
                repair: Some("ee init --workspace .".to_string()),
            };
            return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
        }
    };

    let workspace_id = crate::core::curate::stable_workspace_id(&workspace_path);

    match conn.list_rationale_traces_for_target(&workspace_id, &args.target_type, &args.target_id) {
        Ok(traces) => {
            let trace_summaries: Vec<_> = traces
                .iter()
                .map(|stored| {
                    serde_json::json!({
                        "traceId": stored.trace.trace_id,
                        "kind": stored.trace.kind.as_str(),
                        "author": stored.trace.author,
                        "summary": stored.trace.summary,
                        "posture": stored.trace.posture.as_str(),
                        "confidenceBasisPoints": stored.trace.confidence_basis_points,
                        "createdAt": stored.trace.created_at,
                    })
                })
                .collect();

            let output = serde_json::json!({
                "schema": crate::models::RESPONSE_SCHEMA_V1,
                "success": true,
                "data": {
                    "targetType": args.target_type,
                    "targetId": args.target_id,
                    "count": trace_summaries.len(),
                    "traces": trace_summaries,
                }
            });
            write_stdout(stdout, &(output.to_string() + "\n"))
        }
        Err(e) => {
            let domain_error = DomainError::Storage {
                message: format!("Failed to list rationale traces: {e}"),
                repair: Some("ee db migrate".to_string()),
            };
            write_domain_error(&domain_error, cli.wants_json(), stdout, stderr)
        }
    }
}

