fn handle_diag_quarantine_show<W, E>(
    cli: &Cli,
    args: &DiagQuarantineShowArgs,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    let workspace_path =
        resolve_cli_workspace_path(cli.workspace.as_deref().unwrap_or_else(|| Path::new(".")));
    let canonical_path = match workspace_path.canonicalize() {
        Ok(path) => path,
        Err(error) => {
            return write_domain_error(
                &DomainError::Configuration {
                    message: format!("Failed to resolve workspace: {error}"),
                    repair: Some("ee init --workspace .".to_owned()),
                },
                cli.wants_json(),
                stdout,
                stderr,
            );
        }
    };
    let database_path = canonical_path.join(".ee").join("ee.db");
    if !database_path.is_file() {
        return write_domain_error(
            &DomainError::Configuration {
                message: format!("No ee database was found at {}.", database_path.display()),
                repair: Some("ee init --workspace .".to_owned()),
            },
            cli.wants_json(),
            stdout,
            stderr,
        );
    }
    let workspace_id = crate::core::curate::stable_workspace_id(&canonical_path);
    let connection = match crate::db::DbConnection::open_file(&database_path) {
        Ok(connection) => connection,
        Err(error) => {
            return write_domain_error(
                &DomainError::Storage {
                    message: format!("Failed to open database: {error}"),
                    repair: Some("ee doctor --json".to_owned()),
                },
                cli.wants_json(),
                stdout,
                stderr,
            );
        }
    };

    let entry = match connection.get_trust_quarantine(&workspace_id, &args.source_uri) {
        Ok(Some(row)) => row,
        Ok(None) => {
            return write_domain_error(
                &DomainError::NotFound {
                    resource: "quarantine record".to_owned(),
                    id: args.source_uri.clone(),
                    repair: Some("ee diag quarantine list --json".to_owned()),
                },
                cli.wants_json(),
                stdout,
                stderr,
            );
        }
        Err(error) => {
            return write_domain_error(
                &DomainError::Storage {
                    message: format!("Failed to query quarantine state: {error}"),
                    repair: Some("ee db migrate --workspace .".to_owned()),
                },
                cli.wants_json(),
                stdout,
                stderr,
            );
        }
    };

    match cli.renderer() {
        output::Renderer::Human | output::Renderer::Markdown => {
            write_stdout(stdout, &output::render_quarantine_entry_human(&entry))
        }
        output::Renderer::Toon => write_stdout(
            stdout,
            &(output::render_quarantine_entry_toon(&entry) + "\n"),
        ),
        output::Renderer::Json
        | output::Renderer::Jsonl
        | output::Renderer::Compact
        | output::Renderer::Hook => write_stdout(
            stdout,
            &(output::render_quarantine_entry_json(&entry) + "\n"),
        ),
    }
}

