fn handle_graph_k_core<W, E>(
    cli: &Cli,
    args: &GraphKCoreArgs,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    match validate_graph_read_options(GraphReadOptions::from(args)) {
        Ok(()) => {}
        Err(error) => return write_domain_error(&error, cli.wants_json(), stdout, stderr),
    }

    #[cfg(feature = "graph")]
    {
        match graph_algorithm_input(cli, GraphReadOptions::from(args)) {
            Ok(input) => {
                let result = fnx_algorithms::k_core(&input.undirected, args.k);
                let mut sorted_nodes = result.nodes.clone();
                sorted_nodes.sort();
                let mut sorted_edges: Vec<_> = result
                    .edges
                    .iter()
                    .map(|(left, right)| {
                        if left <= right {
                            (left.clone(), right.clone())
                        } else {
                            (right.clone(), left.clone())
                        }
                    })
                    .collect();
                sorted_edges.sort();
                let data = graph_metric_data(
                    "graph k-core",
                    &input,
                    serde_json::json!({
                        "k": args.k,
                        "nodes": sorted_nodes,
                        "edges": sorted_edges.iter().map(|(left, right)| {
                            serde_json::json!({"left": left, "right": right})
                        }).collect::<Vec<_>>(),
                        "witness": graph_witness_json(&result.witness),
                    }),
                );
                write_graph_surface_data(cli, stdout, data)
            }
            Err(error) => write_domain_error(&error, cli.wants_json(), stdout, stderr),
        }
    }

    #[cfg(not(feature = "graph"))]
    {
        let _ = stderr;
        write_graph_surface_data(cli, stdout, graph_feature_disabled_data("graph k-core"))
    }
}

