fn handle_graph_path<W, E>(
    cli: &Cli,
    args: &GraphPathArgs,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    match validate_graph_read_options(GraphReadOptions::from(args))
        .and_then(|()| validate_graph_memory_pair(&args.src_memory_id, &args.dst_memory_id))
    {
        Ok(()) => {}
        Err(error) => return write_domain_error(&error, cli.wants_json(), stdout, stderr),
    }

    #[cfg(feature = "graph")]
    {
        match graph_algorithm_input(cli, GraphReadOptions::from(args)) {
            Ok(input) => {
                let result = fnx_algorithms::shortest_path_unweighted_directed(
                    &input.directed,
                    &args.src_memory_id,
                    &args.dst_memory_id,
                );
                let path_length = result
                    .path
                    .as_ref()
                    .map(|path| path.len().saturating_sub(1));
                let status = if result.path.is_some() {
                    "path_found"
                } else {
                    "no_path"
                };
                let data = graph_metric_data_with_status(
                    "graph path",
                    status,
                    &input,
                    serde_json::json!({
                        "srcMemoryId": args.src_memory_id,
                        "dstMemoryId": args.dst_memory_id,
                        "path": result.path,
                        "pathLength": path_length,
                        "witness": graph_witness_json(&result.witness),
                    }),
                );
                write_graph_surface_data(cli, stdout, data)
            }
            Err(error) => write_domain_error(&error, cli.wants_json(), stdout, stderr),
        }
    }

    #[cfg(not(feature = "graph"))]
    {
        let _ = stderr;
        write_graph_surface_data(cli, stdout, graph_feature_disabled_data("graph path"))
    }
}

fn handle_graph_explain_link<W, E>(
    cli: &Cli,
    args: &GraphExplainLinkArgs,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    match validate_graph_read_options(GraphReadOptions::from(args))
        .and_then(|()| validate_graph_memory_pair(&args.src_memory_id, &args.dst_memory_id))
    {
        Ok(()) => {}
        Err(error) => return write_domain_error(&error, cli.wants_json(), stdout, stderr),
    }

    #[cfg(feature = "graph")]
    {
        match graph_algorithm_input(cli, GraphReadOptions::from(args)) {
            Ok(input) => {
                let result = fnx_algorithms::shortest_path_unweighted_directed(
                    &input.directed,
                    &args.src_memory_id,
                    &args.dst_memory_id,
                );
                let direct_links =
                    graph_direct_link_json(&input.links, &args.src_memory_id, &args.dst_memory_id);
                let status = if !direct_links.is_empty() {
                    "direct_link_found"
                } else if result.path.is_some() {
                    "path_found"
                } else {
                    "no_link_path"
                };
                let data = graph_metric_data_with_status(
                    "graph explain-link",
                    status,
                    &input,
                    serde_json::json!({
                        "srcMemoryId": args.src_memory_id,
                        "dstMemoryId": args.dst_memory_id,
                        "directLinks": direct_links,
                        "path": result.path,
                        "pathLength": result.path.as_ref().map(|path| path.len().saturating_sub(1)),
                        "witness": graph_witness_json(&result.witness),
                    }),
                );
                write_graph_surface_data(cli, stdout, data)
            }
            Err(error) => write_domain_error(&error, cli.wants_json(), stdout, stderr),
        }
    }

    #[cfg(not(feature = "graph"))]
    {
        let _ = stderr;
        write_graph_surface_data(
            cli,
            stdout,
            graph_feature_disabled_data("graph explain-link"),
        )
    }
}

fn handle_proximity<W, E>(
    cli: &Cli,
    args: &ProximityArgs,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    match validate_graph_read_options(GraphReadOptions::from(args))
        .and_then(|()| validate_graph_memory_pair(&args.memory_a, &args.memory_b))
    {
        Ok(()) => {}
        Err(error) => return write_domain_error(&error, cli.wants_json(), stdout, stderr),
    }

    match proximity_feature_enabled(cli) {
        Ok(true) => {}
        Ok(false) => {
            let report = proximity_feature_disabled_report(args);
            return write_proximity_report(cli, &report, stdout);
        }
        Err(error) => {
            let domain_error = config_surface_error_to_domain(error);
            return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
        }
    }

    #[cfg(feature = "graph")]
    {
        match graph_algorithm_input(cli, GraphReadOptions::from(args)).and_then(|input| {
            crate::graph::gomory_hu::build_gomory_hu_tree(&input.undirected)
                .map(|tree| {
                    crate::graph::gomory_hu::query_proximity(
                        &tree,
                        &args.memory_a,
                        &args.memory_b,
                        0,
                    )
                })
                .map_err(|error| DomainError::Graph {
                    message: error.to_string(),
                    repair: Some("ee graph centrality-refresh --workspace .".to_string()),
                })
        }) {
            Ok(report) => write_proximity_report(cli, &report, stdout),
            Err(error) => write_domain_error(&error, cli.wants_json(), stdout, stderr),
        }
    }

    #[cfg(not(feature = "graph"))]
    {
        let _ = stderr;
        let report = serde_json::json!({
            "schema": crate::graph::gomory_hu::PROXIMITY_SCHEMA_V1,
            "memoryA": args.memory_a,
            "memoryB": args.memory_b,
            "snapshotVersion": 0,
            "minCut": null,
            "interpretation": "graph_feature_disabled",
            "treePath": null,
            "degraded": [{
                "code": "graph_feature_disabled",
                "severity": "medium",
                "message": "Proximity requires graph feature support.",
                "repair": "Build or run ee with --features graph."
            }]
        });
        write_stdout(stdout, &(report.to_string() + "\n"))
    }
}

fn proximity_feature_disabled_report(
    args: &ProximityArgs,
) -> crate::graph::gomory_hu::ProximityReport {
    crate::graph::gomory_hu::ProximityReport {
        schema: crate::graph::gomory_hu::PROXIMITY_SCHEMA_V1,
        memory_a: args.memory_a.clone(),
        memory_b: args.memory_b.clone(),
        snapshot_version: 0,
        min_cut: None,
        interpretation: "graph_feature_disabled".to_string(),
        tree_path: None,
        degraded: vec![crate::graph::gomory_hu::ProximityDegradation {
            code: "graph_feature_disabled".to_string(),
            severity: "medium".to_string(),
            message: "Proximity is disabled by graph.feature.proximity.enabled.".to_string(),
            repair: Some("ee config set graph.feature.proximity.enabled true".to_string()),
        }],
    }
}

fn write_proximity_report<W>(
    cli: &Cli,
    report: &crate::graph::gomory_hu::ProximityReport,
    stdout: &mut W,
) -> ProcessExitCode
where
    W: Write,
{
    match cli.renderer() {
        output::Renderer::Human | output::Renderer::Markdown => {
            write_stdout(stdout, &proximity_human_output(report))
        }
        output::Renderer::Toon => {
            let json = serde_json::to_string(report).unwrap_or_else(|_| "{}".to_string());
            write_stdout(stdout, &(output::render_toon_from_json(&json) + "\n"))
        }
        output::Renderer::Json
        | output::Renderer::Jsonl
        | output::Renderer::Compact
        | output::Renderer::Hook => {
            let json = serde_json::to_string(report).unwrap_or_else(|_| "{}".to_string());
            write_stdout(stdout, &(json + "\n"))
        }
    }
}

fn proximity_human_output(report: &crate::graph::gomory_hu::ProximityReport) -> String {
    let min_cut = report
        .min_cut
        .map(|value| graph_score_json_value(value).to_string())
        .unwrap_or_else(|| "unavailable".to_string());
    let path = report
        .tree_path
        .as_ref()
        .map(|nodes| nodes.join(" -> "))
        .unwrap_or_else(|| "unavailable".to_string());
    let mut output = format!(
        "Proximity between {} and {}\n\n  Interpretation: {}\n  Min cut: {}\n  Tree path: {}\n",
        report.memory_a, report.memory_b, report.interpretation, min_cut, path
    );
    for degraded in &report.degraded {
        output.push_str(&format!("\nDegraded: {}\n", degraded.message));
        if let Some(repair) = &degraded.repair {
            output.push_str(&format!("Next: {repair}\n"));
        }
    }
    output
}

fn validate_graph_read_options(options: GraphReadOptions<'_>) -> Result<(), DomainError> {
    let _ = options.database;
    let _ = options.link_limit;
    let _ = options.include_tombstoned;
    if matches!(options.limit, Some(0)) {
        return Err(DomainError::Usage {
            message: "--limit must be greater than zero".to_string(),
            repair: Some("Omit --limit or pass a positive value.".to_string()),
        });
    }
    validate_graph_threshold(options.min_weight, "--min-weight")?;
    validate_graph_threshold(options.min_confidence, "--min-confidence")
}

fn validate_graph_threshold(value: Option<f32>, name: &'static str) -> Result<(), DomainError> {
    if value.is_some_and(|value| !value.is_finite() || !(0.0..=1.0).contains(&value)) {
        Err(DomainError::Usage {
            message: format!("{name} must be a finite value in [0.0, 1.0]"),
            repair: Some(format!("Use a value like 0.5 or omit {name}.")),
        })
    } else {
        Ok(())
    }
}

fn validate_graph_louvain_args(args: &GraphLouvainArgs) -> Result<(), DomainError> {
    if !args.resolution.is_finite() || args.resolution <= 0.0 {
        return Err(DomainError::Usage {
            message: "--resolution must be a finite positive value".to_string(),
            repair: Some("Use a value like 1.0.".to_string()),
        });
    }
    if !args.threshold.is_finite() || args.threshold < 0.0 {
        return Err(DomainError::Usage {
            message: "--threshold must be a finite non-negative value".to_string(),
            repair: Some("Use a value like 1e-7.".to_string()),
        });
    }
    if matches!(args.max_level, Some(0)) {
        return Err(DomainError::Usage {
            message: "--max-level must be greater than zero".to_string(),
            repair: Some("Omit --max-level or pass a positive value.".to_string()),
        });
    }
    Ok(())
}

fn validate_graph_memory_pair(src_memory_id: &str, dst_memory_id: &str) -> Result<(), DomainError> {
    if src_memory_id.trim().is_empty() || dst_memory_id.trim().is_empty() {
        return Err(DomainError::Usage {
            message: "source and destination memory IDs must be non-empty".to_string(),
            repair: Some(
                "Pass two memory IDs, for example `ee graph path mem_a mem_b`.".to_string(),
            ),
        });
    }
    Ok(())
}

#[cfg(feature = "graph")]
struct GraphAlgorithmInput {
    directed: fnx_classes::digraph::DiGraph,
    undirected: fnx_classes::Graph,
    links: Vec<crate::db::StoredMemoryLink>,
    excluded_tombstoned_nodes: Vec<String>,
}

#[cfg(feature = "graph")]
impl GraphAlgorithmInput {
    fn node_count(&self) -> usize {
        self.directed.node_count()
    }

    fn edge_count(&self) -> usize {
        self.directed.edge_count()
    }
}

#[cfg(feature = "graph")]
fn graph_algorithm_input(
    cli: &Cli,
    options: GraphReadOptions<'_>,
) -> Result<GraphAlgorithmInput, DomainError> {
    use fnx_classes::{AttrMap, Graph, digraph::DiGraph};
    use fnx_runtime::CgseValue;

    let database_path = graph_database_path(cli, options.database)?;
    let conn = crate::db::DbConnection::open_file(&database_path).map_err(|error| {
        DomainError::Storage {
            message: format!("Failed to open database: {error}"),
            repair: None,
        }
    })?;
    let links = conn
        .list_all_memory_links(options.link_limit)
        .map_err(|error| DomainError::Storage {
            message: format!("Failed to query memory links: {error}"),
            repair: Some("ee doctor --json".to_string()),
        })?
        .into_iter()
        .filter(|link| graph_link_matches_read_options(link, options))
        .collect::<Vec<_>>();
    let (links, excluded_tombstoned_nodes) =
        graph_filter_tombstoned_links(&conn, links, options.include_tombstoned)?;

    let mut directed = DiGraph::strict();
    let mut undirected = Graph::strict();
    for link in &links {
        let attrs = graph_link_attrs(link);
        directed
            .add_edge_with_attrs(
                link.src_memory_id.clone(),
                link.dst_memory_id.clone(),
                attrs.clone(),
            )
            .map_err(|error| DomainError::Graph {
                message: format!("Failed to build directed graph projection: {error}"),
                repair: Some("Validate memory link rows with `ee doctor --json`.".to_string()),
            })?;
        if !link.directed {
            directed
                .add_edge_with_attrs(
                    link.dst_memory_id.clone(),
                    link.src_memory_id.clone(),
                    attrs.clone(),
                )
                .map_err(|error| DomainError::Graph {
                    message: format!("Failed to build reciprocal graph projection: {error}"),
                    repair: Some("Validate memory link rows with `ee doctor --json`.".to_string()),
                })?;
        }
        undirected
            .add_edge_with_attrs(
                link.src_memory_id.clone(),
                link.dst_memory_id.clone(),
                attrs,
            )
            .map_err(|error| DomainError::Graph {
                message: format!("Failed to build undirected graph projection: {error}"),
                repair: Some("Validate memory link rows with `ee doctor --json`.".to_string()),
            })?;
    }

    fn graph_link_attrs(link: &crate::db::StoredMemoryLink) -> AttrMap {
        let mut attrs = AttrMap::new();
        attrs.insert(
            "weight".to_string(),
            CgseValue::Float(f64::from(link.weight)),
        );
        attrs.insert(
            "confidence".to_string(),
            CgseValue::Float(f64::from(link.confidence)),
        );
        attrs.insert(
            "relation".to_string(),
            CgseValue::String(link.relation.clone()),
        );
        attrs.insert("source".to_string(), CgseValue::String(link.source.clone()));
        attrs.insert(
            "evidence_count".to_string(),
            CgseValue::Int(i64::from(link.evidence_count)),
        );
        attrs
    }

    Ok(GraphAlgorithmInput {
        directed,
        undirected,
        links,
        excluded_tombstoned_nodes,
    })
}

#[cfg(feature = "graph")]
fn graph_filter_tombstoned_links(
    conn: &crate::db::DbConnection,
    links: Vec<crate::db::StoredMemoryLink>,
    include_tombstoned: bool,
) -> Result<(Vec<crate::db::StoredMemoryLink>, Vec<String>), DomainError> {
    if include_tombstoned || links.is_empty() {
        return Ok((links, Vec::new()));
    }

    let memory_ids = links
        .iter()
        .flat_map(|link| [link.src_memory_id.as_str(), link.dst_memory_id.as_str()])
        .collect::<BTreeSet<_>>();
    let memory_refs = memory_ids.iter().copied().collect::<Vec<_>>();
    let memories = conn
        .get_memories_batch(&memory_refs)
        .map_err(|error| DomainError::Storage {
            message: format!("Failed to query graph memory endpoints: {error}"),
            repair: Some("ee doctor --json".to_string()),
        })?;
    let tombstoned = memories
        .into_iter()
        .filter(|(_, memory)| memory.tombstoned_at.is_some())
        .map(|(_, memory)| memory.id)
        .collect::<BTreeSet<_>>();
    if tombstoned.is_empty() {
        return Ok((links, Vec::new()));
    }

    let filtered = links
        .into_iter()
        .filter(|link| {
            !tombstoned.contains(&link.src_memory_id) && !tombstoned.contains(&link.dst_memory_id)
        })
        .collect::<Vec<_>>();
    Ok((filtered, tombstoned.into_iter().collect()))
}

#[cfg(feature = "graph")]
fn graph_database_path(
    cli: &Cli,
    explicit_database: Option<&Path>,
) -> Result<PathBuf, DomainError> {
    let workspace =
        resolve_cli_workspace_path(cli.workspace.as_deref().unwrap_or_else(|| Path::new(".")));
    let database_path = explicit_database
        .map(Path::to_path_buf)
        .unwrap_or_else(|| workspace.join(".ee").join("ee.db"));
    if !database_path.exists() {
        return Err(DomainError::Storage {
            message: format!("Database not found at {}", database_path.display()),
            repair: Some("ee init --workspace .".to_string()),
        });
    }
    Ok(database_path)
}

#[cfg(feature = "graph")]
fn graph_link_matches_read_options(
    link: &crate::db::StoredMemoryLink,
    options: GraphReadOptions<'_>,
) -> bool {
    crate::graph::memory_link_mesh_metadata_visible(link.metadata_json.as_deref())
        && options
            .min_weight
            .is_none_or(|min_weight| link.weight >= min_weight)
        && options
            .min_confidence
            .is_none_or(|min_confidence| link.confidence >= min_confidence)
}

#[cfg(feature = "graph")]
fn graph_metric_data(
    command: &'static str,
    input: &GraphAlgorithmInput,
    extra: serde_json::Value,
) -> serde_json::Value {
    graph_metric_data_with_status(command, "computed", input, extra)
}

#[cfg(feature = "graph")]
fn graph_metric_data_with_status(
    command: &'static str,
    status: &'static str,
    input: &GraphAlgorithmInput,
    extra: serde_json::Value,
) -> serde_json::Value {
    let mut data = serde_json::json!({
        "schema": GRAPH_ALGORITHM_SCHEMA_V1,
        "command": command,
        "version": env!("CARGO_PKG_VERSION"),
        "status": status,
        "graph": {
            "nodeCount": input.node_count(),
            "edgeCount": input.edge_count(),
            "sourceLinkCount": input.links.len(),
            "excludedNodes": input.excluded_tombstoned_nodes.clone(),
        },
    });
    if let (Some(object), Some(extra)) = (data.as_object_mut(), extra.as_object()) {
        for (key, value) in extra {
            object.insert(key.clone(), value.clone());
        }
    }
    data
}

#[cfg(feature = "graph")]
fn graph_communities_data(
    command: &'static str,
    input: &GraphAlgorithmInput,
    communities: Vec<Vec<String>>,
    limit: Option<usize>,
) -> serde_json::Value {
    let total = communities.len();
    let limited = limit.is_some_and(|limit| communities.len() > limit);
    let mut sorted_communities: Vec<Vec<String>> = communities
        .into_iter()
        .map(|mut nodes| {
            nodes.sort();
            nodes
        })
        .collect();
    sorted_communities.sort_by(|a, b| {
        b.len()
            .cmp(&a.len())
            .then_with(|| a.first().cmp(&b.first()))
    });
    let communities = if let Some(limit) = limit {
        sorted_communities
            .into_iter()
            .take(limit)
            .collect::<Vec<_>>()
    } else {
        sorted_communities
    };
    graph_metric_data(
        command,
        input,
        serde_json::json!({
            "communityCount": total,
            "limited": limited,
            "communities": communities
                .into_iter()
                .enumerate()
                .map(|(index, nodes)| {
                    serde_json::json!({
                        "communityId": format!("community_{:04}", index + 1),
                        "size": nodes.len(),
                        "nodes": nodes,
                    })
                })
                .collect::<Vec<_>>(),
        }),
    )
}

#[cfg(feature = "graph")]
fn graph_scores_json(
    scores: &[fnx_algorithms::CentralityScore],
    limit: Option<usize>,
) -> Vec<serde_json::Value> {
    let mut ordered = scores.iter().collect::<Vec<_>>();
    ordered.sort_by(|left, right| {
        right
            .score
            .total_cmp(&left.score)
            .then_with(|| left.node.cmp(&right.node))
    });
    if let Some(limit) = limit {
        ordered.truncate(limit);
    }
    ordered
        .into_iter()
        .enumerate()
        .map(|(index, score)| {
            serde_json::json!({
                "rank": index + 1,
                "memoryId": score.node,
                "score": graph_score_json_value(score.score),
            })
        })
        .collect()
}

#[cfg(feature = "graph")]
fn graph_score_map_json(
    scores: &std::collections::BTreeMap<String, f64>,
    limit: Option<usize>,
) -> Vec<serde_json::Value> {
    let mut ordered = scores.iter().collect::<Vec<_>>();
    ordered.sort_by(|left, right| right.1.total_cmp(left.1).then_with(|| left.0.cmp(right.0)));
    if let Some(limit) = limit {
        ordered.truncate(limit);
    }
    ordered
        .into_iter()
        .enumerate()
        .map(|(index, (memory_id, score))| {
            serde_json::json!({
                "rank": index + 1,
                "memoryId": memory_id,
                "score": graph_score_json_value(*score),
            })
        })
        .collect()
}

#[cfg(feature = "graph")]
fn graph_witness_json(witness: &fnx_algorithms::ComplexityWitness) -> serde_json::Value {
    serde_json::json!({
        "algorithm": witness.algorithm,
        "complexityClaim": witness.complexity_claim,
        "nodesTouched": witness.nodes_touched,
        "edgesScanned": witness.edges_scanned,
        "queuePeak": witness.queue_peak,
    })
}

#[cfg(feature = "graph")]
fn graph_direct_link_json(
    links: &[crate::db::StoredMemoryLink],
    src_memory_id: &str,
    dst_memory_id: &str,
) -> Vec<serde_json::Value> {
    links
        .iter()
        .filter(|link| {
            (link.src_memory_id == src_memory_id && link.dst_memory_id == dst_memory_id)
                || (link.src_memory_id == dst_memory_id && link.dst_memory_id == src_memory_id)
        })
        .map(|link| {
            serde_json::json!({
                "linkId": link.id,
                "srcMemoryId": link.src_memory_id,
                "dstMemoryId": link.dst_memory_id,
                "relation": link.relation,
                "directed": link.directed,
                "weight": score_json_value(link.weight),
                "confidence": score_json_value(link.confidence),
                "evidenceCount": link.evidence_count,
                "source": link.source,
                "createdAt": link.created_at,
                "lastReinforcedAt": link.last_reinforced_at,
            })
        })
        .collect()
}

#[cfg(not(feature = "graph"))]
fn graph_feature_disabled_data(command: &'static str) -> serde_json::Value {
    serde_json::json!({
        "schema": GRAPH_ALGORITHM_SCHEMA_V1,
        "command": command,
        "version": env!("CARGO_PKG_VERSION"),
        "status": "graph_feature_disabled",
        "graph": {
            "nodeCount": 0,
            "edgeCount": 0,
            "sourceLinkCount": 0,
        },
        "degraded": [{
            "code": "graph_feature_disabled",
            "severity": "medium",
            "message": "Graph algorithm execution requires the optional graph feature.",
            "repair": "Build or run ee with --features graph."
        }]
    })
}

fn write_graph_surface_data<W>(
    cli: &Cli,
    stdout: &mut W,
    data: serde_json::Value,
) -> ProcessExitCode
where
    W: Write,
{
    match cli.renderer() {
        output::Renderer::Human | output::Renderer::Markdown => {
            write_stdout(stdout, &graph_surface_human_output(&data))
        }
        output::Renderer::Toon => write_stdout(stdout, &(graph_surface_toon_output(&data) + "\n")),
        output::Renderer::Json
        | output::Renderer::Jsonl
        | output::Renderer::Compact
        | output::Renderer::Hook => {
            let json = serde_json::json!({
                "schema": crate::models::RESPONSE_SCHEMA_V1,
                "success": true,
                "data": data,
            });
            write_stdout(stdout, &(json.to_string() + "\n"))
        }
    }
}

fn graph_surface_human_output(data: &serde_json::Value) -> String {
    let command = data["command"].as_str().unwrap_or("graph");
    let status = data["status"].as_str().unwrap_or("unknown");
    let node_count = data["graph"]["nodeCount"].as_u64().unwrap_or(0);
    let edge_count = data["graph"]["edgeCount"].as_u64().unwrap_or(0);
    let mut output =
        format!("{command}: {status}\n\n  Nodes: {node_count}\n  Edges: {edge_count}\n");
    if let Some(scores) = data["scores"].as_array() {
        output.push_str("\nTop scores:\n");
        for score in scores.iter().take(5) {
            output.push_str(&format!(
                "  {}. {} {}\n",
                score["rank"].as_u64().unwrap_or(0),
                score["memoryId"].as_str().unwrap_or("-"),
                score["score"].as_f64().unwrap_or(0.0)
            ));
        }
    }
    if let Some(communities) = data["communities"].as_array() {
        output.push_str(&format!("\nCommunities: {}\n", communities.len()));
    }
    if let Some(path) = data["path"].as_array() {
        output.push_str(&format!("\nPath: {}\n", path.len()));
    }
    if let Some(degraded) = data["degraded"].as_array() {
        for entry in degraded {
            output.push_str(&format!(
                "\nDegraded: {}\nNext: {}\n",
                entry["message"]
                    .as_str()
                    .unwrap_or("graph command degraded"),
                entry["repair"]
                    .as_str()
                    .unwrap_or("rerun with graph support")
            ));
        }
    }
    output
}

fn graph_surface_toon_output(data: &serde_json::Value) -> String {
    format!(
        "schema: {}\nsuccess: true\ndata:\n  command: {}\n  status: {}\n  nodeCount: {}\n  edgeCount: {}",
        crate::models::RESPONSE_SCHEMA_V1,
        data["command"].as_str().unwrap_or("graph"),
        data["status"].as_str().unwrap_or("unknown"),
        data["graph"]["nodeCount"].as_u64().unwrap_or(0),
        data["graph"]["edgeCount"].as_u64().unwrap_or(0),
    )
}

fn handle_graph_centrality_refresh<W, E>(
    cli: &Cli,
    args: &GraphCentralityRefreshArgs,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    let workspace =
        resolve_cli_workspace_path(cli.workspace.as_deref().unwrap_or_else(|| Path::new(".")));

    let database_path = args
        .database
        .clone()
        .unwrap_or_else(|| workspace.join(".ee").join("ee.db"));

    if !database_path.exists() {
        let domain_error = DomainError::Storage {
            message: format!("Database not found at {}", database_path.display()),
            repair: Some("ee init --workspace .".to_string()),
        };
        return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
    }

    let conn = match crate::db::DbConnection::open_file(&database_path) {
        Ok(conn) => conn,
        Err(error) => {
            let domain_error = DomainError::Storage {
                message: format!("Failed to open database: {error}"),
                repair: None,
            };
            return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
        }
    };
    let workspace_id = match resolve_graph_workspace_id(&conn, &workspace, None) {
        Ok(workspace_id) => workspace_id,
        Err(error) => return write_domain_error(&error, cli.wants_json(), stdout, stderr),
    };

    let options = crate::graph::CentralityRefreshOptions {
        dry_run: args.dry_run,
        min_weight: args.min_weight,
        min_confidence: args.min_confidence,
        link_limit: args.link_limit,
    };

    match crate::graph::refresh_graph_snapshot(&conn, &workspace_id, &options) {
        Ok(report) => match cli.renderer() {
            output::Renderer::Human | output::Renderer::Markdown => {
                write_stdout(stdout, &report.human_summary())
            }
            output::Renderer::Toon => write_stdout(stdout, &(report.toon_output() + "\n")),
            output::Renderer::Json
            | output::Renderer::Jsonl
            | output::Renderer::Compact
            | output::Renderer::Hook => {
                let json = serde_json::json!({
                    "schema": crate::graph::CENTRALITY_REFRESH_SCHEMA_V1,
                    "success": true,
                    "data": report.data_json(),
                });
                write_stdout(stdout, &(json.to_string() + "\n"))
            }
        },
        Err(error) => {
            let domain_error = DomainError::Graph {
                message: error.to_string(),
                repair: Some("ee graph centrality-refresh --dry-run".to_string()),
            };
            write_domain_error(&domain_error, cli.wants_json(), stdout, stderr)
        }
    }
}

fn handle_graph_snapshot_refresh<W, E>(
    cli: &Cli,
    args: &GraphSnapshotRefreshArgs,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    let workspace =
        resolve_cli_workspace_path(cli.workspace.as_deref().unwrap_or_else(|| Path::new(".")));

    let database_path = args
        .database
        .clone()
        .unwrap_or_else(|| workspace.join(".ee").join("ee.db"));

    if !database_path.exists() {
        let domain_error = DomainError::Storage {
            message: format!("Database not found at {}", database_path.display()),
            repair: Some("ee init --workspace .".to_string()),
        };
        return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
    }

    let conn = match crate::db::DbConnection::open_file(&database_path) {
        Ok(conn) => conn,
        Err(error) => {
            let domain_error = DomainError::Storage {
                message: format!("Failed to open database: {error}"),
                repair: None,
            };
            return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
        }
    };
    let workspace_id = match resolve_graph_workspace_id(&conn, &workspace, None) {
        Ok(workspace_id) => workspace_id,
        Err(error) => return write_domain_error(&error, cli.wants_json(), stdout, stderr),
    };
    let graph_types = match graph_snapshot_refresh_types(&args.graph) {
        Ok(graph_types) => graph_types,
        Err(message) => {
            let domain_error = DomainError::Usage {
                message,
                repair: Some(
                    "Use --graph=memory_links, causal, revision, rules, contradictions, or all."
                        .to_string(),
                ),
            };
            return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
        }
    };

    let options = crate::graph::CentralityRefreshOptions {
        dry_run: args.dry_run,
        min_weight: args.min_weight,
        min_confidence: args.min_confidence,
        link_limit: args.link_limit,
    };
    let mut reports = Vec::with_capacity(graph_types.len());
    for graph_type in graph_types {
        match crate::graph::refresh_graph_snapshot_by_type(
            &conn,
            &workspace_id,
            graph_type,
            &options,
        ) {
            Ok(report) => reports.push((graph_type, report)),
            Err(error) => {
                let domain_error = DomainError::Graph {
                    message: error.to_string(),
                    repair: Some("ee graph snapshot refresh --dry-run".to_string()),
                };
                return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
            }
        }
    }
    let report = crate::graph::GraphSnapshotRefreshBatchReport {
        workspace_id,
        reports,
    };

    match cli.renderer() {
        output::Renderer::Human | output::Renderer::Markdown => {
            write_stdout(stdout, &report.human_summary())
        }
        output::Renderer::Toon => write_stdout(stdout, &(report.toon_output() + "\n")),
        output::Renderer::Json
        | output::Renderer::Jsonl
        | output::Renderer::Compact
        | output::Renderer::Hook => {
            let json = serde_json::json!({
                "schema": crate::graph::CENTRALITY_REFRESH_SCHEMA_V1,
                "success": true,
                "data": report.data_json(),
            });
            write_stdout(stdout, &(json.to_string() + "\n"))
        }
    }
}

fn graph_snapshot_refresh_types(input: &str) -> Result<Vec<crate::db::GraphSnapshotType>, String> {
    use crate::db::GraphSnapshotType;

    let graph_types = match input {
        "memory_links" => vec![GraphSnapshotType::MemoryLinks],
        "causal" | "causal_evidence" => vec![GraphSnapshotType::CausalEvidence],
        "revision" | "revision_dag" => vec![GraphSnapshotType::RevisionDag],
        "rules" | "rule_provenance" => vec![GraphSnapshotType::RuleProvenance],
        "contradictions" | "contradiction_subgraph" => {
            vec![GraphSnapshotType::ContradictionSubgraph]
        }
        "all" => vec![
            GraphSnapshotType::MemoryLinks,
            GraphSnapshotType::CausalEvidence,
            GraphSnapshotType::RevisionDag,
            GraphSnapshotType::RuleProvenance,
            GraphSnapshotType::ContradictionSubgraph,
        ],
        other => return Err(format!("unknown graph refresh target: {other}")),
    };
    Ok(graph_types)
}

fn handle_graph_centrality_read<W, E>(
    cli: &Cli,
    args: &GraphCentralityArgs,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    if args.limit == 0 {
        let domain_error = DomainError::Usage {
            message: "--limit must be greater than zero".to_string(),
            repair: Some("Use --limit 10 or omit the flag.".to_string()),
        };
        return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
    }

    let workspace =
        resolve_cli_workspace_path(cli.workspace.as_deref().unwrap_or_else(|| Path::new(".")));
    let database_path = args
        .database
        .clone()
        .unwrap_or_else(|| workspace.join(".ee").join("ee.db"));

    if !database_path.exists() {
        let domain_error = DomainError::Storage {
            message: format!("Database not found at {}", database_path.display()),
            repair: Some("ee init --workspace .".to_string()),
        };
        return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
    }

    let conn = match crate::db::DbConnection::open_file(&database_path) {
        Ok(conn) => conn,
        Err(error) => {
            let domain_error = DomainError::Storage {
                message: format!("Failed to open database: {error}"),
                repair: None,
            };
            return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
        }
    };

    let workspace_id = match resolve_graph_workspace_id(&conn, &workspace, None) {
        Ok(workspace_id) => workspace_id,
        Err(domain_error) => {
            return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
        }
    };

    let report = match build_graph_centrality_read_report(&conn, &workspace_id, args) {
        Ok(report) => report,
        Err(domain_error) => {
            return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
        }
    };
    let exit_code = if args.require_fresh
        && report
            .degraded
            .iter()
            .any(|entry| entry.code == "graph_snapshot_stale")
    {
        ProcessExitCode::UnsatisfiedDegradedMode
    } else {
        ProcessExitCode::Success
    };

    match cli.renderer() {
        output::Renderer::Human | output::Renderer::Markdown => {
            write_stdout(stdout, &graph_centrality_read_human_output(&report));
        }
        output::Renderer::Toon => {
            write_stdout(stdout, &(graph_centrality_read_toon_output(&report) + "\n"));
        }
        output::Renderer::Json
        | output::Renderer::Jsonl
        | output::Renderer::Compact
        | output::Renderer::Hook => {
            let json = serde_json::json!({
                "schema": crate::models::RESPONSE_SCHEMA_V1,
                "success": report.degraded.iter().all(|entry| entry.severity != "medium")
                    || report.status == "available",
                "data": report.data_json(),
                "degraded": graph_centrality_read_degraded_json(&report.degraded),
            });
            write_stdout(stdout, &(json.to_string() + "\n"));
        }
    }
    exit_code
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum GraphCentralityReadAlgorithm {
    Pagerank,
    Betweenness,
    Authority,
    HitsHubs,
    HitsAuthorities,
    Unknown,
}

impl GraphCentralityReadAlgorithm {
    fn parse(input: &str) -> Self {
        match input {
            "pagerank" | "page_rank" => Self::Pagerank,
            "betweenness" | "betweenness_centrality" => Self::Betweenness,
            "authority" | "authorities" => Self::Authority,
            "hits-hubs" | "hits_hubs" | "hub" | "hubs" => Self::HitsHubs,
            "hits-authorities" | "hits_authorities" => Self::HitsAuthorities,
            _ => Self::Unknown,
        }
    }

    const fn as_str(self) -> &'static str {
        match self {
            Self::Pagerank => "pagerank",
            Self::Betweenness => "betweenness",
            Self::Authority => "authority",
            Self::HitsHubs => "hits-hubs",
            Self::HitsAuthorities => "hits-authorities",
            Self::Unknown => "unknown",
        }
    }

    const fn available_in_memory_link_snapshot(self) -> bool {
        matches!(self, Self::Pagerank | Self::Betweenness)
    }
}

const GRAPH_CENTRALITY_READ_ALGORITHM_VERSION: &str = "fnx-algorithms@0.1.0";

struct GraphCentralityReadDegradation {
    code: &'static str,
    severity: &'static str,
    message: String,
    repair: String,
}

struct GraphCentralityReadRow {
    rank: usize,
    memory_id: String,
    score: f64,
}

struct GraphCentralityReadSnapshot {
    id: String,
    schema_version: String,
    snapshot_version: u32,
    source_generation: u32,
    status: String,
    content_hash: String,
    node_count: u32,
    edge_count: u32,
    created_at: String,
}

struct GraphCentralityReadReport {
    command: &'static str,
    status: &'static str,
    workspace_id: String,
    algorithm: GraphCentralityReadAlgorithm,
    limit: usize,
    memory_id: Option<String>,
    snapshot: Option<GraphCentralityReadSnapshot>,
    rows: Vec<GraphCentralityReadRow>,
    degraded: Vec<GraphCentralityReadDegradation>,
}

impl GraphCentralityReadReport {
    fn data_json(&self) -> serde_json::Value {
        serde_json::json!({
            "command": self.command,
            "schema": "ee.graph.centrality_read.v1",
            "version": env!("CARGO_PKG_VERSION"),
            "status": self.status,
            "workspaceId": self.workspace_id,
            "graphType": crate::db::GraphSnapshotType::MemoryLinks.as_str(),
            "algorithm": self.algorithm.as_str(),
            "snapshotHash": self.snapshot.as_ref().map(|snapshot| snapshot.content_hash.as_str()),
            "computedAt": self.snapshot.as_ref().map(|snapshot| snapshot.created_at.as_str()),
            "algorithmVersion": GRAPH_CENTRALITY_READ_ALGORITHM_VERSION,
            "limit": self.limit,
            "memoryId": self.memory_id,
            "snapshot": self.snapshot.as_ref().map(graph_centrality_read_snapshot_json),
            "rows": self.rows.iter().map(graph_centrality_read_row_json).collect::<Vec<_>>(),
            "degraded": graph_centrality_read_degraded_json(&self.degraded),
        })
    }
}

fn build_graph_centrality_read_report(
    conn: &crate::db::DbConnection,
    workspace_id: &str,
    args: &GraphCentralityArgs,
) -> Result<GraphCentralityReadReport, DomainError> {
    let algorithm = GraphCentralityReadAlgorithm::parse(args.algorithm.as_str());
    let snapshot = conn
        .get_latest_graph_snapshot(workspace_id, crate::db::GraphSnapshotType::MemoryLinks)
        .map_err(|error| DomainError::Storage {
            message: format!("Failed to query graph snapshot: {error}"),
            repair: Some("ee graph centrality-refresh".to_string()),
        })?;
    let Some(snapshot) = snapshot else {
        return Ok(GraphCentralityReadReport {
            command: "graph centrality",
            status: "scores_unavailable",
            workspace_id: workspace_id.to_string(),
            algorithm,
            limit: args.limit,
            memory_id: args.memory_id.clone(),
            snapshot: None,
            rows: Vec::new(),
            degraded: vec![GraphCentralityReadDegradation {
                code: "graph_snapshot_missing",
                severity: "low",
                message: "No persisted graph snapshot exists for centrality reads.".to_string(),
                repair: "ee graph centrality-refresh".to_string(),
            }],
        });
    };

    let mut degraded = Vec::new();
    if snapshot.status == crate::db::GraphSnapshotStatus::Stale {
        degraded.push(GraphCentralityReadDegradation {
            code: "graph_snapshot_stale",
            severity: "medium",
            message: "Graph snapshot is stale; centrality scores may lag memory links.".to_string(),
            repair: "ee graph centrality-refresh".to_string(),
        });
    }
    if !algorithm.available_in_memory_link_snapshot() {
        degraded.push(GraphCentralityReadDegradation {
            code: "graph_algorithm_unavailable",
            severity: "medium",
            message: format!(
                "Graph centrality algorithm `{}` has no computed scores in the latest memory-link snapshot.",
                args.algorithm
            ),
            repair: format!(
                "ee graph centrality-refresh --algorithm {}",
                args.algorithm
            ),
        });
        return Ok(GraphCentralityReadReport {
            command: "graph centrality",
            status: "algorithm_unavailable",
            workspace_id: workspace_id.to_string(),
            algorithm,
            limit: args.limit,
            memory_id: args.memory_id.clone(),
            snapshot: Some(graph_centrality_read_snapshot(&snapshot)),
            rows: Vec::new(),
            degraded,
        });
    }

    let centrality =
        crate::graph::graph_snapshot_centrality_report(&snapshot).map_err(|error| {
            DomainError::Graph {
                message: error.to_string(),
                repair: Some("ee graph centrality-refresh".to_string()),
            }
        })?;
    let mut rows: Vec<_> = centrality
        .scores
        .iter()
        .filter(|score| {
            args.memory_id
                .as_ref()
                .is_none_or(|memory_id| memory_id == &score.memory_id)
        })
        .map(|score| GraphCentralityReadRow {
            rank: 0,
            memory_id: score.memory_id.clone(),
            score: match algorithm {
                GraphCentralityReadAlgorithm::Pagerank => score.pagerank,
                GraphCentralityReadAlgorithm::Betweenness => score.betweenness,
                _ => 0.0,
            },
        })
        .collect();
    rows.sort_by(|left, right| {
        right
            .score
            .total_cmp(&left.score)
            .then_with(|| left.memory_id.cmp(&right.memory_id))
    });
    rows.truncate(args.limit);
    for (index, row) in rows.iter_mut().enumerate() {
        row.rank = index + 1;
    }

    Ok(GraphCentralityReadReport {
        command: "graph centrality",
        status: "available",
        workspace_id: workspace_id.to_string(),
        algorithm,
        limit: args.limit,
        memory_id: args.memory_id.clone(),
        snapshot: Some(graph_centrality_read_snapshot(&snapshot)),
        rows,
        degraded,
    })
}

fn graph_centrality_read_snapshot(
    snapshot: &crate::db::StoredGraphSnapshot,
) -> GraphCentralityReadSnapshot {
    GraphCentralityReadSnapshot {
        id: snapshot.id.clone(),
        schema_version: snapshot.schema_version.clone(),
        snapshot_version: snapshot.snapshot_version,
        source_generation: snapshot.source_generation,
        status: snapshot.status.as_str().to_string(),
        content_hash: snapshot.content_hash.clone(),
        node_count: snapshot.node_count,
        edge_count: snapshot.edge_count,
        created_at: snapshot.created_at.clone(),
    }
}

fn graph_centrality_read_snapshot_json(
    snapshot: &GraphCentralityReadSnapshot,
) -> serde_json::Value {
    serde_json::json!({
        "id": snapshot.id,
        "schemaVersion": snapshot.schema_version,
        "snapshotVersion": snapshot.snapshot_version,
        "sourceGeneration": snapshot.source_generation,
        "status": snapshot.status,
        "contentHash": snapshot.content_hash,
        "nodeCount": snapshot.node_count,
        "edgeCount": snapshot.edge_count,
        "createdAt": snapshot.created_at,
    })
}

fn graph_centrality_read_row_json(row: &GraphCentralityReadRow) -> serde_json::Value {
    serde_json::json!({
        "rank": row.rank,
        "memoryId": row.memory_id,
        "score": graph_score_json_value(row.score),
    })
}

fn graph_centrality_read_degraded_json(
    degraded: &[GraphCentralityReadDegradation],
) -> Vec<serde_json::Value> {
    aggregate_cli_degraded_json(degraded.iter().map(|entry| {
        DegradationAggregationInput::new(
            "graph_centrality_read",
            entry.code,
            entry.severity,
            entry.message.clone(),
            entry.repair.clone(),
        )
    }))
}

fn graph_hits_degraded_json(
    degraded: &[crate::graph::hits::HitsDegradation],
) -> Vec<serde_json::Value> {
    aggregate_cli_degraded_json(degraded.iter().map(|entry| {
        DegradationAggregationInput::new(
            "hits",
            entry.code.as_str(),
            entry.severity,
            entry.message.as_str(),
            entry.repair.as_deref().unwrap_or_default(),
        )
    }))
}

fn graph_feature_enrichment_data_json(
    report: &crate::graph::GraphFeatureEnrichmentReport,
) -> serde_json::Value {
    let degraded = graph_feature_enrichment_degraded_json(&report.degraded);
    let mut data = report.data_json();
    if let Some(object) = data.as_object_mut() {
        object.insert(
            "degraded".to_string(),
            serde_json::Value::Array(degraded.clone()),
        );
        if let Some(summary) = object
            .get_mut("summary")
            .and_then(serde_json::Value::as_object_mut)
        {
            summary.insert(
                "degradedCount".to_string(),
                serde_json::json!(degraded.len()),
            );
        }
    }
    data
}

fn graph_feature_enrichment_degraded_json(
    degraded: &[crate::graph::GraphFeatureEnrichmentDegradation],
) -> Vec<serde_json::Value> {
    aggregate_cli_degraded_json(degraded.iter().map(|entry| {
        DegradationAggregationInput::new(
            "graph_feature_enrichment",
            entry.code,
            entry.severity,
            entry.message.clone(),
            entry.repair.clone(),
        )
    }))
}

fn graph_export_data_json(report: &crate::graph::GraphExportReport) -> serde_json::Value {
    let mut data = report.data_json();
    if let Some(object) = data.as_object_mut() {
        object.insert(
            "degraded".to_string(),
            serde_json::Value::Array(graph_export_degraded_json(&report.degraded)),
        );
    }
    data
}

fn graph_export_degraded_json(
    degraded: &[crate::graph::GraphExportDegradation],
) -> Vec<serde_json::Value> {
    aggregate_cli_degraded_json(degraded.iter().map(|entry| {
        DegradationAggregationInput::new(
            "graph_export",
            entry.code,
            entry.severity,
            entry.message.clone(),
            entry.repair.clone(),
        )
    }))
}

fn graph_centrality_read_human_output(report: &GraphCentralityReadReport) -> String {
    let mut output = format!(
        "Graph centrality ({})\n\n  Algorithm: {}\n  Rows: {}\n",
        report.status,
        report.algorithm.as_str(),
        report.rows.len()
    );
    if let Some(snapshot) = &report.snapshot {
        output.push_str(&format!(
            "  Snapshot: {} (status {}, generation {})\n",
            snapshot.id, snapshot.status, snapshot.source_generation
        ));
    }
    if !report.rows.is_empty() {
        output.push_str("\nScores:\n");
        for row in &report.rows {
            output.push_str(&format!(
                "  {}. {} ({:.4})\n",
                row.rank, row.memory_id, row.score
            ));
        }
    }
    if !report.degraded.is_empty() {
        output.push_str("\nDegraded:\n");
        for entry in &report.degraded {
            output.push_str(&format!(
                "  - {}: {}\n    Next: {}\n",
                entry.code, entry.message, entry.repair
            ));
        }
    }
    output
}

fn graph_centrality_read_toon_output(report: &GraphCentralityReadReport) -> String {
    format!(
        "schema: ee.response.v1\nsuccess: {}\ndata:\n  command: graph centrality\n  status: {}\n  algorithm: {}\n  rows: {}\n  degradedCount: {}",
        report.status == "available",
        report.status,
        report.algorithm.as_str(),
        report.rows.len(),
        report.degraded.len(),
    )
}

fn handle_graph_feature_enrichment<W, E>(
    cli: &Cli,
    args: &GraphFeatureEnrichmentArgs,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    if matches!(args.max_features, Some(0)) {
        let domain_error = DomainError::Usage {
            message: "--max-features must be greater than zero".to_string(),
            repair: Some("Omit --max-features to use the default cap.".to_string()),
        };
        return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
    }

    if let Some(min_combined_score) = args.min_combined_score {
        if !min_combined_score.is_finite() || !(0.0..=1.0).contains(&min_combined_score) {
            let domain_error = DomainError::Usage {
                message: "--min-combined-score must be a finite value in [0.0, 1.0]".to_string(),
                repair: Some("Use a value like 0.01 or omit the flag.".to_string()),
            };
            return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
        }
    }

    if let Some(max_selection_boost) = args.max_selection_boost {
        if !max_selection_boost.is_finite() || max_selection_boost < 0.0 {
            let domain_error = DomainError::Usage {
                message: "--max-selection-boost must be a finite non-negative value".to_string(),
                repair: Some("Use a value like 0.15 or omit the flag.".to_string()),
            };
            return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
        }
    }

    let workspace =
        resolve_cli_workspace_path(cli.workspace.as_deref().unwrap_or_else(|| Path::new(".")));
    let database_path = args
        .database
        .clone()
        .unwrap_or_else(|| workspace.join(".ee").join("ee.db"));

    if !database_path.exists() {
        let domain_error = DomainError::Storage {
            message: format!("Database not found at {}", database_path.display()),
            repair: Some("ee init --workspace .".to_string()),
        };
        return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
    }

    let conn = match crate::db::DbConnection::open_file(&database_path) {
        Ok(conn) => conn,
        Err(error) => {
            let domain_error = DomainError::Storage {
                message: format!("Failed to open database: {error}"),
                repair: None,
            };
            return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
        }
    };

    let mut enrichment_options = crate::graph::GraphFeatureEnrichmentOptions::default();
    if let Some(max_features) = args.max_features {
        enrichment_options.max_features = max_features;
    }
    if let Some(min_combined_score) = args.min_combined_score {
        enrichment_options.min_combined_score = min_combined_score;
    }
    if let Some(max_selection_boost) = args.max_selection_boost {
        enrichment_options.max_selection_boost = max_selection_boost;
    }

    let report = if args.dry_run {
        match crate::core::singleflight::run_graph_feature_enrichment(
            workspace.to_string_lossy().as_ref(),
            0,
            None,
            "dry_run",
            &enrichment_options,
            || {
                let centrality = crate::graph::CentralityRefreshReport {
                    version: env!("CARGO_PKG_VERSION"),
                    status: crate::graph::CentralityRefreshStatus::DryRun,
                    dry_run: true,
                    node_count: 0,
                    edge_count: 0,
                    projection_ms: 0.0,
                    pagerank_ms: 0.0,
                    betweenness_ms: 0.0,
                    total_ms: 0.0,
                    scores: Vec::new(),
                    top_pagerank: Vec::new(),
                    top_betweenness: Vec::new(),
                };
                crate::graph::enrich_graph_features(&centrality, &enrichment_options)
            },
        ) {
            Ok(run) => run.value,
            Err(error) => graph_feature_enrichment_singleflight_error_report(
                &enrichment_options,
                "dry_run",
                error,
            ),
        }
    } else {
        let workspace_id = match resolve_graph_workspace_id(&conn, &workspace, None) {
            Ok(workspace_id) => workspace_id,
            Err(domain_error) => {
                return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
            }
        };
        let snapshot = match conn
            .get_latest_graph_snapshot(&workspace_id, crate::db::GraphSnapshotType::MemoryLinks)
        {
            Ok(snapshot) => snapshot,
            Err(error) => {
                let domain_error = DomainError::Storage {
                    message: format!("Failed to query graph snapshot: {error}"),
                    repair: Some("ee graph centrality-refresh".to_string()),
                };
                return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
            }
        };
        let workspace_generation = snapshot
            .as_ref()
            .map_or(0, |snapshot| u64::from(snapshot.source_generation));
        let graph_generation = snapshot
            .as_ref()
            .map(|snapshot| u64::from(snapshot.snapshot_version));
        let source_mode = if snapshot.is_some() {
            "graph_snapshot"
        } else {
            "graph_snapshot_missing"
        };
        match crate::core::singleflight::run_graph_feature_enrichment(
            workspace.to_string_lossy().as_ref(),
            workspace_generation,
            graph_generation,
            source_mode,
            &enrichment_options,
            || {
                crate::graph::enrich_graph_features_from_graph_snapshot(
                    snapshot.as_ref(),
                    &workspace_id,
                    crate::db::GraphSnapshotType::MemoryLinks,
                    &enrichment_options,
                )
            },
        ) {
            Ok(run) => run.value,
            Err(error) => graph_feature_enrichment_singleflight_error_report(
                &enrichment_options,
                source_mode,
                error,
            ),
        }
    };

    match cli.renderer() {
        output::Renderer::Human | output::Renderer::Markdown => {
            write_stdout(stdout, &graph_feature_enrichment_human_output(&report))
        }
        output::Renderer::Toon => write_stdout(
            stdout,
            &(graph_feature_enrichment_toon_output(&report) + "\n"),
        ),
        output::Renderer::Json
        | output::Renderer::Jsonl
        | output::Renderer::Compact
        | output::Renderer::Hook => {
            let json = serde_json::json!({
                "schema": crate::models::RESPONSE_SCHEMA_V1,
                "success": true,
                "data": graph_feature_enrichment_data_json(&report),
            });
            write_stdout(stdout, &(json.to_string() + "\n"))
        }
    }
}

fn graph_feature_enrichment_singleflight_error_report(
    options: &crate::graph::GraphFeatureEnrichmentOptions,
    source_mode: &'static str,
    error: crate::core::singleflight::SingleFlightError,
) -> crate::graph::GraphFeatureEnrichmentReport {
    crate::graph::GraphFeatureEnrichmentReport {
        schema: crate::graph::GRAPH_FEATURE_ENRICHMENT_SCHEMA_V1,
        version: env!("CARGO_PKG_VERSION"),
        status: crate::graph::GraphFeatureEnrichmentStatus::ScoresUnavailable,
        source_status: crate::graph::CentralityRefreshStatus::EmptyGraph,
        source: crate::graph::GraphFeatureEnrichmentSource {
            kind: source_mode,
            workspace_id: None,
            graph_type: Some(
                crate::db::GraphSnapshotType::MemoryLinks
                    .as_str()
                    .to_owned(),
            ),
            snapshot: None,
        },
        limited: false,
        max_features: options.max_features,
        max_selection_boost: options.max_selection_boost,
        features: Vec::new(),
        degraded: vec![crate::graph::GraphFeatureEnrichmentDegradation {
            code: error.code(),
            severity: error.severity(),
            message: format!(
                "Single-flight coalescing failed for graph feature enrichment: {error}"
            ),
            repair: error.repair().to_owned(),
        }],
    }
}

fn graph_feature_enrichment_human_output(
    report: &crate::graph::GraphFeatureEnrichmentReport,
) -> String {
    let mut output = format!(
        "Graph feature enrichment ({})\n\n  Source status: {}\n  Feature count: {}\n  Max features: {}\n  Max selection boost: {:.4}\n",
        report.status.as_str(),
        report.source_status.as_str(),
        report.features.len(),
        report.max_features,
        report.max_selection_boost,
    );

    if report.limited {
        output.push_str("  Output was truncated by max feature cap.\n");
    }

    if !report.features.is_empty() {
        output.push_str("\nTop enriched memories:\n");
        for (index, feature) in report.features.iter().take(5).enumerate() {
            output.push_str(&format!(
                "  {}. {} (combined {:.4}, boost {:.4})\n",
                index + 1,
                feature.memory_id,
                feature.combined_score,
                feature.selection_boost,
            ));
        }
    }

    if !report.degraded.is_empty() {
        output.push_str("\nDegraded:\n");
        for entry in &report.degraded {
            output.push_str(&format!(
                "  - {}: {}\n    Next: {}\n",
                entry.code, entry.message, entry.repair
            ));
        }
    }

    output
}

fn graph_feature_enrichment_toon_output(
    report: &crate::graph::GraphFeatureEnrichmentReport,
) -> String {
    format!(
        "schema: {}\nsuccess: true\ndata:\n  command: graph feature-enrichment\n  status: {}\n  sourceStatus: {}\n  featureCount: {}\n  degradedCount: {}\n  maxFeatures: {}\n  limited: {}",
        crate::models::RESPONSE_SCHEMA_V1,
        report.status.as_str(),
        report.source_status.as_str(),
        report.features.len(),
        report.degraded.len(),
        report.max_features,
        report.limited,
    )
}

fn handle_graph_export<W, E>(
    cli: &Cli,
    args: &GraphExportArgs,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    let workspace =
        resolve_cli_workspace_path(cli.workspace.as_deref().unwrap_or_else(|| Path::new(".")));
    let database_path = args
        .database
        .clone()
        .unwrap_or_else(|| workspace.join(".ee").join("ee.db"));

    if !database_path.exists() {
        let domain_error = DomainError::Storage {
            message: format!("Database not found at {}", database_path.display()),
            repair: Some("ee init --workspace .".to_string()),
        };
        return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
    }

    let conn = match crate::db::DbConnection::open_file(&database_path) {
        Ok(conn) => conn,
        Err(error) => {
            let domain_error = DomainError::Storage {
                message: format!("Failed to open database: {error}"),
                repair: None,
            };
            return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
        }
    };
    if let Err(error) = conn.migrate() {
        let domain_error = DomainError::MigrationRequired {
            message: format!("Failed to migrate graph database: {error}"),
            repair: Some("ee db migrate --workspace .".to_string()),
        };
        return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
    }

    let workspace_id = match resolve_graph_export_workspace_id(&conn, &workspace, args) {
        Ok(workspace_id) => workspace_id,
        Err(domain_error) => {
            return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
        }
    };

    let graph_type = match args.graph_type.parse::<crate::db::GraphSnapshotType>() {
        Ok(graph_type) => graph_type,
        Err(error) => {
            let domain_error = DomainError::Usage {
                message: error,
                repair: Some(
                    "Use one of memory_links, session_graph, procedure_graph, evidence_graph, composite."
                        .to_string(),
                ),
            };
            return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
        }
    };

    let options = crate::graph::GraphExportOptions {
        workspace_id,
        graph_type,
        snapshot_id: args.snapshot_id.clone(),
        format: crate::graph::GraphExportFormat::Mermaid,
    };

    match crate::graph::export_graph_snapshot(&conn, &options) {
        Ok(report) => write_graph_export_report(cli, &report, stdout),
        Err(error) => {
            let domain_error = DomainError::Graph {
                message: error.to_string(),
                repair: Some("ee graph centrality-refresh".to_string()),
            };
            write_domain_error(&domain_error, cli.wants_json(), stdout, stderr)
        }
    }
}

fn resolve_cli_workspace_path(path: &Path) -> PathBuf {
    let absolute = if path.is_absolute() {
        path.to_path_buf()
    } else {
        std::env::current_dir()
            .unwrap_or_else(|_| PathBuf::from("."))
            .join(path)
    };
    absolute.canonicalize().unwrap_or(absolute)
}

fn resolve_graph_export_workspace_id(
    conn: &crate::db::DbConnection,
    workspace: &Path,
    args: &GraphExportArgs,
) -> Result<String, DomainError> {
    resolve_graph_workspace_id(conn, workspace, args.workspace_id.as_deref())
}

fn resolve_graph_workspace_id(
    conn: &crate::db::DbConnection,
    workspace: &Path,
    explicit_workspace_id: Option<&str>,
) -> Result<String, DomainError> {
    if let Some(workspace_id) = explicit_workspace_id {
        return Ok(workspace_id.to_owned());
    }
    let workspace_path = workspace.to_string_lossy().into_owned();
    let stored = conn
        .get_workspace_by_path(&workspace_path)
        .map_err(|error| DomainError::Storage {
            message: format!("Failed to query workspace: {error}"),
            repair: Some("ee doctor".to_string()),
        })?;

    Ok(stored.map_or_else(
        || stable_cli_workspace_id(workspace),
        |workspace| workspace.id,
    ))
}

fn stable_cli_workspace_id(path: &Path) -> String {
    let hash = blake3::hash(format!("workspace:{}", path.to_string_lossy()).as_bytes());
    let mut bytes = [0_u8; 16];
    bytes.copy_from_slice(&hash.as_bytes()[..16]);
    crate::models::WorkspaceId::from_uuid(uuid::Uuid::from_bytes(bytes)).to_string()
}

fn write_graph_export_report<W>(
    cli: &Cli,
    report: &crate::graph::GraphExportReport,
    stdout: &mut W,
) -> ProcessExitCode
where
    W: Write,
{
    if cli.format == OutputFormat::Mermaid && !cli.json && !cli.robot {
        return write_stdout(stdout, &report.diagram);
    }

    match cli.renderer() {
        output::Renderer::Human | output::Renderer::Markdown => {
            write_stdout(stdout, &report.human_summary())
        }
        output::Renderer::Toon => write_stdout(stdout, &(graph_export_toon_output(report) + "\n")),
        output::Renderer::Json
        | output::Renderer::Jsonl
        | output::Renderer::Compact
        | output::Renderer::Hook => {
            let json = serde_json::json!({
                "schema": crate::models::RESPONSE_SCHEMA_V1,
                "success": true,
                "data": graph_export_data_json(report),
            });
            write_stdout(stdout, &(json.to_string() + "\n"))
        }
    }
}

fn graph_export_toon_output(report: &crate::graph::GraphExportReport) -> String {
    format!(
        "schema: {}\nsuccess: true\ndata:\n  command: graph export\n  status: {}\n  format: {}\n  workspaceId: {}\n  graphType: {}\n  nodeCount: {}\n  edgeCount: {}",
        crate::models::RESPONSE_SCHEMA_V1,
        report.status.as_str(),
        report.format.as_str(),
        report.workspace_id,
        report.graph_type,
        report.node_count,
        report.edge_count
    )
}

fn handle_graph_neighborhood<W, E>(
    cli: &Cli,
    args: &GraphNeighborhoodArgs,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    let workspace =
        resolve_cli_workspace_path(cli.workspace.as_deref().unwrap_or_else(|| Path::new(".")));
    let database_path = args
        .database
        .clone()
        .unwrap_or_else(|| workspace.join(".ee").join("ee.db"));

    if !database_path.exists() {
        let domain_error = DomainError::Storage {
            message: format!("Database not found at {}", database_path.display()),
            repair: Some("ee init --workspace .".to_string()),
        };
        return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
    }

    let direction = match args.direction.as_str() {
        "incoming" => crate::graph::GraphNeighborhoodDirection::Incoming,
        "outgoing" => crate::graph::GraphNeighborhoodDirection::Outgoing,
        "both" => crate::graph::GraphNeighborhoodDirection::Both,
        other => {
            let domain_error = DomainError::Usage {
                message: format!("Unknown direction filter: {other}"),
                repair: Some("Use one of incoming, outgoing, both.".to_string()),
            };
            return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
        }
    };

    let relation = match args.relation.as_deref() {
        None => None,
        Some(raw) => match crate::db::MemoryLinkRelation::parse(raw) {
            Some(parsed) => Some(parsed),
            None => {
                let domain_error = DomainError::Usage {
                    message: format!("Unknown memory link relation: {raw}"),
                    repair: Some(
                        "Use one of supports, contradicts, derived_from, supersedes, related, co_tag, co_mention."
                            .to_string(),
                    ),
                };
                return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
            }
        },
    };

    if matches!(args.limit, Some(0)) {
        let domain_error = DomainError::Usage {
            message: "--limit must be greater than zero".to_string(),
            repair: Some("Omit --limit to keep all neighbors.".to_string()),
        };
        return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
    }

    let conn = match crate::db::DbConnection::open_file(&database_path) {
        Ok(conn) => conn,
        Err(error) => {
            let domain_error = DomainError::Storage {
                message: format!("Failed to open database: {error}"),
                repair: None,
            };
            return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
        }
    };

    let options = crate::graph::GraphNeighborhoodOptions {
        memory_id: args.memory_id.clone(),
        direction,
        relation,
        limit: args.limit,
    };

    match crate::graph::graph_neighborhood(&conn, &options) {
        Ok(report) => match cli.renderer() {
            output::Renderer::Human | output::Renderer::Markdown => {
                write_stdout(stdout, &report.human_summary())
            }
            output::Renderer::Toon => {
                write_stdout(stdout, &(graph_neighborhood_toon_output(&report) + "\n"))
            }
            output::Renderer::Json
            | output::Renderer::Jsonl
            | output::Renderer::Compact
            | output::Renderer::Hook => {
                let json = serde_json::json!({
                    "schema": crate::graph::GRAPH_NEIGHBORHOOD_SCHEMA_V1,
                    "success": true,
                    "data": report.data_json(),
                });
                write_stdout(stdout, &(json.to_string() + "\n"))
            }
        },
        Err(error) => {
            let domain_error = DomainError::Graph {
                message: error.to_string(),
                repair: Some("ee graph centrality-refresh".to_string()),
            };
            write_domain_error(&domain_error, cli.wants_json(), stdout, stderr)
        }
    }
}

fn graph_neighborhood_toon_output(report: &crate::graph::GraphNeighborhoodReport) -> String {
    let neighbor_count = report
        .nodes
        .iter()
        .filter(|node| node.role == "neighbor")
        .count();
    format!(
        "schema: {}\nsuccess: true\ndata:\n  command: graph neighborhood\n  status: {}\n  memoryId: {}\n  direction: {}\n  edgeCount: {}\n  neighborCount: {}",
        crate::graph::GRAPH_NEIGHBORHOOD_SCHEMA_V1,
        report.status.as_str(),
        report.memory_id,
        report.direction.as_str(),
        report.edges.len(),
        neighbor_count,
    )
}

