fn parse_memory_revise_confidence(raw: Option<&str>) -> Result<Option<f32>, DomainError> {
    match raw {
        Some(value) => match value.parse::<f32>() {
            Ok(parsed) if parsed.is_finite() && (0.0..=1.0).contains(&parsed) => Ok(Some(parsed)),
            _ => Err(DomainError::Usage {
                message: format!(
                    "Invalid confidence `{value}`: expected a finite number from 0.0 to 1.0"
                ),
                repair: Some("Use --confidence 0.8".to_owned()),
            }),
        },
        None => Ok(None),
    }
}

fn parse_memory_revise_tags(raw: &str) -> Vec<String> {
    raw.split(',')
        .map(str::trim)
        .filter(|tag| !tag.is_empty())
        .map(str::to_owned)
        .collect()
}

fn parse_memory_tags_values(values: &[String]) -> Result<Vec<String>, DomainError> {
    let mut tags = BTreeSet::new();
    for value in values {
        for raw in value
            .split(',')
            .map(str::trim)
            .filter(|tag| !tag.is_empty())
        {
            let tag = Tag::parse(raw).map_err(|error| DomainError::Usage {
                message: error.to_string(),
                repair: Some("Use lowercase tag names such as --add release,testing.".to_owned()),
            })?;
            tags.insert(tag.to_string());
        }
    }
    Ok(tags.into_iter().collect())
}

fn parse_memory_tags_value(value: &str) -> Result<Vec<String>, DomainError> {
    parse_memory_tags_values(&[value.to_owned()])
}

fn parse_memory_link_relation(raw: &str) -> Result<crate::db::MemoryLinkRelation, DomainError> {
    crate::db::MemoryLinkRelation::parse(raw).ok_or_else(|| DomainError::Usage {
        message: format!("Unknown memory link relation: {raw}"),
        repair: Some(
            "Use one of supports, contradicts, derived_from, supersedes, related, co_tag, co_mention."
                .to_owned(),
        ),
    })
}

fn parse_memory_link_source(raw: &str) -> Result<crate::db::MemoryLinkSource, DomainError> {
    crate::db::MemoryLinkSource::parse(raw).ok_or_else(|| DomainError::Usage {
        message: format!("Unknown memory link source: {raw}"),
        repair: Some("Use one of agent, auto, import, maintenance, human.".to_owned()),
    })
}

fn parse_memory_link_score(label: &str, raw: &str) -> Result<f32, DomainError> {
    match raw.parse::<f32>() {
        Ok(value) if value.is_finite() && (0.0..=1.0).contains(&value) => Ok(value),
        _ => Err(DomainError::Usage {
            message: format!(
                "Invalid memory link {label}: expected a finite number from 0.0 to 1.0"
            ),
            repair: Some(format!("Use --{label} 0.8.")),
        }),
    }
}

fn memory_link_mode_from_args(args: &MemoryLinkArgs) -> Result<MemoryLinkMode, DomainError> {
    match &args.target_memory_id {
        Some(target_memory_id) => {
            let relation = args.relation.as_deref().ok_or_else(|| DomainError::Usage {
                message: "Creating a memory link requires --relation.".to_owned(),
                repair: Some(
                    "Use ee memory link <source> <target> --relation supports.".to_owned(),
                ),
            })?;
            Ok(MemoryLinkMode::Create {
                target_memory_id: target_memory_id.clone(),
                relation: parse_memory_link_relation(relation)?,
                weight: parse_memory_link_score("weight", &args.weight)?,
                confidence: parse_memory_link_score("confidence", &args.confidence)?,
                directed: !args.undirected,
                evidence_count: args.evidence_count,
                source: parse_memory_link_source(&args.source)?,
                metadata_json: args.metadata.clone(),
            })
        }
        None => Ok(MemoryLinkMode::List {
            relation: args
                .relation
                .as_deref()
                .map(parse_memory_link_relation)
                .transpose()?,
        }),
    }
}

fn memory_tags_mode_from_args(args: &MemoryTagsArgs) -> Result<MemoryTagsMode, DomainError> {
    let patch_requested = !args.add.is_empty() || !args.remove.is_empty();
    let set_requested = args.set.is_some();
    let exclusive_count =
        u8::from(patch_requested) + u8::from(set_requested) + u8::from(args.clear);

    if exclusive_count > 1 {
        return Err(DomainError::Usage {
            message: "Choose only one memory tag mutation mode: --add/--remove, --set, or --clear."
                .to_owned(),
            repair: Some("Use ee memory tags <id> --add release,testing.".to_owned()),
        });
    }

    if patch_requested {
        return Ok(MemoryTagsMode::Patch {
            add: parse_memory_tags_values(&args.add)?,
            remove: parse_memory_tags_values(&args.remove)?,
        });
    }

    if let Some(tags) = &args.set {
        return Ok(MemoryTagsMode::Set(parse_memory_tags_value(tags)?));
    }

    if args.clear {
        return Ok(MemoryTagsMode::Clear);
    }

    Ok(MemoryTagsMode::List)
}

fn memory_revise_error_to_domain(report: &MemoryReviseReport, memory_id: &str) -> DomainError {
    match report.error.as_deref() {
        Some("Memory not found") => DomainError::NotFound {
            resource: "memory".to_string(),
            id: memory_id.to_string(),
            repair: Some("ee memory list".to_string()),
        },
        Some("No changes specified") => DomainError::Usage {
            message: "No memory revision changes were specified.".to_string(),
            repair: Some(
                "Use at least one of --content, --level, --kind, --confidence, --tag, or --provenance-uri."
                    .to_string(),
            ),
        },
        Some("Cannot revise tombstoned memory") => DomainError::PolicyDenied {
            message: "Cannot revise tombstoned memory.".to_string(),
            repair: Some("Use ee memory show --include-tombstoned to inspect it.".to_string()),
        },
        Some(message) if message.starts_with("Memory revision writes are unavailable") => {
            DomainError::PolicyDenied {
                message: message.to_string(),
                repair: Some("Rerun with --dry-run to preview the revision.".to_string()),
            }
        }
        Some(message) => DomainError::Storage {
            message: message.to_string(),
            repair: Some("ee doctor".to_string()),
        },
        None => DomainError::PolicyDenied {
            message: "Memory revision did not complete.".to_string(),
            repair: Some("Rerun with --dry-run to preview the revision.".to_string()),
        },
    }
}

fn parse_context_profile(value: &str) -> Result<ContextPackProfile, String> {
    match value.to_lowercase().as_str() {
        "compact" => Ok(ContextPackProfile::Compact),
        "balanced" => Ok(ContextPackProfile::Balanced),
        "thorough" => Ok(ContextPackProfile::Thorough),
        "submodular" => Ok(ContextPackProfile::Submodular),
        _ => Err(format!(
            "Invalid context profile '{value}'. Expected compact, balanced, thorough, or submodular."
        )),
    }
}

fn resolve_context_output_options(
    pack_profile: PackOutputProfileArg,
    resource_profile: PackResourceProfile,
    no_coverage_fill: Option<bool>,
    no_rendered_text: Option<bool>,
    no_skipped: Option<bool>,
    no_meta: Option<bool>,
    include_non_affecting_degradations: Option<bool>,
) -> ContextPackOutputOptions {
    ContextPackOutputOptions::for_profile(pack_profile.to_core())
        .with_overrides(ContextPackOutputOptionOverrides {
            no_coverage_fill,
            no_rendered_text,
            no_skipped,
            no_meta,
            include_non_affecting_degradations,
        })
        .with_resource_profile(resource_profile)
}

fn parse_pack_resource_profile_arg(value: &str) -> Result<PackResourceProfile, String> {
    value
        .parse::<PackResourceProfile>()
        .map_err(|error| error.to_string())
}

fn parse_operating_profile(value: &str) -> Result<OperatingProfile, String> {
    value
        .parse::<OperatingProfile>()
        .map_err(|error| error.to_string())
}

fn parse_speed_mode_arg(value: &str) -> Result<crate::search::SpeedMode, String> {
    value
        .parse::<crate::search::SpeedMode>()
        .map_err(|error| error.to_string())
}

fn parse_mesh_command_mode_arg(value: &str) -> Result<MeshCommandMode, String> {
    value.parse::<MeshCommandMode>().map_err(|_| {
        format!("Invalid mesh mode '{value}'. Expected off, cache, revisable, or blocking.")
    })
}

fn parse_search_source_mode_arg(value: &str) -> Result<SearchSourceMode, String> {
    match value {
        "lexical_only" => Ok(SearchSourceMode::LexicalOnly),
        "semantic_only" => Ok(SearchSourceMode::SemanticOnly),
        "hybrid" => Ok(SearchSourceMode::Hybrid),
        _ => Err(format!(
            "Invalid source mode '{value}'. Expected lexical_only, semantic_only, or hybrid."
        )),
    }
}

fn parse_memory_scope_arg(value: &str) -> Result<MemoryScope, String> {
    MemoryScope::parse(value).ok_or_else(|| {
        format!(
            "Invalid memory scope '{value}'. Expected self, team, workspace, verified, or swarm."
        )
    })
}

fn parse_rfc3339_arg(value: &str) -> Result<chrono::DateTime<chrono::Utc>, String> {
    chrono::DateTime::parse_from_rfc3339(value)
        .map(|timestamp| timestamp.with_timezone(&chrono::Utc))
        .map_err(|error| format!("Expected RFC3339 timestamp, got {value:?}: {error}"))
}

fn write_context_response<W>(
    renderer: output::Renderer,
    requested_format: OutputFormat,
    response: &ContextResponse,
    redaction: Option<&EffectiveRedactionLevel>,
    render_options: output::ContextJsonRenderOptions,
    stdout: &mut W,
) -> ProcessExitCode
where
    W: Write,
{
    let rendered = match renderer {
        output::Renderer::Human => output::render_context_response_human(response),
        output::Renderer::Toon => match redaction {
            Some(redaction) => {
                let (fields, patterns) = context_redaction_fields_and_patterns(response);
                output::render_toon_from_json(&json_with_redaction_metadata(
                    output::render_context_response_json_with_options(response, render_options),
                    redaction,
                    fields,
                    patterns,
                )) + "\n"
            }
            None => output::render_context_response_toon(response) + "\n",
        },
        output::Renderer::Json => match redaction {
            Some(redaction) => {
                let (fields, patterns) = context_redaction_fields_and_patterns(response);
                json_with_redaction_metadata(
                    output::render_context_response_json_with_options(response, render_options),
                    redaction,
                    fields,
                    patterns,
                ) + "\n"
            }
            None => {
                output::render_context_response_json_with_options(response, render_options) + "\n"
            }
        },
        output::Renderer::Jsonl => output::render_context_response_jsonl(response) + "\n",
        output::Renderer::Compact => output::render_context_response_compact(response) + "\n",
        output::Renderer::Hook => output::render_context_response_hook(response) + "\n",
        output::Renderer::Markdown => {
            if requested_format == OutputFormat::Mermaid {
                output::render_context_response_mermaid(response)
            } else {
                output::render_context_response_markdown(response)
            }
        }
    };
    tracing::debug!(
        target: "ee::format_render",
        event = "format_render",
        format = context_format_name(renderer, requested_format),
        byte_size = rendered.len(),
        hash = response.data.pack.hash.as_deref().unwrap_or("absent"),
        fields_omitted_count = context_format_fields_omitted_count(renderer, requested_format, render_options),
    );
    write_stdout(stdout, &rendered)
}

fn validate_context_stream_request(cli: &Cli, args: &ContextArgs) -> Result<(), DomainError> {
    if !args.stream {
        return Ok(());
    }
    if args.explain_performance {
        return Err(DomainError::Usage {
            message: "`ee context --stream` cannot be combined with --explain-performance."
                .to_string(),
            repair: Some(
                "Use `ee context \"<task>\" --stream --format json` for frames, or omit --stream for the performance report."
                    .to_string(),
            ),
        });
    }
    match cli.context_renderer() {
        output::Renderer::Json | output::Renderer::Jsonl => Ok(()),
        _ => Err(DomainError::Usage {
            message:
                "`ee context --stream` requires --json, --robot, --format json, or --format jsonl."
                    .to_string(),
            repair: Some("Use `ee context \"<task>\" --stream --format json`.".to_string()),
        }),
    }
}

fn write_context_stream_response<W>(
    response: &ContextResponse,
    workspace_path: &Path,
    stdout: &mut W,
) -> Result<ProcessExitCode, String>
where
    W: Write,
{
    let started_at = chrono::Utc::now().to_rfc3339();
    let pack_id = context_stream_pack_id(response);
    let workspace_id = crate::core::workspace::stable_workspace_id(workspace_path);
    let request_id = format!("ctx_stream_{pack_id}");
    let options = output::streaming::ContextStreamFrameOptions::new(
        pack_id,
        workspace_id,
        request_id,
        started_at,
        chrono::Utc::now().to_rfc3339(),
    );
    let frames = output::streaming::context_response_stream_frames(response, options)
        .map_err(|error| error.to_string())?;
    let mut writer = output::streaming::PackStreamWriter::new(stdout);
    for frame in &frames {
        writer
            .write_frame(frame)
            .map_err(|error| error.to_string())?;
    }
    tracing::debug!(
        target: "ee::context_stream",
        event = "context_stream_render",
        frame_count = writer.frames_written(),
        hash = response.data.pack.hash.as_deref().unwrap_or("absent"),
    );
    Ok(ProcessExitCode::Success)
}

fn context_stream_pack_id(response: &ContextResponse) -> String {
    let source = response
        .data
        .pack
        .hash
        .as_deref()
        .unwrap_or("absent")
        .strip_prefix("blake3:")
        .unwrap_or_else(|| response.data.pack.hash.as_deref().unwrap_or("absent"));
    let suffix: String = source
        .chars()
        .filter(|character| character.is_ascii_alphanumeric())
        .take(26)
        .collect();
    if suffix.is_empty() {
        "pack_stream_absent".to_string()
    } else {
        format!("pack_stream_{suffix}")
    }
}

fn context_format_name(renderer: output::Renderer, requested_format: OutputFormat) -> &'static str {
    match (renderer, requested_format) {
        (output::Renderer::Markdown, OutputFormat::Mermaid) => "mermaid",
        _ => renderer.as_str(),
    }
}

fn context_format_fields_omitted_count(
    renderer: output::Renderer,
    requested_format: OutputFormat,
    render_options: output::ContextJsonRenderOptions,
) -> u32 {
    let json_omissions = u32::from(!render_options.include_rendered_text)
        + u32::from(!render_options.include_skipped)
        + u32::from(!render_options.include_meta)
        + u32::from(!render_options.include_verbose_meta);
    match (renderer, requested_format) {
        (output::Renderer::Json, _) | (output::Renderer::Toon, _) => json_omissions,
        (output::Renderer::Jsonl, _) => json_omissions + 8,
        (output::Renderer::Compact, _) => json_omissions + 11,
        (output::Renderer::Hook, _) => json_omissions + 8,
        (output::Renderer::Markdown, OutputFormat::Mermaid) => json_omissions + 10,
        (output::Renderer::Markdown, _) | (output::Renderer::Human, _) => json_omissions + 6,
    }
}

fn context_error_to_domain(error: &ContextPackError) -> DomainError {
    match error {
        ContextPackError::Storage(message) => DomainError::Storage {
            message: message.clone(),
            repair: error.repair_hint().map(str::to_string),
        },
        ContextPackError::Search(search_error) => DomainError::SearchIndex {
            message: search_error.to_string(),
            repair: error.repair_hint().map(str::to_string),
        },
        ContextPackError::Pack(message) => DomainError::Usage {
            message: message.clone(),
            repair: error.repair_hint().map(str::to_string),
        },
        ContextPackError::PolicyDenied(message) => DomainError::PolicyDenied {
            message: message.clone(),
            repair: Some("Use redaction.policy=respect or remove redaction bypass.".to_string()),
        },
    }
}

/// Handle `ee context-show <pack_id>` — retrieve a previously persisted
/// pack by ID and render it. Bead bd-17c65.1.10 (A11).
///
/// Loads the StoredPackRecord + StoredPackItems from the workspace
/// database and renders a compact ee.response.v1 envelope mirroring
/// the canonical pack shape. Persisted packs are immutable artifacts,
/// so the response surface is read-only — no re-computation of
/// scores, no re-walk of memory state. The pack hash returned by the
/// original `ee context` invocation is preserved verbatim so callers
/// can correlate this view back to the audit log.
fn handle_context_show<W, E>(
    cli: &Cli,
    args: &ContextShowArgs,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    let workspace_path = cli.resolve_workspace();
    let database_path = args
        .database
        .clone()
        .unwrap_or_else(|| workspace_path.join(".ee").join("ee.db"));

    if !database_path.exists() {
        let domain_error = DomainError::Storage {
            message: format!("Database not found: {}", database_path.display()),
            repair: Some("ee init --workspace .".to_string()),
        };
        return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
    }

    let conn = match crate::db::DbConnection::open_schema_only(&database_path) {
        Ok(c) => c,
        Err(error) => {
            let domain_error = DomainError::Storage {
                message: format!("Failed to open database: {error}"),
                repair: Some("ee doctor".to_string()),
            };
            return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
        }
    };

    let record = match conn.get_pack_record(&args.pack_id) {
        Ok(Some(record)) => record,
        Ok(None) => {
            let domain_error = DomainError::NotFound {
                resource: "pack".to_owned(),
                id: args.pack_id.clone(),
                repair: Some("ee context <query>  # create a fresh pack".to_owned()),
            };
            return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
        }
        Err(error) => {
            let domain_error = DomainError::Storage {
                message: format!("Failed to query pack: {error}"),
                repair: Some("ee doctor".to_string()),
            };
            return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
        }
    };

    let items = match conn.get_pack_items(&args.pack_id) {
        Ok(items) => items,
        Err(error) => {
            let domain_error = DomainError::Storage {
                message: format!("Failed to query pack items: {error}"),
                repair: Some("ee doctor".to_string()),
            };
            return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
        }
    };

    // Build response. The shape mirrors ee context but uses the
    // persisted record's fields. Pack item provenance is stored as a
    // raw JSON blob in the DB — pass it through verbatim.
    let items_json: Vec<serde_json::Value> = items
        .into_iter()
        .map(|item| {
            let provenance: serde_json::Value =
                serde_json::from_str(&item.provenance_json).unwrap_or(serde_json::Value::Null);
            serde_json::json!({
                "rank": item.rank,
                "memoryId": item.memory_id,
                "section": item.section,
                "estimatedTokens": item.estimated_tokens,
                "scores": {
                    "relevance": item.relevance,
                    "utility": item.utility,
                },
                "why": item.why,
                "diversityKey": item.diversity_key,
                "provenance": provenance,
                "trust": {
                    "class": item.trust_class,
                    "subclass": item.trust_subclass,
                },
            })
        })
        .collect();

    let degraded: serde_json::Value = record
        .degraded_json
        .as_deref()
        .and_then(|s| serde_json::from_str(s).ok())
        .unwrap_or_else(|| serde_json::json!([]));

    let envelope = serde_json::json!({
        "schema": "ee.response.v1",
        "success": true,
        "data": {
            "command": "context show",
            "pack": {
                "id": record.id,
                "workspaceId": record.workspace_id,
                "query": record.query,
                "profile": record.profile,
                "maxTokens": record.max_tokens,
                "usedTokens": record.used_tokens,
                "itemCount": record.item_count,
                "omittedCount": record.omitted_count,
                "hash": record.pack_hash,
                "ledgerHash": record.ledger_hash,
                "createdAt": record.created_at,
                "createdBy": record.created_by,
                "items": items_json,
                "degraded": degraded,
            },
        },
    });

    match cli.renderer() {
        output::Renderer::Json
        | output::Renderer::Jsonl
        | output::Renderer::Compact
        | output::Renderer::Hook => {
            let _ = write_stdout(
                stdout,
                &(serde_json::to_string(&envelope).unwrap_or_default() + "\n"),
            );
        }
        _ => {
            let mut out = String::new();
            out.push_str(&format!(
                "Pack: {}\n  Query: {}\n  Profile: {}\n  Tokens: {}/{}\n  Items: {}\n  Created: {}\n  Hash: {}\n",
                record.id,
                record.query,
                record.profile,
                record.used_tokens,
                record.max_tokens,
                record.item_count,
                record.created_at,
                record.pack_hash,
            ));
            let _ = write_stdout(stdout, &out);
        }
    }
    ProcessExitCode::Success
}

fn handle_context<W, E>(
    cli: &Cli,
    args: &ContextArgs,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    handle_context_with_alias_notice(cli, args, stdout, stderr, true)
}

fn handle_context_with_alias_notice<W, E>(
    cli: &Cli,
    args: &ContextArgs,
    stdout: &mut W,
    stderr: &mut E,
    include_deprecated_alias: bool,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    let profile = match parse_context_profile(&args.profile) {
        Ok(profile) => profile,
        Err(message) => {
            let domain_error = DomainError::Usage {
                message,
                repair: Some("ee context --help".to_string()),
            };
            return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
        }
    };

    let workspace_path = cli.resolve_workspace();
    let database_path_for_pack_dna = args
        .database
        .clone()
        .unwrap_or_else(|| workspace_path.join(".ee").join("ee.db"));
    let output_options = resolve_context_output_options(
        args.pack_profile,
        args.resource_profile,
        args.no_coverage_fill,
        args.no_rendered_text,
        args.no_skipped,
        args.no_meta,
        args.include_non_affecting_degradations,
    );
    let redaction = effective_redaction_level(
        &workspace_path,
        args.redaction,
        crate::config::RedactionDefaultSurface::ContextJson,
        RedactionLevel::Minimal,
    );
    let mut filters = crate::models::QueryFilters::default();
    filters.temporal.as_of = args.as_of;
    if let Err(domain_error) = validate_context_stream_request(cli, args) {
        return write_domain_error(&domain_error, true, stdout, stderr);
    }
    let options = ContextPackOptions {
        workspace_path: workspace_path.clone(),
        database_path: args.database.clone(),
        index_dir: args.index_dir.clone(),
        query: args.query.clone(),
        speed: args.speed,
        profile: Some(profile),
        max_tokens: Some(args.max_tokens),
        candidate_pool: Some(args.candidate_pool),
        max_results: None,
        include_tombstoned: args.include_tombstoned,
        as_of: args.as_of,
        include_expired: args.include_expired,
        include_future: args.include_future,
        include_stale: args.include_stale,
        redaction_level: redaction.level,
        memory_scope: args.memory_scope,
        strict_scope: args.strict_scope,
        ppr_weight: args.ppr_weight,
        pagination: None,
        coordination_snapshot_path: args.coordination_snapshot.clone(),
        coordination_stale_after_ms: args.coordination_stale_after_ms,
        filters,
        output_options,
    };

    if args.explain_performance {
        return match run_context_pack_with_performance(&options, "context") {
            Ok(run) => write_stdout(stdout, &(run.performance.to_string() + "\n")),
            Err(error) => {
                let domain_error = context_error_to_domain(&error);
                write_domain_error(&domain_error, true, stdout, stderr)
            }
        };
    }

    match run_context_pack(&options) {
        Ok(mut response) => {
            if args.explain && !args.no_pack_dna {
                attach_pack_dna_to_context_response(&database_path_for_pack_dna, &mut response);
            }
            if include_deprecated_alias {
                response
                    .data
                    .degraded
                    .push(deprecated_context_alias_degradation());
            }
            if args.stream {
                return match write_context_stream_response(&response, &workspace_path, stdout) {
                    Ok(exit) => exit,
                    Err(error) => {
                        let domain_error = DomainError::Usage {
                            message: format!("Failed to render context stream: {error}"),
                            repair: Some(
                                "Retry without --stream to inspect the batch context response."
                                    .to_string(),
                            ),
                        };
                        write_domain_error(&domain_error, true, stdout, stderr)
                    }
                };
            }
            write_context_response(
                cli.context_renderer(),
                cli.format,
                &response,
                Some(&redaction),
                output::ContextJsonRenderOptions::from(output_options),
                stdout,
            )
        }
        Err(error) => {
            let domain_error = context_error_to_domain(&error);
            write_domain_error(&domain_error, cli.wants_json(), stdout, stderr)
        }
    }
}

fn deprecated_context_alias_degradation() -> ContextResponseDegradation {
    match ContextResponseDegradation::new(
        "deprecated_alias",
        ContextResponseSeverity::Low,
        "`ee context` is a compatibility alias for the promoted triad command.",
        Some("Use `ee pack \"<task>\"`.".to_string()),
    ) {
        Ok(entry) => entry,
        Err(_) => ContextResponseDegradation {
            code: "deprecated_alias".to_string(),
            severity: ContextResponseSeverity::Low,
            message: "`ee context` is a compatibility alias for the promoted triad command."
                .to_string(),
            repair: Some("Use `ee pack \"<task>\"`.".to_string()),
        },
    }
}

