#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum QueryFileErrorCode {
    MalformedJson,
    UnknownVersion,
    EmptyQuery,
    InvalidOperator,
    InvalidFilterValue,
    InvalidTimestamp,
    UnsafePath,
    UnsupportedFeature,
    ZeroBudget,
    MissingFile,
    InvalidFile,
    InvalidCursor,
}

impl QueryFileErrorCode {
    #[must_use]
    pub const fn as_str(self) -> &'static str {
        match self {
            Self::MalformedJson => "ERR_MALFORMED_JSON",
            Self::UnknownVersion => "ERR_UNKNOWN_VERSION",
            Self::EmptyQuery => "ERR_EMPTY_QUERY",
            Self::InvalidOperator => "ERR_INVALID_OPERATOR",
            Self::InvalidFilterValue => "ERR_INVALID_FILTER_VALUE",
            Self::InvalidTimestamp => "ERR_INVALID_TIMESTAMP",
            Self::UnsafePath => "ERR_UNSAFE_PATH",
            Self::UnsupportedFeature => "ERR_UNSUPPORTED_FEATURE",
            Self::ZeroBudget => "ERR_ZERO_BUDGET",
            Self::MissingFile => "ERR_QUERY_FILE_NOT_FOUND",
            Self::InvalidFile => "ERR_INVALID_QUERY_FILE",
            Self::InvalidCursor => "ERR_INVALID_CURSOR",
        }
    }
}

#[derive(Clone, Debug, Eq, PartialEq)]
struct QueryFileError {
    code: QueryFileErrorCode,
    message: String,
    repair: Option<String>,
}

impl QueryFileError {
    fn new(code: QueryFileErrorCode, message: impl Into<String>, repair: Option<String>) -> Self {
        Self {
            code,
            message: message.into(),
            repair,
        }
    }
}

#[derive(Clone, Debug, PartialEq)]
struct QueryFileRequest {
    workspace_path: Option<PathBuf>,
    query: String,
    profile: Option<ContextPackProfile>,
    max_tokens: Option<u32>,
    candidate_pool: Option<u32>,
    max_results: Option<u32>,
    speed: crate::search::SpeedMode,
    renderer: Option<output::Renderer>,
    degraded: Vec<ContextResponseDegradation>,
    filters: crate::models::QueryFilters,
    pagination: crate::models::QueryPagination,
}

#[derive(Clone, Copy, Debug, Default, Eq, PartialEq)]
struct QueryFileBudget {
    max_tokens: Option<u32>,
    candidate_pool: Option<u32>,
    max_results: Option<u32>,
}

type QueryOutputControls = (
    Option<ContextPackProfile>,
    Option<output::Renderer>,
    Vec<ContextResponseDegradation>,
);

fn handle_completion<W>(_cli: &Cli, args: &CompletionArgs, stdout: &mut W) -> ProcessExitCode
where
    W: Write,
{
    let shell: Shell = args.shell.into();
    let mut cmd = Cli::command();
    generate(shell, &mut cmd, "ee", stdout);
    ProcessExitCode::Success
}

fn handle_db_status<W>(cli: &Cli, args: &DbStatusArgs, stdout: &mut W) -> ProcessExitCode
where
    W: Write,
{
    let workspace_path = cli.resolve_workspace();
    let database_path = args
        .database
        .clone()
        .unwrap_or_else(|| workspace_path.join(".ee").join("ee.db"));

    let mut report = DbStatusReport {
        database_path: database_path.display().to_string(),
        exists: database_path.exists(),
        file_size_bytes: None,
        wal_path: None,
        wal_file_exists: None,
        wal_size_bytes: None,
        shm_file_exists: None,
        journal_mode: None,
        page_size_bytes: None,
        page_count: None,
        schema_version: None,
        latest_compiled_schema_version: None,
        needs_migration: None,
        applied_migration_count: None,
        pending_migration_versions: None,
        table_count: None,
        table_row_counts: None,
        error: None,
    };

    let wal_path = wal_sidecar_path(&database_path);
    let shm_path = shm_sidecar_path(&database_path);
    if args.wal {
        report.wal_path = Some(wal_path.display().to_string());
        let wal_present = wal_path.exists();
        report.wal_file_exists = Some(wal_present);
        report.shm_file_exists = Some(shm_path.exists());
        if wal_present {
            report.wal_size_bytes = fs::metadata(&wal_path).ok().map(|m| m.len());
        }
    }

    if !report.exists {
        report.error = Some("Database file not found".to_string());
        return write_db_status_output(cli, &report, stdout);
    }

    if let Ok(meta) = fs::metadata(&database_path) {
        report.file_size_bytes = Some(meta.len());
    }

    let conn = match crate::db::DbConnection::open_schema_only(&database_path) {
        Ok(conn) => conn,
        Err(error) => {
            report.error = Some(format!("Failed to open database: {error}"));
            return write_db_status_output(cli, &report, stdout);
        }
    };

    populate_db_status_from_connection(&conn, args, &mut report);
    write_db_status_output(cli, &report, stdout)
}

fn populate_db_status_from_connection(
    conn: &crate::db::DbConnection,
    args: &DbStatusArgs,
    report: &mut DbStatusReport,
) {
    if let Ok(mode) = conn.journal_mode() {
        report.journal_mode = Some(mode);
    }
    if let Ok(page_size) = conn.page_size() {
        report.page_size_bytes = Some(page_size);
    }
    if let Ok(page_count) = conn.page_count() {
        report.page_count = Some(page_count);
    }
    report.latest_compiled_schema_version = crate::db::MIGRATIONS.last().map(|m| m.version());

    match conn.schema_version() {
        Ok(version) => report.schema_version = version,
        Err(error) => {
            if report.error.is_none() {
                report.error = Some(format!("Failed to read schema version: {error}"));
            }
        }
    }
    match conn.needs_migration() {
        Ok(value) => report.needs_migration = Some(value),
        Err(error) => {
            if report.error.is_none() {
                report.error = Some(format!("Failed to inspect migrations: {error}"));
            }
        }
    }
    if let Ok(applied) = conn.applied_migrations() {
        report.applied_migration_count = Some(applied.len());
    }
    if let Ok(pending) = conn.pending_migrations() {
        report.pending_migration_versions = Some(pending);
    }

    let tables = match conn.list_user_tables() {
        Ok(tables) => tables,
        Err(error) => {
            if report.error.is_none() {
                report.error = Some(format!("Failed to list tables: {error}"));
            }
            return;
        }
    };
    report.table_count = Some(tables.len());

    if args.counts {
        let mut counts: Vec<DbTableRowCount> = Vec::with_capacity(tables.len());
        for table in &tables {
            let entry = match conn.count_table_rows(table) {
                Ok(value) => DbTableRowCount {
                    table: table.clone(),
                    rows: Some(value),
                    error: None,
                },
                Err(error) => DbTableRowCount {
                    table: table.clone(),
                    rows: None,
                    error: Some(error.to_string()),
                },
            };
            counts.push(entry);
        }
        report.table_row_counts = Some(counts);
    }
}

fn write_db_status_output<W: Write>(
    cli: &Cli,
    report: &DbStatusReport,
    stdout: &mut W,
) -> ProcessExitCode {
    let degraded = db_status_degraded(report);
    let migration_pending = db_status_has_pending_migration(report);
    let success = report.error.is_none() && !migration_pending;
    let exit_code = if migration_pending {
        ProcessExitCode::MigrationRequired
    } else {
        ProcessExitCode::Success
    };
    match cli.renderer() {
        output::Renderer::Json
        | output::Renderer::Jsonl
        | output::Renderer::Compact
        | output::Renderer::Hook => {
            let json = serde_json::json!({
                "schema": "ee.response.v1",
                "success": success,
                "data": {
                    "command": "db status",
                    "report": {
                        "databasePath": report.database_path,
                        "exists": report.exists,
                        "fileSizeBytes": report.file_size_bytes,
                        "walPath": report.wal_path,
                        "walFileExists": report.wal_file_exists,
                        "walSizeBytes": report.wal_size_bytes,
                        "shmFileExists": report.shm_file_exists,
                        "journalMode": report.journal_mode,
                        "pageSizeBytes": report.page_size_bytes,
                        "pageCount": report.page_count,
                        "schemaVersion": report.schema_version,
                        "latestCompiledSchemaVersion": report.latest_compiled_schema_version,
                        "needsMigration": report.needs_migration,
                        "appliedMigrationCount": report.applied_migration_count,
                        "pendingMigrationVersions": report.pending_migration_versions,
                        "tableCount": report.table_count,
                        "tableRowCounts": report.table_row_counts,
                        "error": report.error,
                    }
                },
                "degraded": degraded
            });
            let write_exit = write_stdout(
                stdout,
                &(serde_json::to_string(&json).unwrap_or_default() + "\n"),
            );
            if write_exit == ProcessExitCode::Success {
                exit_code
            } else {
                write_exit
            }
        }
        _ => {
            let mut out = String::new();
            out.push_str(&format!("Database: {}\n", report.database_path));
            out.push_str(&format!("Exists: {}\n", report.exists));
            if let Some(size) = report.file_size_bytes {
                out.push_str(&format!("Size: {size} bytes\n"));
            }
            if let Some(version) = report.schema_version {
                out.push_str(&format!("Schema version: {version}\n"));
            }
            if let Some(latest) = report.latest_compiled_schema_version {
                out.push_str(&format!("Latest compiled schema version: {latest}\n"));
            }
            if let Some(needs) = report.needs_migration {
                out.push_str(&format!("Needs migration: {needs}\n"));
            }
            if let Some(applied) = report.applied_migration_count {
                out.push_str(&format!("Applied migrations: {applied}\n"));
            }
            if let Some(pending) = &report.pending_migration_versions {
                if pending.is_empty() {
                    out.push_str("Pending migrations: none\n");
                } else {
                    out.push_str(&format!("Pending migrations: {pending:?}\n"));
                }
            }
            if let Some(mode) = &report.journal_mode {
                out.push_str(&format!("Journal mode: {mode}\n"));
            }
            if let Some(page_size) = report.page_size_bytes {
                out.push_str(&format!("Page size: {page_size} bytes\n"));
            }
            if let Some(page_count) = report.page_count {
                out.push_str(&format!("Page count: {page_count}\n"));
            }
            if let Some(table_count) = report.table_count {
                out.push_str(&format!("Tables: {table_count}\n"));
            }
            if let Some(wal) = report.wal_file_exists {
                out.push_str(&format!("WAL file exists: {wal}\n"));
            }
            if let Some(shm) = report.shm_file_exists {
                out.push_str(&format!("SHM file exists: {shm}\n"));
            }
            if let Some(wal_size) = report.wal_size_bytes {
                out.push_str(&format!("WAL size: {wal_size} bytes\n"));
            }
            if let Some(rows) = &report.table_row_counts {
                out.push_str("Row counts:\n");
                for row in rows {
                    match (row.rows, row.error.as_deref()) {
                        (Some(count), _) => {
                            out.push_str(&format!("  {}: {count}\n", row.table));
                        }
                        (None, Some(err)) => {
                            out.push_str(&format!("  {}: error: {err}\n", row.table));
                        }
                        (None, None) => {
                            out.push_str(&format!("  {}: unknown\n", row.table));
                        }
                    }
                }
            }
            if let Some(ref e) = report.error {
                out.push_str(&format!("Error: {e}\n"));
            }
            if !degraded.is_empty() {
                out.push_str("Degraded:\n");
                for entry in degraded {
                    out.push_str(&format!(
                        "  - {}: {}\n",
                        entry["code"].as_str().unwrap_or("unknown"),
                        entry["message"].as_str().unwrap_or("")
                    ));
                }
            }
            let write_exit = write_stdout(stdout, &out);
            if write_exit == ProcessExitCode::Success {
                exit_code
            } else {
                write_exit
            }
        }
    }
}

fn db_status_has_pending_migration(report: &DbStatusReport) -> bool {
    report.needs_migration == Some(true)
        || report
            .pending_migration_versions
            .as_ref()
            .is_some_and(|versions| !versions.is_empty())
}

fn db_status_degraded(report: &DbStatusReport) -> Vec<serde_json::Value> {
    let mut degraded = Vec::new();
    if db_status_has_pending_migration(report) {
        degraded.push(DegradationAggregationInput::new(
            "db_status",
            "db_migration_pending",
            "medium",
            "Database has pending migrations; db inspection may be incomplete until migrations run.",
            "ee init --workspace .",
        ));
    }
    if report.wal_file_exists == Some(true)
        && (!report.exists || report.shm_file_exists == Some(false))
    {
        degraded.push(DegradationAggregationInput::new(
            "db_status",
            "db_wal_stale",
            "medium",
            "Database WAL sidecar exists without a matching SHM sidecar; WAL state may be stale.",
            "ee init --workspace .",
        ));
    }
    aggregate_cli_degraded_json(degraded)
}

fn db_diagnostic_failure_degraded(
    source: &'static str,
    message: Option<&str>,
) -> Vec<serde_json::Value> {
    let Some(message) = message.map(str::trim).filter(|message| !message.is_empty()) else {
        return Vec::new();
    };
    let (code, severity, repair) = if message.contains("not found")
        || message.contains("Failed to open database")
    {
        (
            "storage_unavailable",
            "high",
            "Run `ee db status --json` to confirm the database path, then run `ee init --workspace .` if the workspace is not initialized.",
        )
    } else {
        (
            "storage_degraded",
            "medium",
            "Run `ee db check --full --json` and inspect the report before relying on derived database diagnostics.",
        )
    };
    aggregate_cli_degraded_json([DegradationAggregationInput::new(
        source, code, severity, message, repair,
    )])
}

#[derive(Debug, serde::Serialize)]
struct DbStatusReport {
    database_path: String,
    exists: bool,
    file_size_bytes: Option<u64>,
    wal_path: Option<String>,
    wal_file_exists: Option<bool>,
    wal_size_bytes: Option<u64>,
    shm_file_exists: Option<bool>,
    journal_mode: Option<String>,
    page_size_bytes: Option<u32>,
    page_count: Option<u64>,
    schema_version: Option<u32>,
    latest_compiled_schema_version: Option<u32>,
    needs_migration: Option<bool>,
    applied_migration_count: Option<usize>,
    pending_migration_versions: Option<Vec<u32>>,
    table_count: Option<usize>,
    table_row_counts: Option<Vec<DbTableRowCount>>,
    error: Option<String>,
}

#[derive(Debug, serde::Serialize)]
struct DbTableRowCount {
    table: String,
    rows: Option<i64>,
    error: Option<String>,
}

fn handle_db_inspect<W>(cli: &Cli, args: &DbInspectArgs, stdout: &mut W) -> ProcessExitCode
where
    W: Write,
{
    let workspace_path = cli.resolve_workspace();
    let database_path = args
        .database
        .clone()
        .unwrap_or_else(|| workspace_path.join(".ee").join("ee.db"));

    let mut report = DbInspectReport {
        database_path: database_path.display().to_string(),
        table: args.table.clone(),
        exists: database_path.exists(),
        limit: args.limit,
        table_row_count: None,
        returned_row_count: 0,
        available_tables: Vec::new(),
        columns: Vec::new(),
        rows: Vec::new(),
        error: None,
    };

    if !report.exists {
        report.error = Some("Database file not found".to_string());
        return write_db_inspect_output(cli, &report, stdout);
    }

    let conn = match crate::db::DbConnection::open_schema_only(&database_path) {
        Ok(conn) => conn,
        Err(error) => {
            report.error = Some(format!("Failed to open database: {error}"));
            return write_db_inspect_output(cli, &report, stdout);
        }
    };

    let tables = match conn.list_user_tables() {
        Ok(tables) => tables,
        Err(error) => {
            report.error = Some(format!("Failed to list tables: {error}"));
            return write_db_inspect_output(cli, &report, stdout);
        }
    };
    report.available_tables = tables.clone();

    if !tables.iter().any(|table| table == &args.table) || !db_table_name_is_safe(&args.table) {
        report.error = Some(format!(
            "Table '{}' was not found in this database",
            args.table
        ));
        return write_db_inspect_output(cli, &report, stdout);
    }

    report.table_row_count = match conn.count_table_rows(&args.table) {
        Ok(count) => Some(count),
        Err(error) => {
            report.error = Some(format!("Failed to count table rows: {error}"));
            return write_db_inspect_output(cli, &report, stdout);
        }
    };

    let quoted_table = db_quote_identifier(&args.table);
    let column_sql = format!("PRAGMA table_info({quoted_table})");
    let column_rows = match conn.query(&column_sql, &[]) {
        Ok(rows) => rows,
        Err(error) => {
            report.error = Some(format!("Failed to inspect table columns: {error}"));
            return write_db_inspect_output(cli, &report, stdout);
        }
    };
    report.columns = column_rows
        .iter()
        .filter_map(|row| {
            row.get(1)
                .and_then(sqlmodel_core::Value::as_str)
                .map(str::to_owned)
        })
        .collect();

    let selected_columns = report
        .columns
        .iter()
        .map(|column| db_quote_identifier(column))
        .collect::<Vec<_>>()
        .join(", ");
    let rows_sql = format!("SELECT {selected_columns} FROM {quoted_table} LIMIT ?1");
    let rows = match conn.query(
        &rows_sql,
        &[sqlmodel_core::Value::BigInt(i64::from(args.limit))],
    ) {
        Ok(rows) => rows,
        Err(error) => {
            report.error = Some(format!("Failed to read table rows: {error}"));
            return write_db_inspect_output(cli, &report, stdout);
        }
    };

    report.rows = rows.iter().map(db_inspect_row_json).collect();
    report.returned_row_count = report.rows.len();
    write_db_inspect_output(cli, &report, stdout)
}

fn write_db_inspect_output<W: Write>(
    cli: &Cli,
    report: &DbInspectReport,
    stdout: &mut W,
) -> ProcessExitCode {
    let success = report.error.is_none();
    let degraded = db_diagnostic_failure_degraded("db_inspect", report.error.as_deref());
    let exit_code = if success {
        ProcessExitCode::Success
    } else {
        ProcessExitCode::Storage
    };

    match cli.renderer() {
        output::Renderer::Json
        | output::Renderer::Jsonl
        | output::Renderer::Compact
        | output::Renderer::Hook => {
            let json = serde_json::json!({
                "schema": "ee.response.v1",
                "success": success,
                "data": {
                    "command": "db inspect",
                    "report": {
                        "databasePath": report.database_path,
                        "table": report.table,
                        "exists": report.exists,
                        "limit": report.limit,
                        "tableRowCount": report.table_row_count,
                        "returnedRowCount": report.returned_row_count,
                        "availableTables": report.available_tables,
                        "columns": report.columns,
                        "rows": report.rows,
                        "error": report.error,
                    }
                },
                "degraded": degraded
            });
            let _ = write_stdout(
                stdout,
                &(serde_json::to_string(&json).unwrap_or_default() + "\n"),
            );
            exit_code
        }
        _ => {
            let mut out = String::new();
            out.push_str(&format!("Database: {}\n", report.database_path));
            out.push_str(&format!("Table: {}\n", report.table));
            out.push_str(&format!("Exists: {}\n", report.exists));
            if let Some(count) = report.table_row_count {
                out.push_str(&format!("Rows: {count}\n"));
            }
            out.push_str(&format!("Returned: {}\n", report.returned_row_count));
            if let Some(error) = &report.error {
                out.push_str(&format!("Error: {error}\n"));
            }
            let _ = write_stdout(stdout, &out);
            exit_code
        }
    }
}

#[derive(Debug, serde::Serialize)]
struct DbInspectReport {
    database_path: String,
    table: String,
    exists: bool,
    limit: u32,
    table_row_count: Option<i64>,
    returned_row_count: usize,
    available_tables: Vec<String>,
    columns: Vec<String>,
    rows: Vec<DbInspectRow>,
    error: Option<String>,
}

#[derive(Debug, serde::Serialize)]
struct DbInspectRow {
    #[serde(rename = "sourceUri")]
    source_uri: Option<String>,
    values: BTreeMap<String, serde_json::Value>,
}

fn db_table_name_is_safe(table: &str) -> bool {
    table
        .chars()
        .next()
        .is_some_and(|c| c.is_ascii_alphabetic() || c == '_')
        && table.chars().all(|c| c.is_ascii_alphanumeric() || c == '_')
}

fn db_quote_identifier(identifier: &str) -> String {
    format!("\"{}\"", identifier.replace('"', "\"\""))
}

fn db_inspect_row_json(row: &sqlmodel_core::Row) -> DbInspectRow {
    let mut values = BTreeMap::new();
    let mut source_uri = None;
    for (column, value) in row.iter() {
        let inspected = if db_inspect_column_is_sensitive(column) {
            serde_json::Value::String("<redacted>".to_string())
        } else {
            db_sql_value_json(value)
        };
        if column == "source_uri" {
            source_uri = value.as_str().map(str::to_owned);
        }
        values.insert(column.to_string(), inspected);
    }

    DbInspectRow { source_uri, values }
}

fn db_inspect_column_is_sensitive(column: &str) -> bool {
    let name = column.to_ascii_lowercase();
    ["secret", "token", "password", "credential", "auth", "key"]
        .iter()
        .any(|needle| name.contains(needle))
}

fn db_sql_value_json(value: &sqlmodel_core::Value) -> serde_json::Value {
    match value {
        sqlmodel_core::Value::Null | sqlmodel_core::Value::Default => serde_json::Value::Null,
        sqlmodel_core::Value::Bool(value) => serde_json::Value::Bool(*value),
        sqlmodel_core::Value::TinyInt(value) => serde_json::json!(*value),
        sqlmodel_core::Value::SmallInt(value) => serde_json::json!(*value),
        sqlmodel_core::Value::Int(value) => serde_json::json!(*value),
        sqlmodel_core::Value::BigInt(value) => serde_json::json!(*value),
        sqlmodel_core::Value::Float(value) => serde_json::json!(*value),
        sqlmodel_core::Value::Double(value) => serde_json::json!(*value),
        sqlmodel_core::Value::Decimal(value) | sqlmodel_core::Value::Text(value) => {
            serde_json::Value::String(value.clone())
        }
        sqlmodel_core::Value::Bytes(value) => serde_json::json!({
            "type": "bytes",
            "hex": db_hex_encode(value),
            "byteLength": value.len(),
        }),
        sqlmodel_core::Value::Date(value) => serde_json::json!(*value),
        sqlmodel_core::Value::Time(value)
        | sqlmodel_core::Value::Timestamp(value)
        | sqlmodel_core::Value::TimestampTz(value) => serde_json::json!(*value),
        sqlmodel_core::Value::Uuid(value) => serde_json::json!({
            "type": "uuidBytes",
            "hex": db_hex_encode(value),
        }),
        sqlmodel_core::Value::Json(value) => value.clone(),
        sqlmodel_core::Value::Array(values) => {
            serde_json::Value::Array(values.iter().map(db_sql_value_json).collect())
        }
    }
}

fn db_hex_encode(bytes: &[u8]) -> String {
    bytes
        .iter()
        .map(|byte| format!("{byte:02x}"))
        .collect::<String>()
}

fn wal_sidecar_path(database_path: &Path) -> PathBuf {
    let mut wal = database_path.as_os_str().to_os_string();
    wal.push("-wal");
    PathBuf::from(wal)
}

fn shm_sidecar_path(database_path: &Path) -> PathBuf {
    let mut shm = database_path.as_os_str().to_os_string();
    shm.push("-shm");
    PathBuf::from(shm)
}

fn handle_db_check<W>(cli: &Cli, args: &DbCheckArgs, stdout: &mut W) -> ProcessExitCode
where
    W: Write,
{
    handle_db_check_named(cli, args, stdout, "db check", args.full)
}

fn handle_db_check_integrity<W>(cli: &Cli, args: &DbCheckArgs, stdout: &mut W) -> ProcessExitCode
where
    W: Write,
{
    handle_db_check_named(cli, args, stdout, "db check-integrity", true)
}

fn handle_db_reindex<W>(cli: &Cli, args: &DbReindexArgs, stdout: &mut W) -> ProcessExitCode
where
    W: Write,
{
    let workspace_path = cli.resolve_workspace();
    let database_path = args
        .database
        .clone()
        .unwrap_or_else(|| workspace_path.join(".ee").join("ee.db"));
    let index_dir = args
        .index_dir
        .clone()
        .unwrap_or_else(|| workspace_path.join(".ee").join("index"));

    let mut report = DbReindexReport {
        database_path: database_path.display().to_string(),
        index_dir: index_dir.display().to_string(),
        dry_run: args.dry_run,
        preview_only: true,
        mutation_allowed: false,
        exists: database_path.exists(),
        index_health: "unknown".to_string(),
        db_generation: None,
        index_generation: None,
        last_rebuild_at: None,
        needs_rebuild: false,
        pending_action_count: 0,
        pending_actions: Vec::new(),
        document_counts: DbReindexDocumentCounts::default(),
        error: None,
    };

    if !report.exists {
        report.error = Some("Database file not found".to_string());
        return write_db_reindex_output(cli, &report, stdout);
    }

    match get_index_status(&IndexStatusOptions {
        workspace_path: workspace_path.clone(),
        database_path: Some(database_path.clone()),
        index_dir: Some(index_dir.clone()),
    }) {
        Ok(status) => {
            report.index_health = status.health.as_str().to_string();
            report.db_generation = status.db_generation;
            report.index_generation = status.index_generation;
            report.last_rebuild_at = status.last_rebuild_at;
            report.needs_rebuild = status.health != crate::core::index::IndexHealth::Ready;
            if report.needs_rebuild {
                report
                    .pending_actions
                    .push(db_reindex_pending_action(status.health));
            }
        }
        Err(error) => {
            report.error = Some(format!("Failed to inspect index status: {error}"));
        }
    }

    if report.error.is_none() {
        match db_reindex_document_counts(&database_path) {
            Ok(counts) => report.document_counts = counts,
            Err(error) => report.error = Some(error),
        }
    }
    if report.error.is_none() && args.dry_run && report.pending_actions.is_empty() {
        report.needs_rebuild = true;
        report.pending_actions.push(db_reindex_pending_action(
            crate::core::index::IndexHealth::Ready,
        ));
    }
    report.pending_action_count = report.pending_actions.len();

    write_db_reindex_output(cli, &report, stdout)
}

fn db_reindex_pending_action(health: crate::core::index::IndexHealth) -> DbReindexPendingAction {
    DbReindexPendingAction {
        kind: "full_rebuild".to_string(),
        reason: match health {
            crate::core::index::IndexHealth::Ready => {
                "dry-run preview of a full derived search index rebuild".to_string()
            }
            crate::core::index::IndexHealth::Stale => {
                "database generation is newer than the derived search index".to_string()
            }
            crate::core::index::IndexHealth::Missing => {
                "derived search index is missing".to_string()
            }
            crate::core::index::IndexHealth::Corrupt => {
                "derived search index metadata is corrupt".to_string()
            }
        },
        command: "ee index rebuild --workspace . --json".to_string(),
        mutation_allowed: false,
        writes_derived_assets: true,
        index_families: vec![
            "frankensearch".to_string(),
            "fts5".to_string(),
            "json".to_string(),
        ],
    }
}

fn db_reindex_document_counts(database_path: &Path) -> Result<DbReindexDocumentCounts, String> {
    let conn = crate::db::DbConnection::open_schema_only(database_path)
        .map_err(|error| format!("Failed to open database: {error}"))?;
    let tables = conn
        .list_user_tables()
        .map_err(|error| format!("Failed to list tables: {error}"))?;
    let count = |table: &str| -> Result<u32, String> {
        if !tables.iter().any(|candidate| candidate == table) {
            return Ok(0);
        }
        let rows = conn
            .count_table_rows(table)
            .map_err(|error| format!("Failed to count {table}: {error}"))?;
        u32::try_from(rows.max(0)).map_err(|_| format!("{table} row count exceeds u32"))
    };
    let memories = count("memories")?;
    let sessions = count("sessions")?;
    let artifacts = count("artifacts")?;
    Ok(DbReindexDocumentCounts {
        memories,
        sessions,
        artifacts,
        total: memories.saturating_add(sessions).saturating_add(artifacts),
    })
}

fn write_db_reindex_output<W: Write>(
    cli: &Cli,
    report: &DbReindexReport,
    stdout: &mut W,
) -> ProcessExitCode {
    let success = report.error.is_none();
    let degraded = db_diagnostic_failure_degraded("db_reindex", report.error.as_deref());
    let exit_code = if success {
        ProcessExitCode::Success
    } else {
        ProcessExitCode::Storage
    };

    match cli.renderer() {
        output::Renderer::Json
        | output::Renderer::Jsonl
        | output::Renderer::Compact
        | output::Renderer::Hook => {
            let json = serde_json::json!({
                "schema": "ee.response.v1",
                "success": success,
                "data": {
                    "command": "db reindex",
                    "report": {
                        "databasePath": report.database_path,
                        "indexDir": report.index_dir,
                        "dryRun": report.dry_run,
                        "previewOnly": report.preview_only,
                        "mutationAllowed": report.mutation_allowed,
                        "exists": report.exists,
                        "indexHealth": report.index_health,
                        "dbGeneration": report.db_generation,
                        "indexGeneration": report.index_generation,
                        "lastRebuildAt": report.last_rebuild_at,
                        "needsRebuild": report.needs_rebuild,
                        "pendingActionCount": report.pending_action_count,
                        "pendingActions": report.pending_actions,
                        "documentCounts": report.document_counts,
                        "error": report.error,
                    }
                },
                "degraded": degraded
            });
            let _ = write_stdout(
                stdout,
                &(serde_json::to_string(&json).unwrap_or_default() + "\n"),
            );
            exit_code
        }
        _ => {
            let mut out = String::new();
            out.push_str("Database reindex preview\n");
            out.push_str(&format!("Database: {}\n", report.database_path));
            out.push_str(&format!("Index directory: {}\n", report.index_dir));
            out.push_str(&format!("Dry run requested: {}\n", report.dry_run));
            out.push_str("Mutation allowed: false\n");
            out.push_str(&format!("Index health: {}\n", report.index_health));
            out.push_str(&format!("Needs rebuild: {}\n", report.needs_rebuild));
            out.push_str(&format!(
                "Documents: {} memories, {} sessions, {} artifacts ({} total)\n",
                report.document_counts.memories,
                report.document_counts.sessions,
                report.document_counts.artifacts,
                report.document_counts.total
            ));
            if !report.pending_actions.is_empty() {
                out.push_str("Pending actions:\n");
                for action in &report.pending_actions {
                    out.push_str(&format!(
                        "  - {}: {} ({})\n",
                        action.kind, action.reason, action.command
                    ));
                }
            }
            if let Some(error) = &report.error {
                out.push_str(&format!("Error: {error}\n"));
            }
            let _ = write_stdout(stdout, &out);
            exit_code
        }
    }
}

#[derive(Debug, serde::Serialize)]
struct DbReindexReport {
    database_path: String,
    index_dir: String,
    dry_run: bool,
    preview_only: bool,
    mutation_allowed: bool,
    exists: bool,
    index_health: String,
    db_generation: Option<u64>,
    index_generation: Option<u64>,
    last_rebuild_at: Option<String>,
    needs_rebuild: bool,
    pending_action_count: usize,
    pending_actions: Vec<DbReindexPendingAction>,
    document_counts: DbReindexDocumentCounts,
    error: Option<String>,
}

#[derive(Debug, Default, serde::Serialize)]
struct DbReindexDocumentCounts {
    memories: u32,
    sessions: u32,
    artifacts: u32,
    total: u32,
}

#[derive(Debug, serde::Serialize)]
struct DbReindexPendingAction {
    kind: String,
    reason: String,
    command: String,
    #[serde(rename = "mutationAllowed")]
    mutation_allowed: bool,
    #[serde(rename = "writesDerivedAssets")]
    writes_derived_assets: bool,
    #[serde(rename = "indexFamilies")]
    index_families: Vec<String>,
}

fn handle_db_check_named<W>(
    cli: &Cli,
    args: &DbCheckArgs,
    stdout: &mut W,
    command_name: &'static str,
    full: bool,
) -> ProcessExitCode
where
    W: Write,
{
    let workspace_path = cli.resolve_workspace();
    let database_path = args
        .database
        .clone()
        .unwrap_or_else(|| workspace_path.join(".ee").join("ee.db"));

    let check_type = if full {
        "integrity_check"
    } else {
        "quick_check"
    };
    let records_audit = command_name == "db check-integrity";

    if !database_path.exists() {
        let report = DbCheckReport {
            database_path: database_path.display().to_string(),
            check_type: check_type.to_string(),
            passed: false,
            integrity_passed: None,
            integrity_issues: None,
            foreign_key_passed: None,
            foreign_key_violations: None,
            audit_recorded: None,
            audit_action: None,
            audit_error: None,
            message: "Database file not found".to_string(),
        };
        return write_db_check_output(cli, &report, stdout, command_name);
    }

    let conn = match if records_audit {
        crate::db::DbConnection::open_file(&database_path)
    } else {
        crate::db::DbConnection::open_schema_only(&database_path)
    } {
        Ok(conn) => conn,
        Err(error) => {
            let report = DbCheckReport {
                database_path: database_path.display().to_string(),
                check_type: check_type.to_string(),
                passed: false,
                integrity_passed: None,
                integrity_issues: None,
                foreign_key_passed: None,
                foreign_key_violations: None,
                audit_recorded: None,
                audit_action: None,
                audit_error: None,
                message: format!("Failed to open database: {error}"),
            };
            return write_db_check_output(cli, &report, stdout, command_name);
        }
    };

    let integrity = if full {
        conn.check_integrity()
    } else {
        conn.quick_check()
    };

    let mut report = DbCheckReport {
        database_path: database_path.display().to_string(),
        check_type: check_type.to_string(),
        passed: false,
        integrity_passed: None,
        integrity_issues: None,
        foreign_key_passed: None,
        foreign_key_violations: None,
        audit_recorded: None,
        audit_action: None,
        audit_error: None,
        message: String::new(),
    };

    let integrity = match integrity {
        Ok(result) => result,
        Err(error) => {
            report.message = format!("Integrity check failed: {error}");
            return write_db_check_output(cli, &report, stdout, command_name);
        }
    };

    report.integrity_passed = Some(integrity.passed);
    if !integrity.issues.is_empty() {
        report.integrity_issues = Some(integrity.issues.clone());
    }

    let mut messages: Vec<String> = Vec::new();

    if full {
        match conn.check_foreign_keys() {
            Ok(fk) => {
                report.foreign_key_passed = Some(fk.passed);
                if !fk.violations.is_empty() {
                    let serialized: Vec<serde_json::Value> = fk
                        .violations
                        .iter()
                        .map(|violation| {
                            serde_json::json!({
                                "table": violation.table,
                                "rowid": violation.rowid,
                                "parent": violation.parent,
                                "fkid": violation.fkid,
                            })
                        })
                        .collect();
                    report.foreign_key_violations = Some(serialized);
                }
            }
            Err(error) => {
                messages.push(format!("foreign key check failed: {error}"));
            }
        }
    }

    let integrity_ok = integrity.passed;
    let fk_ok = report.foreign_key_passed.unwrap_or(true);
    report.passed = integrity_ok && fk_ok && messages.is_empty();

    if integrity_ok {
        messages.insert(0, format!("{check_type} passed"));
    } else {
        let count = integrity.issues.len();
        messages.insert(0, format!("{check_type} found {count} issue(s)"));
    }
    if full && !fk_ok {
        let count = report
            .foreign_key_violations
            .as_ref()
            .map(Vec::len)
            .unwrap_or(0);
        messages.push(format!("foreign key check found {count} violation(s)"));
    }
    report.message = messages.join("; ");

    if records_audit {
        report.audit_action = Some(DB_CHECK_INTEGRITY_AUDIT_ACTION.to_string());
        match insert_db_check_integrity_audit(&conn, &workspace_path, &report) {
            Ok(()) => report.audit_recorded = Some(true),
            Err(error) => {
                report.audit_recorded = Some(false);
                report.audit_error = Some(error);
                report.message.push_str("; audit row insert failed");
                report.passed = false;
            }
        }
    }

    write_db_check_output(cli, &report, stdout, command_name)
}

const DB_CHECK_INTEGRITY_AUDIT_ACTION: &str = "db.check_integrity";

fn insert_db_check_integrity_audit(
    conn: &crate::db::DbConnection,
    workspace_path: &Path,
    report: &DbCheckReport,
) -> Result<(), String> {
    let details = serde_json::json!({
        "command": "db check-integrity",
        "databasePath": report.database_path,
        "checkType": report.check_type,
        "passed": report.passed,
        "integrityPassed": report.integrity_passed,
        "integrityIssueCount": report.integrity_issues.as_ref().map(Vec::len).unwrap_or(0),
        "foreignKeyPassed": report.foreign_key_passed,
        "foreignKeyViolationCount": report
            .foreign_key_violations
            .as_ref()
            .map(Vec::len)
            .unwrap_or(0),
        "message": report.message,
    });
    let details_json = serde_json::to_string(&details)
        .map_err(|error| format!("Failed to serialize audit details: {error}"))?;
    let audit_id = crate::db::generate_audit_id();
    conn.insert_audit(
        &audit_id,
        &crate::db::CreateAuditInput {
            workspace_id: migration_audit_workspace_id(conn, workspace_path),
            actor: Some("ee db check-integrity".to_string()),
            action: DB_CHECK_INTEGRITY_AUDIT_ACTION.to_string(),
            target_type: None,
            target_id: None,
            details: Some(details_json),
        },
    )
    .map_err(|error| format!("Failed to record integrity audit row: {error}"))
}

fn write_db_check_output<W: Write>(
    cli: &Cli,
    report: &DbCheckReport,
    stdout: &mut W,
    command_name: &'static str,
) -> ProcessExitCode {
    let degraded = if report.passed {
        Vec::new()
    } else {
        db_diagnostic_failure_degraded("db_check", Some(report.message.as_str()))
    };
    let exit_code = if report.passed {
        ProcessExitCode::Success
    } else {
        ProcessExitCode::Storage
    };

    match cli.renderer() {
        output::Renderer::Json
        | output::Renderer::Jsonl
        | output::Renderer::Compact
        | output::Renderer::Hook => {
            let json = serde_json::json!({
                "schema": "ee.response.v1",
                "success": report.passed,
                "data": {
                    "command": command_name,
                    "report": {
                        "databasePath": report.database_path,
                        "checkType": report.check_type,
                        "passed": report.passed,
                        "integrityPassed": report.integrity_passed,
                        "integrityIssues": report.integrity_issues,
                        "foreignKeyPassed": report.foreign_key_passed,
                        "foreignKeyViolations": report.foreign_key_violations,
                        "auditRecorded": report.audit_recorded,
                        "auditAction": report.audit_action,
                        "auditError": report.audit_error,
                        "message": report.message,
                    }
                },
                "degraded": degraded
            });
            let _ = write_stdout(
                stdout,
                &(serde_json::to_string(&json).unwrap_or_default() + "\n"),
            );
            exit_code
        }
        _ => {
            let mut out = String::new();
            out.push_str(&format!("Database: {}\n", report.database_path));
            out.push_str(&format!("Check: {}\n", report.check_type));
            out.push_str(&format!("Passed: {}\n", report.passed));
            out.push_str(&format!("Message: {}\n", report.message));
            if let Some(issues) = &report.integrity_issues {
                if !issues.is_empty() {
                    out.push_str("Integrity issues:\n");
                    for issue in issues {
                        out.push_str(&format!("  - {issue}\n"));
                    }
                }
            }
            if let Some(violations) = &report.foreign_key_violations {
                if !violations.is_empty() {
                    out.push_str(&format!(
                        "Foreign key violations: {} entries\n",
                        violations.len()
                    ));
                }
            }
            if let Some(recorded) = report.audit_recorded {
                out.push_str(&format!("Audit recorded: {recorded}\n"));
            }
            if let Some(error) = &report.audit_error {
                out.push_str(&format!("Audit error: {error}\n"));
            }
            let _ = write_stdout(stdout, &out);
            exit_code
        }
    }
}

#[derive(Debug, serde::Serialize)]
struct DbCheckReport {
    database_path: String,
    check_type: String,
    passed: bool,
    integrity_passed: Option<bool>,
    integrity_issues: Option<Vec<String>>,
    foreign_key_passed: Option<bool>,
    foreign_key_violations: Option<Vec<serde_json::Value>>,
    audit_recorded: Option<bool>,
    audit_action: Option<String>,
    audit_error: Option<String>,
    message: String,
}

fn handle_db_migrations<W>(cli: &Cli, args: &DbMigrationsArgs, stdout: &mut W) -> ProcessExitCode
where
    W: Write,
{
    let workspace_path = cli.resolve_workspace();
    let database_path = args
        .database
        .clone()
        .unwrap_or_else(|| workspace_path.join(".ee").join("ee.db"));

    let normalized_filter = args.status.trim().to_ascii_lowercase();
    let filter_kind = match normalized_filter.as_str() {
        "all" | "" => DbMigrationsFilter::All,
        "applied" => DbMigrationsFilter::Applied,
        "pending" => DbMigrationsFilter::Pending,
        other => {
            let report = DbMigrationsReport {
                database_path: database_path.display().to_string(),
                filter: other.to_string(),
                exists: database_path.exists(),
                applied: vec![],
                pending: vec![],
                latest_compiled_schema_version: crate::db::MIGRATIONS.last().map(|m| m.version()),
                schema_version: None,
                needs_migration: None,
                error: Some(format!(
                    "invalid --status value '{other}'; expected 'all', 'applied', or 'pending'"
                )),
            };
            return write_db_migrations_output(cli, &report, stdout, false);
        }
    };

    let mut report = DbMigrationsReport {
        database_path: database_path.display().to_string(),
        filter: normalized_filter.clone(),
        exists: database_path.exists(),
        applied: vec![],
        pending: vec![],
        latest_compiled_schema_version: crate::db::MIGRATIONS.last().map(|m| m.version()),
        schema_version: None,
        needs_migration: None,
        error: None,
    };

    if !report.exists {
        if matches!(
            filter_kind,
            DbMigrationsFilter::All | DbMigrationsFilter::Pending
        ) {
            report.pending = compiled_pending_summaries();
        }
        report.error = Some("Database file not found".to_string());
        return write_db_migrations_output(cli, &report, stdout, false);
    }

    let conn = match crate::db::DbConnection::open_schema_only(&database_path) {
        Ok(conn) => conn,
        Err(error) => {
            report.error = Some(format!("Failed to open database: {error}"));
            return write_db_migrations_output(cli, &report, stdout, false);
        }
    };

    let applied = match conn.applied_migrations() {
        Ok(records) => records,
        Err(error) => {
            report.error = Some(format!("Failed to list applied migrations: {error}"));
            return write_db_migrations_output(cli, &report, stdout, false);
        }
    };

    if matches!(
        filter_kind,
        DbMigrationsFilter::All | DbMigrationsFilter::Applied
    ) {
        let mut entries: Vec<DbAppliedMigration> = applied
            .iter()
            .map(|record| DbAppliedMigration {
                version: record.version(),
                name: record.name().to_string(),
                checksum: record.checksum().to_string(),
                applied_at: record.applied_at().to_string(),
            })
            .collect();
        entries.sort_by_key(|entry| entry.version);
        report.applied = entries;
    }

    if matches!(
        filter_kind,
        DbMigrationsFilter::All | DbMigrationsFilter::Pending
    ) {
        match conn.pending_migrations() {
            Ok(versions) => {
                report.pending = versions
                    .into_iter()
                    .filter_map(compiled_summary_for_version)
                    .collect();
            }
            Err(error) => {
                report.error = Some(format!("Failed to compute pending migrations: {error}"));
            }
        }
    }

    report.schema_version = applied.last().map(|m| m.version());
    let pending_present = !report.pending.is_empty();
    report.needs_migration = Some(
        pending_present
            || (matches!(filter_kind, DbMigrationsFilter::Applied)
                && conn.needs_migration().unwrap_or(false)),
    );

    write_db_migrations_output(cli, &report, stdout, true)
}

// ============================================================================
// `ee migrate` (top-level surface, bead bd-17c65.12.1 / L0 phase 1)
//
// Thin orchestrator over the existing DbConnection migration framework
// (migrate() / needs_migration() / schema_version()). Each handler emits an
// ee.response.v1 envelope and uses the standard exit codes:
//   - Success when up-to-date (status) or applied (run)
//   - DegradedRequired (8) when status reports pending migrations
//   - Storage on DB open / mutation errors
// ============================================================================

fn handle_migrate_status<W, E>(
    cli: &Cli,
    args: &MigrateStatusArgs,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    let workspace_path = cli.resolve_workspace();
    let database_path = args
        .database
        .clone()
        .unwrap_or_else(|| workspace_path.join(".ee").join("ee.db"));

    if !database_path.exists() {
        let domain_error = DomainError::Storage {
            message: format!("Database not found: {}", database_path.display()),
            repair: Some("ee init --workspace .".to_string()),
        };
        return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
    }

    let conn = match crate::db::DbConnection::open_schema_only(&database_path) {
        Ok(conn) => conn,
        Err(error) => {
            let domain_error = DomainError::Storage {
                message: format!("Failed to open database: {error}"),
                repair: Some("ee doctor".to_string()),
            };
            return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
        }
    };

    let schema_version = conn.schema_version().unwrap_or(None);
    let needs_migration = conn.needs_migration().unwrap_or(false);
    let latest_compiled = crate::db::MIGRATIONS.last().map(|m| m.version());
    let pending_count: usize = crate::db::MIGRATIONS
        .iter()
        .filter(|m| !conn.has_migration(m.version()).unwrap_or(true))
        .count();

    let json = serde_json::json!({
        "schema": "ee.response.v1",
        "success": true,
        "data": {
            "command": "migrate status",
            "databasePath": database_path.display().to_string(),
            "schemaVersion": schema_version,
            "latestCompiledSchemaVersion": latest_compiled,
            "needsMigration": needs_migration,
            "pendingCount": pending_count,
            "upToDate": !needs_migration,
        },
        "degraded": []
    });

    match cli.renderer() {
        output::Renderer::Json
        | output::Renderer::Jsonl
        | output::Renderer::Compact
        | output::Renderer::Hook => {
            let _ = write_stdout(
                stdout,
                &(serde_json::to_string(&json).unwrap_or_default() + "\n"),
            );
        }
        _ => {
            let mut out = String::new();
            out.push_str(&format!("Database: {}\n", database_path.display()));
            if let Some(version) = schema_version {
                out.push_str(&format!("Schema version: {version}\n"));
            } else {
                out.push_str("Schema version: <none recorded>\n");
            }
            if let Some(latest) = latest_compiled {
                out.push_str(&format!("Latest compiled schema version: {latest}\n"));
            }
            out.push_str(&format!("Pending migrations: {pending_count}\n"));
            if needs_migration {
                out.push_str("\nWorkspace requires migration. Run:\n");
                out.push_str("  ee migrate run --workspace .\n");
            } else {
                out.push_str("\nWorkspace is up to date.\n");
            }
            let _ = write_stdout(stdout, &out);
        }
    }

    // Exit code 8 (DegradedRequired) when migration is needed so calling
    // scripts/agents can detect the condition without parsing JSON.
    if needs_migration {
        ProcessExitCode::MigrationRequired
    } else {
        ProcessExitCode::Success
    }
}

const POST_MIGRATION_INDEX_REBUILD_STEP_ID: &str = "v0_2_010_index_rebuild";

fn migration_index_rebuild_dry_run_json(pending_count: usize) -> serde_json::Value {
    let required = pending_count > 0;
    serde_json::json!({
        "stepId": POST_MIGRATION_INDEX_REBUILD_STEP_ID,
        "required": required,
        "dryRun": true,
        "status": if required { "planned" } else { "skipped_no_migrations_pending" },
        "reason": if required {
            "pending_migrations_require_derived_search_index_rebuild"
        } else {
            "no_pending_migrations"
        },
    })
}

fn migration_index_rebuild_skipped_json() -> serde_json::Value {
    serde_json::json!({
        "stepId": POST_MIGRATION_INDEX_REBUILD_STEP_ID,
        "required": false,
        "dryRun": false,
        "status": "skipped_no_migrations_applied",
        "reason": "migration_run_applied_no_schema_changes",
    })
}

fn migration_audit_workspace_id(
    conn: &crate::db::DbConnection,
    workspace_path: &Path,
) -> Option<String> {
    let mut candidates = Vec::new();
    if let Ok(canonical) = workspace_path.canonicalize() {
        candidates.push(canonical);
    }
    candidates.push(workspace_path.to_path_buf());

    for candidate in candidates {
        let path = candidate.to_string_lossy();
        if let Ok(Some(workspace)) = conn.get_workspace_by_path(path.as_ref()) {
            return Some(workspace.id);
        }
    }

    conn.list_workspaces()
        .ok()
        .and_then(|workspaces| workspaces.into_iter().next())
        .map(|workspace| workspace.id)
}

fn migration_index_rebuild_audit_details(
    database_path: &Path,
    applied: &[u32],
    schema_version: Option<u32>,
    status: &str,
    report: Option<&IndexRebuildReport>,
    error: Option<&str>,
) -> serde_json::Value {
    let report_json = report.map(|report| {
        serde_json::json!({
            "indexDir": report.index_dir.display().to_string(),
            "memoriesIndexed": report.memories_indexed,
            "sessionsIndexed": report.sessions_indexed,
            "artifactsIndexed": report.artifacts_indexed,
            "documentsTotal": report.documents_total,
            "elapsedMs": report.elapsed_ms,
            "dryRun": report.dry_run,
            "errors": &report.errors,
        })
    });

    serde_json::json!({
        "stepId": POST_MIGRATION_INDEX_REBUILD_STEP_ID,
        "databasePath": database_path.display().to_string(),
        "appliedMigrations": applied,
        "appliedCount": applied.len(),
        "schemaVersion": schema_version,
        "status": status,
        "report": report_json,
        "error": error,
    })
}

struct MigrationIndexRebuildAudit<'a> {
    workspace_path: &'a Path,
    database_path: &'a Path,
    applied: &'a [u32],
    schema_version: Option<u32>,
    status: &'a str,
    report: Option<&'a IndexRebuildReport>,
    error: Option<&'a str>,
}

fn insert_migration_index_rebuild_audit(
    conn: &crate::db::DbConnection,
    audit: MigrationIndexRebuildAudit<'_>,
) -> Result<String, DomainError> {
    let audit_id = crate::db::generate_audit_id();
    let details = migration_index_rebuild_audit_details(
        audit.database_path,
        audit.applied,
        audit.schema_version,
        audit.status,
        audit.report,
        audit.error,
    );
    let details_json =
        serde_json::to_string(&details).map_err(|serialize_error| DomainError::Storage {
            message: format!(
                "Failed to serialize migration index rebuild audit: {serialize_error}"
            ),
            repair: Some("ee doctor".to_string()),
        })?;

    conn.insert_audit(
        &audit_id,
        &crate::db::CreateAuditInput {
            workspace_id: migration_audit_workspace_id(conn, audit.workspace_path),
            actor: Some("ee migrate run".to_string()),
            action: crate::db::audit_actions::MIGRATION_INDEX_REBUILD.to_string(),
            target_type: Some("migration".to_string()),
            target_id: Some(POST_MIGRATION_INDEX_REBUILD_STEP_ID.to_string()),
            details: Some(details_json),
        },
    )
    .map_err(|audit_error| DomainError::Storage {
        message: format!("Failed to audit migration index rebuild: {audit_error}"),
        repair: Some("ee audit verify --json".to_string()),
    })?;

    Ok(audit_id)
}

fn migration_index_rebuild_report_json(
    report: &IndexRebuildReport,
    audit_id: &str,
) -> serde_json::Value {
    serde_json::json!({
        "stepId": POST_MIGRATION_INDEX_REBUILD_STEP_ID,
        "required": true,
        "dryRun": false,
        "status": report.status.as_str(),
        "auditId": audit_id,
        "memoriesIndexed": report.memories_indexed,
        "sessionsIndexed": report.sessions_indexed,
        "artifactsIndexed": report.artifacts_indexed,
        "documentsTotal": report.documents_total,
        "indexDir": report.index_dir.display().to_string(),
        "elapsedMs": report.elapsed_ms,
        "errors": &report.errors,
    })
}

fn run_post_migration_index_rebuild(
    conn: &crate::db::DbConnection,
    workspace_path: &Path,
    database_path: &Path,
    applied: &[u32],
    schema_version: Option<u32>,
) -> Result<serde_json::Value, DomainError> {
    if applied.is_empty() {
        return Ok(migration_index_rebuild_skipped_json());
    }

    let options = IndexRebuildOptions {
        workspace_path: workspace_path.to_path_buf(),
        database_path: Some(database_path.to_path_buf()),
        index_dir: None,
        dry_run: false,
    };

    let report = match rebuild_index(&options) {
        Ok(report) => report,
        Err(error) => {
            let message = error.to_string();
            let audit_result = insert_migration_index_rebuild_audit(
                conn,
                MigrationIndexRebuildAudit {
                    workspace_path,
                    database_path,
                    applied,
                    schema_version,
                    status: "failed",
                    report: None,
                    error: Some(&message),
                },
            );
            match audit_result {
                Ok(audit_id) => {
                    tracing::error!(
                        target: "ee::migration",
                        step_id = POST_MIGRATION_INDEX_REBUILD_STEP_ID,
                        audit_id = %audit_id,
                        error = %message,
                        "post-migration index rebuild failed"
                    );
                }
                Err(audit_error) => {
                    tracing::error!(
                        target: "ee::migration",
                        step_id = POST_MIGRATION_INDEX_REBUILD_STEP_ID,
                        error = %message,
                        audit_error = %audit_error,
                        "post-migration index rebuild failed and audit insertion failed"
                    );
                }
            }
            return Err(DomainError::SearchIndex {
                message: format!("Post-migration index rebuild failed: {message}"),
                repair: error
                    .repair_hint()
                    .map(str::to_string)
                    .or_else(|| Some("ee index rebuild --workspace . --json".to_string())),
            });
        }
    };

    let audit_status = if matches!(
        report.status,
        IndexRebuildStatus::Success | IndexRebuildStatus::NoDocuments
    ) && report.errors.is_empty()
    {
        "completed"
    } else {
        "failed"
    };
    let audit_id = insert_migration_index_rebuild_audit(
        conn,
        MigrationIndexRebuildAudit {
            workspace_path,
            database_path,
            applied,
            schema_version,
            status: audit_status,
            report: Some(&report),
            error: None,
        },
    )?;

    tracing::info!(
        target: "ee::migration",
        step_id = POST_MIGRATION_INDEX_REBUILD_STEP_ID,
        audit_id = %audit_id,
        status = report.status.as_str(),
        applied_count = applied.len(),
        documents_total = report.documents_total,
        memories_indexed = report.memories_indexed,
        index_dir = %report.index_dir.display(),
        "post-migration index rebuild completed"
    );

    if audit_status == "completed" {
        Ok(migration_index_rebuild_report_json(&report, &audit_id))
    } else {
        Err(DomainError::SearchIndex {
            message: format!(
                "Post-migration index rebuild ended with status {}",
                report.status.as_str()
            ),
            repair: Some("ee index rebuild --workspace . --json".to_string()),
        })
    }
}

fn handle_migrate_run<W, E>(
    cli: &Cli,
    args: &MigrateRunArgs,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    let workspace_path = cli.resolve_workspace();
    let database_path = args
        .database
        .clone()
        .unwrap_or_else(|| workspace_path.join(".ee").join("ee.db"));

    if !database_path.exists() {
        let domain_error = DomainError::Storage {
            message: format!("Database not found: {}", database_path.display()),
            repair: Some("ee init --workspace .".to_string()),
        };
        return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
    }

    let conn = match crate::db::DbConnection::open_file(&database_path) {
        Ok(conn) => conn,
        Err(error) => {
            let domain_error = DomainError::Storage {
                message: format!("Failed to open database: {error}"),
                repair: Some("ee doctor".to_string()),
            };
            return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
        }
    };

    let pending_summaries: Vec<serde_json::Value> = crate::db::MIGRATIONS
        .iter()
        .filter(|m| !conn.has_migration(m.version()).unwrap_or(true))
        .map(|m| {
            serde_json::json!({
                "version": m.version(),
                "name": m.name(),
                "checksum": m.checksum(),
            })
        })
        .collect();

    // Dry-run: report what would be applied without mutating.
    if args.dry_run {
        let pending_count = pending_summaries.len();
        let json = serde_json::json!({
            "schema": "ee.response.v1",
            "success": true,
            "data": {
                "command": "migrate run",
                "databasePath": database_path.display().to_string(),
                "dryRun": true,
                "wouldApply": pending_summaries,
                "wouldApplyCount": pending_count,
                "postMigrationIndexRebuild": migration_index_rebuild_dry_run_json(pending_count),
                "schemaVersion": conn.schema_version().unwrap_or(None),
            },
            "degraded": []
        });
        match cli.renderer() {
            output::Renderer::Json
            | output::Renderer::Jsonl
            | output::Renderer::Compact
            | output::Renderer::Hook => {
                let _ = write_stdout(
                    stdout,
                    &(serde_json::to_string(&json).unwrap_or_default() + "\n"),
                );
            }
            _ => {
                let mut out = String::new();
                out.push_str(&format!(
                    "DRY RUN: would apply {} migration(s) to {}\n",
                    pending_count,
                    database_path.display()
                ));
                for m in crate::db::MIGRATIONS
                    .iter()
                    .filter(|m| !conn.has_migration(m.version()).unwrap_or(true))
                {
                    out.push_str(&format!("  v{} {}\n", m.version(), m.name()));
                }
                let _ = write_stdout(stdout, &out);
            }
        }
        return ProcessExitCode::Success;
    }

    let result = match conn.migrate() {
        Ok(result) => result,
        Err(error) => {
            let domain_error = DomainError::Storage {
                message: format!("Migration failed: {error}"),
                repair: Some("ee doctor".to_string()),
            };
            return write_domain_error(&domain_error, cli.wants_json(), stdout, stderr);
        }
    };

    let post_version = conn.schema_version().unwrap_or(None);
    let applied: Vec<u32> = result.applied().to_vec();
    let skipped: Vec<u32> = result.skipped().to_vec();
    let post_migration_index_rebuild = match run_post_migration_index_rebuild(
        &conn,
        &workspace_path,
        &database_path,
        &applied,
        post_version,
    ) {
        Ok(report) => report,
        Err(error) => return write_domain_error(&error, cli.wants_json(), stdout, stderr),
    };
    let post_migration_index_rebuild_status = post_migration_index_rebuild
        .get("status")
        .and_then(serde_json::Value::as_str)
        .unwrap_or("unknown")
        .to_string();
    let applied_count = applied.len();
    let skipped_count = skipped.len();
    let json = serde_json::json!({
        "schema": "ee.response.v1",
        "success": true,
        "data": {
            "command": "migrate run",
            "databasePath": database_path.display().to_string(),
            "dryRun": false,
            "applied": applied.clone(),
            "appliedCount": applied_count,
            "skipped": skipped.clone(),
            "skippedCount": skipped_count,
            "schemaVersion": post_version,
            "postMigrationIndexRebuild": post_migration_index_rebuild.clone(),
            "upToDate": true,
        },
        "degraded": []
    });
    match cli.renderer() {
        output::Renderer::Json
        | output::Renderer::Jsonl
        | output::Renderer::Compact
        | output::Renderer::Hook => {
            let _ = write_stdout(
                stdout,
                &(serde_json::to_string(&json).unwrap_or_default() + "\n"),
            );
        }
        _ => {
            let mut out = String::new();
            out.push_str(&format!(
                "Applied {} migration(s) to {}\n",
                applied_count,
                database_path.display()
            ));
            for version in &applied {
                out.push_str(&format!("  v{}\n", version));
            }
            if !skipped.is_empty() {
                out.push_str(&format!(
                    "Skipped {} already-applied migration(s)\n",
                    skipped_count
                ));
            }
            if let Some(v) = post_version {
                out.push_str(&format!("Workspace is now at schema v{v}.\n"));
            }
            out.push_str(&format!(
                "Post-migration index rebuild: {post_migration_index_rebuild_status}\n"
            ));
            let _ = write_stdout(stdout, &out);
        }
    }

    ProcessExitCode::Success
}

fn compiled_pending_summaries() -> Vec<DbPendingMigration> {
    crate::db::MIGRATIONS
        .iter()
        .map(|m| DbPendingMigration {
            version: m.version(),
            name: m.name().to_string(),
            checksum: m.checksum(),
        })
        .collect()
}

fn compiled_summary_for_version(version: u32) -> Option<DbPendingMigration> {
    crate::db::MIGRATIONS
        .iter()
        .find(|m| m.version() == version)
        .map(|m| DbPendingMigration {
            version: m.version(),
            name: m.name().to_string(),
            checksum: m.checksum(),
        })
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum DbMigrationsFilter {
    All,
    Applied,
    Pending,
}

fn write_db_migrations_output<W: Write>(
    cli: &Cli,
    report: &DbMigrationsReport,
    stdout: &mut W,
    db_open_succeeded: bool,
) -> ProcessExitCode {
    let success = db_open_succeeded && report.error.is_none();
    let exit_code = if success {
        ProcessExitCode::Success
    } else {
        ProcessExitCode::Storage
    };

    match cli.renderer() {
        output::Renderer::Json
        | output::Renderer::Jsonl
        | output::Renderer::Compact
        | output::Renderer::Hook => {
            let applied: Vec<serde_json::Value> = report
                .applied
                .iter()
                .map(|m| {
                    serde_json::json!({
                        "version": m.version,
                        "name": m.name,
                        "checksum": m.checksum,
                        "appliedAt": m.applied_at,
                    })
                })
                .collect();
            let pending: Vec<serde_json::Value> = report
                .pending
                .iter()
                .map(|m| {
                    serde_json::json!({
                        "version": m.version,
                        "name": m.name,
                        "checksum": m.checksum,
                    })
                })
                .collect();
            let json = serde_json::json!({
                "schema": "ee.response.v1",
                "success": success,
                "data": {
                    "command": "db migrations",
                    "report": {
                        "databasePath": report.database_path,
                        "filter": report.filter,
                        "exists": report.exists,
                        "schemaVersion": report.schema_version,
                        "latestCompiledSchemaVersion": report.latest_compiled_schema_version,
                        "needsMigration": report.needs_migration,
                        "applied": applied,
                        "pending": pending,
                        "error": report.error,
                    }
                },
                "degraded": []
            });
            let _ = write_stdout(
                stdout,
                &(serde_json::to_string(&json).unwrap_or_default() + "\n"),
            );
            exit_code
        }
        _ => {
            let mut out = String::new();
            out.push_str(&format!("Database: {}\n", report.database_path));
            out.push_str(&format!("Filter: {}\n", report.filter));
            out.push_str(&format!("Exists: {}\n", report.exists));
            if let Some(version) = report.schema_version {
                out.push_str(&format!("Schema version: {version}\n"));
            }
            if let Some(latest) = report.latest_compiled_schema_version {
                out.push_str(&format!("Latest compiled schema version: {latest}\n"));
            }
            if let Some(needs) = report.needs_migration {
                out.push_str(&format!("Needs migration: {needs}\n"));
            }
            if !report.applied.is_empty() {
                out.push_str(&format!("Applied ({}):\n", report.applied.len()));
                for m in &report.applied {
                    out.push_str(&format!(
                        "  v{} {} (applied {})\n",
                        m.version, m.name, m.applied_at
                    ));
                }
            }
            if !report.pending.is_empty() {
                out.push_str(&format!("Pending ({}):\n", report.pending.len()));
                for m in &report.pending {
                    out.push_str(&format!("  v{} {}\n", m.version, m.name));
                }
            }
            if let Some(ref e) = report.error {
                out.push_str(&format!("Error: {e}\n"));
            }
            let _ = write_stdout(stdout, &out);
            exit_code
        }
    }
}

#[derive(Debug, serde::Serialize)]
struct DbMigrationsReport {
    database_path: String,
    filter: String,
    exists: bool,
    applied: Vec<DbAppliedMigration>,
    pending: Vec<DbPendingMigration>,
    schema_version: Option<u32>,
    latest_compiled_schema_version: Option<u32>,
    needs_migration: Option<bool>,
    error: Option<String>,
}

#[derive(Debug, serde::Serialize)]
struct DbAppliedMigration {
    version: u32,
    name: String,
    checksum: String,
    applied_at: String,
}

#[derive(Debug, serde::Serialize)]
struct DbPendingMigration {
    version: u32,
    name: String,
    checksum: String,
}

fn handle_pack_command<W, E>(
    cli: &Cli,
    args: &PackArgs,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    if let Some(query) = args.query.as_ref() {
        if args.query_file.is_some() {
            let error = DomainError::Usage {
                message: "`ee pack <task>` cannot be combined with --query-file.".to_string(),
                repair: Some("Use either `ee pack \"prepare release\"` or `ee pack --query-file task.eeq.json`.".to_string()),
            };
            return write_domain_error(&error, cli.wants_json(), stdout, stderr);
        }
        let context_args = ContextArgs {
            query: query.clone(),
            max_tokens: args.max_tokens.unwrap_or(4000),
            candidate_pool: args.candidate_pool.unwrap_or(100),
            speed: args.speed.unwrap_or(crate::search::SpeedMode::Default),
            stream: false,
            profile: args
                .profile
                .clone()
                .unwrap_or_else(|| "balanced".to_string()),
            ppr_weight: None,
            pack_profile: args.pack_profile.unwrap_or_default(),
            resource_profile: args.resource_profile.unwrap_or_default(),
            database: args.database.clone(),
            index_dir: args.index_dir.clone(),
            explain_performance: args.explain_performance,
            explain: false,
            no_pack_dna: false,
            no_coverage_fill: args.no_coverage_fill,
            no_rendered_text: args.no_rendered_text,
            no_skipped: args.no_skipped,
            no_meta: args.no_meta,
            redaction: None,
            include_non_affecting_degradations: args.include_non_affecting_degradations,
            include_tombstoned: false,
            as_of: args.as_of,
            include_expired: args.include_expired,
            include_future: args.include_future,
            include_stale: args.include_stale,
            mesh_mode: args.mesh_mode,
            memory_scope: MemoryScope::Swarm,
            strict_scope: false,
            coordination_snapshot: args.coordination_snapshot.clone(),
            coordination_stale_after_ms: args.coordination_stale_after_ms,
        };
        return handle_context_with_alias_notice(cli, &context_args, stdout, stderr, false);
    }

    match &args.command {
        Some(PackCommand::Build(build_args)) => handle_pack(cli, build_args, stdout, stderr),
        Some(PackCommand::Replay(replay_args)) => {
            handle_pack_replay(cli, replay_args, stdout, stderr)
        }
        Some(PackCommand::Diff(diff_args)) => handle_pack_diff(cli, diff_args, stdout, stderr),
        None => match args.legacy_build_args() {
            Ok(build_args) => handle_pack(cli, &build_args, stdout, stderr),
            Err(error) => write_domain_error(&error, cli.wants_json(), stdout, stderr),
        },
    }
}

fn handle_pack<W, E>(
    cli: &Cli,
    args: &PackBuildArgs,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    let mut request = match load_query_file(&args.query_file) {
        Ok(request) => request,
        Err(error) => return write_query_file_error(&error, cli.wants_json(), stdout, stderr),
    };

    let profile = match args.profile.as_deref() {
        Some(profile) => match parse_context_profile(profile) {
            Ok(profile) => Some(profile),
            Err(message) => {
                let error = QueryFileError::new(
                    QueryFileErrorCode::UnsupportedFeature,
                    message,
                    Some("ee pack --help".to_string()),
                );
                return write_query_file_error(&error, cli.wants_json(), stdout, stderr);
            }
        },
        None => request.profile,
    };

    let workspace_path = cli
        .workspace
        .clone()
        .or_else(|| request.workspace_path.take())
        .unwrap_or_else(|| PathBuf::from("."));
    let output_options = resolve_context_output_options(
        args.pack_profile.unwrap_or_default(),
        args.resource_profile.unwrap_or_default(),
        args.no_coverage_fill,
        args.no_rendered_text,
        args.no_skipped,
        args.no_meta,
        args.include_non_affecting_degradations,
    );

    let pagination = if request.pagination.is_empty() {
        None
    } else {
        let query_hash = crate::models::compute_query_shape_hash(&request.query, &request.filters);
        let offset = match &request.pagination.cursor {
            Some(cursor_token) => match crate::models::PaginationCursor::decode(cursor_token) {
                Ok(cursor) => {
                    if cursor.query_hash != query_hash {
                        let error = QueryFileError::new(
                            QueryFileErrorCode::InvalidCursor,
                            "Pagination cursor was generated for a different query shape.",
                            Some(
                                "Remove the cursor to start from the first page, or use the \
                                     same query that generated the cursor."
                                    .to_string(),
                            ),
                        );
                        return write_query_file_error(&error, cli.wants_json(), stdout, stderr);
                    }
                    cursor.offset
                }
                Err(err) => {
                    let error = QueryFileError::new(
                        QueryFileErrorCode::InvalidCursor,
                        format!("Invalid pagination cursor: {err}"),
                        Some(
                            "Remove the cursor to start from the first page, or use a valid \
                                 cursor from a previous response."
                                .to_string(),
                        ),
                    );
                    return write_query_file_error(&error, cli.wants_json(), stdout, stderr);
                }
            },
            None => 0,
        };
        Some(crate::core::context::ContextPagination {
            limit: request.pagination.effective_limit(),
            offset,
            query_hash,
        })
    };

    let mut filters = request.filters;
    if filters.temporal.as_of.is_none() {
        filters.temporal.as_of = args.as_of;
    }

    let options = ContextPackOptions {
        workspace_path,
        database_path: args.database.clone(),
        index_dir: args.index_dir.clone(),
        query: request.query,
        speed: args.speed.unwrap_or(request.speed),
        filters,
        profile,
        max_tokens: args.max_tokens.or(request.max_tokens),
        candidate_pool: args.candidate_pool.or(request.candidate_pool),
        max_results: request.max_results,
        include_tombstoned: false,
        as_of: args.as_of,
        include_expired: args.include_expired,
        include_future: args.include_future,
        include_stale: args.include_stale,
        redaction_level: BackupRedaction::Minimal.to_model(),
        memory_scope: MemoryScope::Swarm,
        strict_scope: false,
        ppr_weight: None,
        pagination,
        coordination_snapshot_path: args.coordination_snapshot.clone(),
        coordination_stale_after_ms: args.coordination_stale_after_ms,
        output_options,
    };
    let renderer = effective_pack_renderer(cli, request.renderer);

    if args.explain_performance {
        return match run_context_pack_with_performance(&options, "pack") {
            Ok(run) => write_stdout(stdout, &(run.performance.to_string() + "\n")),
            Err(error) => {
                let domain_error = context_error_to_domain(&error);
                write_domain_error(&domain_error, true, stdout, stderr)
            }
        };
    }

    match run_context_pack(&options) {
        Ok(mut response) => {
            response.data.degraded.extend(request.degraded);
            write_context_response(
                renderer,
                cli.format,
                &response,
                None,
                output::ContextJsonRenderOptions::from(output_options),
                stdout,
            )
        }
        Err(error) => {
            let domain_error = context_error_to_domain(&error);
            write_domain_error(
                &domain_error,
                cli.wants_json() || matches!(renderer, output::Renderer::Json),
                stdout,
                stderr,
            )
        }
    }
}

/// Schema for pack replay response.
pub const PACK_REPLAY_SCHEMA_V1: &str = "ee.pack.replay.v1";

/// Schema for pack diff response.
pub const PACK_DIFF_SCHEMA_V1: &str = "ee.pack.diff.v1";

const PACK_DIFF_SCORE_EPSILON: f64 = 0.000_001;

type PackLedgerStatus = crate::db::PackLedgerStatus;
type ParsedPackLedger = crate::db::ParsedPackLedger;

#[derive(Clone, Debug, PartialEq)]
struct PackDiffItem {
    memory_id: String,
    rank: Option<u32>,
    section: Option<String>,
    relevance: Option<f64>,
    utility: Option<f64>,
    redaction_classes: Vec<String>,
    trust_class: Option<String>,
    trust_subclass: Option<String>,
    why_hash: Option<String>,
}

fn pack_database_path(cli: &Cli, database: Option<&Path>) -> PathBuf {
    database.map_or_else(
        || {
            cli.workspace
                .clone()
                .unwrap_or_else(|| PathBuf::from("."))
                .join(".ee")
                .join("ee.db")
        },
        Path::to_path_buf,
    )
}

fn open_pack_read_database(
    cli: &Cli,
    database: Option<&Path>,
) -> Result<crate::db::DbConnection, DomainError> {
    let database_path = pack_database_path(cli, database);
    if !database_path.exists() {
        return Err(DomainError::Storage {
            message: format!("Database not found at {}", database_path.display()),
            repair: Some("ee init --workspace .".to_string()),
        });
    }

    crate::db::DbConnection::open_file(&database_path).map_err(|error| DomainError::Storage {
        message: format!(
            "Failed to open database {}: {error}",
            database_path.display()
        ),
        repair: Some("Check the database path or run `ee init --workspace .`.".to_string()),
    })
}

fn load_pack_record(
    connection: &crate::db::DbConnection,
    pack_id: &str,
) -> Result<crate::db::StoredPackRecord, DomainError> {
    connection
        .get_pack_record(pack_id)
        .map_err(|error| DomainError::Storage {
            message: format!("Failed to retrieve pack {pack_id}: {error}"),
            repair: Some("Run `ee doctor --json` to inspect database health.".to_string()),
        })?
        .ok_or_else(|| DomainError::NotFound {
            resource: "pack".to_string(),
            id: pack_id.to_string(),
            repair: Some("Check the pack ID from `ee why <memory-id> --json`.".to_string()),
        })
}

fn load_pack_items(
    connection: &crate::db::DbConnection,
    pack_id: &str,
) -> Result<Vec<crate::db::StoredPackItem>, DomainError> {
    connection
        .get_pack_items(pack_id)
        .map_err(|error| DomainError::Storage {
            message: format!("Failed to retrieve pack {pack_id} items: {error}"),
            repair: Some("Run `ee doctor --json` to inspect database health.".to_string()),
        })
}

fn parse_pack_ledger(record: &crate::db::StoredPackRecord) -> ParsedPackLedger {
    crate::db::parse_stored_pack_ledger(record)
}

fn stored_pack_item_json(item: &crate::db::StoredPackItem) -> serde_json::Value {
    serde_json::json!({
        "memoryId": item.memory_id,
        "rank": item.rank,
        "section": item.section,
        "estimatedTokens": item.estimated_tokens,
        "scores": {
            "relevance": item.relevance,
            "utility": item.utility,
        },
        "why": item.why,
        "diversityKey": item.diversity_key,
        "trustClass": item.trust_class,
        "trustSubclass": item.trust_subclass,
    })
}

fn pack_record_json(
    record: &crate::db::StoredPackRecord,
    ledger: &ParsedPackLedger,
) -> serde_json::Value {
    serde_json::json!({
        "id": record.id,
        "workspaceId": record.workspace_id,
        "query": record.query,
        "profile": record.profile,
        "maxTokens": record.max_tokens,
        "usedTokens": record.used_tokens,
        "itemCount": record.item_count,
        "omittedCount": record.omitted_count,
        "packHash": record.pack_hash,
        "createdAt": record.created_at,
        "createdBy": record.created_by,
        "ledgerHash": record.ledger_hash,
        "ledgerStatus": ledger.status.as_str(),
    })
}

fn ledger_core_array<'a>(
    ledger: &'a serde_json::Value,
    field: &str,
) -> Option<&'a Vec<serde_json::Value>> {
    crate::db::pack_ledger_core_array(ledger, field)
}

fn ledger_degraded_values(parsed: &ParsedPackLedger) -> Vec<serde_json::Value> {
    crate::db::stored_pack_ledger_degraded_values(parsed)
}

fn canonical_json(value: &serde_json::Value) -> String {
    serde_json::to_string(value).unwrap_or_else(|_| value.to_string())
}

fn sorted_unique_strings(values: &serde_json::Value) -> Vec<String> {
    let mut strings = values
        .as_array()
        .map(|items| {
            items
                .iter()
                .filter_map(serde_json::Value::as_str)
                .map(str::to_string)
                .collect::<Vec<_>>()
        })
        .unwrap_or_default();
    strings.sort();
    strings.dedup();
    strings
}

fn optional_u32(value: Option<&serde_json::Value>) -> Option<u32> {
    value
        .and_then(serde_json::Value::as_u64)
        .and_then(|raw| u32::try_from(raw).ok())
}

fn optional_f64(value: Option<&serde_json::Value>) -> Option<f64> {
    value.and_then(serde_json::Value::as_f64)
}

fn optional_string(value: Option<&serde_json::Value>) -> Option<String> {
    value
        .and_then(serde_json::Value::as_str)
        .map(str::to_string)
}

fn diff_item_from_ledger(value: &serde_json::Value) -> Option<PackDiffItem> {
    let memory_id = value.get("memoryId")?.as_str()?.to_string();
    Some(PackDiffItem {
        memory_id,
        rank: optional_u32(value.get("rank")),
        section: optional_string(value.get("section")),
        relevance: optional_f64(value.pointer("/scores/relevance")),
        utility: optional_f64(value.pointer("/scores/utility")),
        redaction_classes: sorted_unique_strings(
            value
                .get("redactionClasses")
                .unwrap_or(&serde_json::Value::Null),
        ),
        trust_class: optional_string(value.get("trustClass")),
        trust_subclass: optional_string(value.get("trustSubclass")),
        why_hash: optional_string(value.pointer("/why/hash")),
    })
}

fn diff_item_from_stored(item: &crate::db::StoredPackItem) -> PackDiffItem {
    PackDiffItem {
        memory_id: item.memory_id.clone(),
        rank: Some(item.rank),
        section: Some(item.section.clone()),
        relevance: Some(f64::from(item.relevance)),
        utility: Some(f64::from(item.utility)),
        redaction_classes: Vec::new(),
        trust_class: Some(item.trust_class.clone()),
        trust_subclass: item.trust_subclass.clone(),
        why_hash: None,
    }
}

fn diff_items_for_pack(
    parsed: &ParsedPackLedger,
    stored_items: &[crate::db::StoredPackItem],
) -> BTreeMap<String, PackDiffItem> {
    if let Some(ledger) = parsed.ledger.as_ref()
        && let Some(items) = ledger_core_array(ledger, "selectedItems")
    {
        return items
            .iter()
            .filter_map(diff_item_from_ledger)
            .map(|item| (item.memory_id.clone(), item))
            .collect();
    }

    stored_items
        .iter()
        .map(diff_item_from_stored)
        .map(|item| (item.memory_id.clone(), item))
        .collect()
}

fn diff_item_json(item: &PackDiffItem) -> serde_json::Value {
    serde_json::json!({
        "memoryId": item.memory_id,
        "rank": item.rank,
        "section": item.section,
        "scores": {
            "relevance": item.relevance,
            "utility": item.utility,
        },
        "redactionClasses": item.redaction_classes,
        "trustClass": item.trust_class,
        "trustSubclass": item.trust_subclass,
        "whyHash": item.why_hash,
    })
}

fn score_delta(new_value: Option<f64>, old_value: Option<f64>) -> Option<f64> {
    match (new_value, old_value) {
        (Some(new_value), Some(old_value)) => Some(new_value - old_value),
        _ => None,
    }
}

fn score_delta_changed(delta: Option<f64>) -> bool {
    delta.is_some_and(|value| value.abs() > PACK_DIFF_SCORE_EPSILON)
}

fn pack_record_request_value(ledger: &ParsedPackLedger, field: &str) -> Option<serde_json::Value> {
    ledger
        .ledger
        .as_ref()
        .and_then(|value| {
            value
                .pointer(&format!("/core/request/{field}"))
                .or_else(|| value.pointer(&format!("/request/{field}")))
        })
        .cloned()
}

fn pack_record_derived_asset(ledger: &ParsedPackLedger, field: &str) -> Option<serde_json::Value> {
    ledger
        .ledger
        .as_ref()
        .and_then(|value| {
            value
                .pointer(&format!("/core/derivedAssets/{field}"))
                .or_else(|| value.pointer(&format!("/derivedAssets/{field}")))
        })
        .cloned()
}

fn set_diff_values(
    left: &[serde_json::Value],
    right: &[serde_json::Value],
) -> Vec<serde_json::Value> {
    let right_keys = right.iter().map(canonical_json).collect::<BTreeSet<_>>();
    left.iter()
        .filter(|value| !right_keys.contains(&canonical_json(value)))
        .cloned()
        .collect()
}

fn collect_pack_diff(
    record_a: &crate::db::StoredPackRecord,
    ledger_a: &ParsedPackLedger,
    items_a: &[crate::db::StoredPackItem],
    record_b: &crate::db::StoredPackRecord,
    ledger_b: &ParsedPackLedger,
    items_b: &[crate::db::StoredPackItem],
) -> serde_json::Value {
    let comparable_a = diff_items_for_pack(ledger_a, items_a);
    let comparable_b = diff_items_for_pack(ledger_b, items_b);
    let ids_a = comparable_a.keys().cloned().collect::<BTreeSet<_>>();
    let ids_b = comparable_b.keys().cloned().collect::<BTreeSet<_>>();

    let added = ids_b
        .difference(&ids_a)
        .filter_map(|memory_id| comparable_b.get(memory_id))
        .map(diff_item_json)
        .collect::<Vec<_>>();
    let removed = ids_a
        .difference(&ids_b)
        .filter_map(|memory_id| comparable_a.get(memory_id))
        .map(diff_item_json)
        .collect::<Vec<_>>();

    let mut changed = Vec::new();
    let mut redaction_changes = Vec::new();
    for memory_id in ids_a.intersection(&ids_b) {
        let Some(old_item) = comparable_a.get(memory_id) else {
            continue;
        };
        let Some(new_item) = comparable_b.get(memory_id) else {
            continue;
        };

        let relevance_delta = score_delta(new_item.relevance, old_item.relevance);
        let utility_delta = score_delta(new_item.utility, old_item.utility);
        let old_rank = old_item.rank.unwrap_or_default();
        let new_rank = new_item.rank.unwrap_or_default();
        let rank_delta = i64::from(new_rank) - i64::from(old_rank);
        let section_changed = old_item.section != new_item.section;
        let trust_changed = old_item.trust_class != new_item.trust_class
            || old_item.trust_subclass != new_item.trust_subclass;
        let why_changed = old_item.why_hash != new_item.why_hash;
        let redaction_changed = old_item.redaction_classes != new_item.redaction_classes;

        if redaction_changed {
            redaction_changes.push(serde_json::json!({
                "memoryId": memory_id,
                "oldClasses": old_item.redaction_classes,
                "newClasses": new_item.redaction_classes,
            }));
        }

        if rank_delta != 0
            || score_delta_changed(relevance_delta)
            || score_delta_changed(utility_delta)
            || section_changed
            || trust_changed
            || why_changed
            || redaction_changed
        {
            changed.push(serde_json::json!({
                "memoryId": memory_id,
                "old": diff_item_json(old_item),
                "new": diff_item_json(new_item),
                "rankDelta": rank_delta,
                "scoreDelta": {
                    "relevance": relevance_delta,
                    "utility": utility_delta,
                },
                "sectionChanged": section_changed,
                "trustChanged": trust_changed,
                "whyChanged": why_changed,
                "redactionChanged": redaction_changed,
            }));
        }
    }

    let degraded_a = ledger_degraded_values(ledger_a);
    let degraded_b = ledger_degraded_values(ledger_b);
    let degradation_added = set_diff_values(&degraded_b, &degraded_a);
    let degradation_removed = set_diff_values(&degraded_a, &degraded_b);

    let mut derived_asset_changes = Vec::new();
    for field in ["searchIndex", "graphSnapshot"] {
        let old_asset = pack_record_derived_asset(ledger_a, field);
        let new_asset = pack_record_derived_asset(ledger_b, field);
        if old_asset != new_asset {
            derived_asset_changes.push(serde_json::json!({
                "asset": field,
                "old": old_asset,
                "new": new_asset,
            }));
        }
    }

    let old_max_tokens = pack_record_request_value(ledger_a, "maxTokens")
        .and_then(|value| value.as_u64())
        .unwrap_or(u64::from(record_a.max_tokens));
    let new_max_tokens = pack_record_request_value(ledger_b, "maxTokens")
        .and_then(|value| value.as_u64())
        .unwrap_or(u64::from(record_b.max_tokens));

    let mut likely_causes = BTreeSet::new();
    if ledger_a.status != PackLedgerStatus::Available
        || ledger_b.status != PackLedgerStatus::Available
    {
        likely_causes.insert("ledger_unavailable_or_untrusted");
    }
    if record_a.query != record_b.query {
        likely_causes.insert("query_changed");
    }
    if record_a.profile != record_b.profile {
        likely_causes.insert("profile_changed");
    }
    if old_max_tokens != new_max_tokens {
        likely_causes.insert("budget_changed");
    }
    if !derived_asset_changes.is_empty() {
        likely_causes.insert("derived_asset_changed");
    }
    if !degradation_added.is_empty() || !degradation_removed.is_empty() {
        likely_causes.insert("degradation_changed");
    }
    if !redaction_changes.is_empty() {
        likely_causes.insert("redaction_changed");
    }
    if !changed.is_empty() || !added.is_empty() || !removed.is_empty() {
        likely_causes.insert("selection_changed");
    }
    if likely_causes.is_empty() && record_a.pack_hash == record_b.pack_hash {
        likely_causes.insert("no_change");
    } else if record_a.pack_hash != record_b.pack_hash && likely_causes.is_empty() {
        likely_causes.insert("memory_or_index_state_changed");
    }

    serde_json::json!({
        "summary": {
            "addedCount": added.len(),
            "removedCount": removed.len(),
            "changedCount": changed.len(),
            "redactionChangeCount": redaction_changes.len(),
            "degradationAddedCount": degradation_added.len(),
            "degradationRemovedCount": degradation_removed.len(),
            "derivedAssetChangeCount": derived_asset_changes.len(),
            "hashMatch": record_a.pack_hash == record_b.pack_hash,
            "queryMatch": record_a.query == record_b.query,
            "profileMatch": record_a.profile == record_b.profile,
            "tokenDelta": i64::from(record_b.used_tokens) - i64::from(record_a.used_tokens),
            "replayable": ledger_a.ledger.is_some() && ledger_b.ledger.is_some(),
        },
        "added": added,
        "removed": removed,
        "changed": changed,
        "redactionChanges": redaction_changes,
        "degradationChanges": {
            "added": degradation_added,
            "removed": degradation_removed,
        },
        "derivedAssetChanges": derived_asset_changes,
        "likelyCauses": likely_causes.into_iter().collect::<Vec<_>>(),
    })
}

fn handle_pack_replay<W, E>(
    cli: &Cli,
    args: &PackReplayArgs,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    let connection = match open_pack_read_database(cli, args.database.as_deref()) {
        Ok(connection) => connection,
        Err(error) => return write_domain_error(&error, cli.wants_json(), stdout, stderr),
    };
    let record = match load_pack_record(&connection, &args.pack_id) {
        Ok(record) => record,
        Err(error) => return write_domain_error(&error, cli.wants_json(), stdout, stderr),
    };
    let items = match load_pack_items(&connection, &args.pack_id) {
        Ok(items) => items,
        Err(error) => return write_domain_error(&error, cli.wants_json(), stdout, stderr),
    };
    let ledger = parse_pack_ledger(&record);
    let ledger_value = ledger.ledger.clone();
    let selected_items = ledger_value
        .as_ref()
        .and_then(|value| ledger_core_array(value, "selectedItems"))
        .cloned()
        .unwrap_or_default();
    let omitted_items = ledger_value
        .as_ref()
        .and_then(|value| ledger_core_array(value, "omittedItems"))
        .cloned()
        .unwrap_or_default();
    let ledger_degraded = ledger_degraded_values(&ledger);

    let response = serde_json::json!({
        "schema": PACK_REPLAY_SCHEMA_V1,
        "success": true,
        "data": {
            "command": "pack replay",
            "pack": pack_record_json(&record, &ledger),
            "replay": {
                "status": ledger.status.as_str(),
                "ledger": ledger_value,
                "selectedItems": selected_items,
                "omittedItems": omitted_items,
                "degraded": ledger_degraded,
            },
            "storedItems": items.iter().map(stored_pack_item_json).collect::<Vec<_>>(),
            "degraded": ledger.degraded,
        }
    });

    write_stdout(stdout, &(response.to_string() + "\n"))
}

fn handle_pack_diff<W, E>(
    cli: &Cli,
    args: &PackDiffArgs,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    let connection = match open_pack_read_database(cli, args.database.as_deref()) {
        Ok(connection) => connection,
        Err(error) => return write_domain_error(&error, cli.wants_json(), stdout, stderr),
    };
    let record_a = match load_pack_record(&connection, &args.pack_a) {
        Ok(record) => record,
        Err(error) => return write_domain_error(&error, cli.wants_json(), stdout, stderr),
    };
    let record_b = match load_pack_record(&connection, &args.pack_b) {
        Ok(record) => record,
        Err(error) => return write_domain_error(&error, cli.wants_json(), stdout, stderr),
    };
    let items_a = match load_pack_items(&connection, &args.pack_a) {
        Ok(items) => items,
        Err(error) => return write_domain_error(&error, cli.wants_json(), stdout, stderr),
    };
    let items_b = match load_pack_items(&connection, &args.pack_b) {
        Ok(items) => items,
        Err(error) => return write_domain_error(&error, cli.wants_json(), stdout, stderr),
    };
    let ledger_a = parse_pack_ledger(&record_a);
    let ledger_b = parse_pack_ledger(&record_b);
    let diff = collect_pack_diff(
        &record_a, &ledger_a, &items_a, &record_b, &ledger_b, &items_b,
    );
    let mut degraded = ledger_a.degraded.clone();
    degraded.extend(ledger_b.degraded.clone());

    let response = serde_json::json!({
        "schema": PACK_DIFF_SCHEMA_V1,
        "success": true,
        "data": {
            "command": "pack diff",
            "packA": pack_record_json(&record_a, &ledger_a),
            "packB": pack_record_json(&record_b, &ledger_b),
            "diff": diff,
            "degraded": degraded,
        }
    });

    write_stdout(stdout, &(response.to_string() + "\n"))
}

fn load_query_file(path: &Path) -> Result<QueryFileRequest, QueryFileError> {
    validate_query_file_path(path)?;
    let bytes = fs::read(path).map_err(|error| {
        QueryFileError::new(
            QueryFileErrorCode::InvalidFile,
            format!("Failed to read query file {}: {error}", path.display()),
            Some("Check file permissions and retry.".to_string()),
        )
    })?;
    let content = String::from_utf8(bytes).map_err(|error| {
        QueryFileError::new(
            QueryFileErrorCode::MalformedJson,
            format!("Query file is not valid UTF-8 JSON: {error}"),
            Some("Save the query document as UTF-8 JSON.".to_string()),
        )
    })?;
    parse_query_document(&content)
}

fn validate_query_file_path(path: &Path) -> Result<(), QueryFileError> {
    if path.as_os_str().is_empty() || path_has_parent_dir(path) {
        return Err(QueryFileError::new(
            QueryFileErrorCode::UnsafePath,
            format!("Unsafe query file path: {}", path.display()),
            Some("Pass a direct JSON file path without '..' components.".to_string()),
        ));
    }

    let metadata = fs::symlink_metadata(path).map_err(|error| {
        QueryFileError::new(
            QueryFileErrorCode::MissingFile,
            format!("Query file not found at {}: {error}", path.display()),
            Some("Create the query file or pass the correct --query-file path.".to_string()),
        )
    })?;
    if metadata.file_type().is_symlink() {
        return Err(QueryFileError::new(
            QueryFileErrorCode::UnsafePath,
            format!(
                "Query file path is a symlink and is not accepted: {}",
                path.display()
            ),
            Some("Pass the canonical JSON file path directly.".to_string()),
        ));
    }
    if !metadata.is_file() {
        return Err(QueryFileError::new(
            QueryFileErrorCode::InvalidFile,
            format!("Query file path is not a regular file: {}", path.display()),
            Some("Pass a regular JSON file to --query-file.".to_string()),
        ));
    }
    if metadata.len() > QUERY_FILE_MAX_BYTES {
        return Err(QueryFileError::new(
            QueryFileErrorCode::InvalidFile,
            format!(
                "Query file is too large: {} bytes exceeds the {} byte limit.",
                metadata.len(),
                QUERY_FILE_MAX_BYTES
            ),
            Some("Use a smaller ee.query.v1 JSON document.".to_string()),
        ));
    }

    Ok(())
}

fn path_has_parent_dir(path: &Path) -> bool {
    path.components()
        .any(|component| matches!(component, Component::ParentDir))
}

fn parse_query_document(content: &str) -> Result<QueryFileRequest, QueryFileError> {
    let value: serde_json::Value = serde_json::from_str(content).map_err(|error| {
        QueryFileError::new(
            QueryFileErrorCode::MalformedJson,
            format!("Malformed ee.query.v1 JSON: {error}"),
            Some("Fix the JSON syntax and retry.".to_string()),
        )
    })?;
    let object = value.as_object().ok_or_else(|| {
        QueryFileError::new(
            QueryFileErrorCode::MalformedJson,
            "Query document must be a JSON object.",
            Some("Use an object with version and query fields.".to_string()),
        )
    })?;

    let mut degraded = unknown_field_degradations(object)?;
    validate_query_version(object)?;
    validate_unsupported_query_features(object)?;

    let query = query_text_from_document(object)?;
    let workspace_path = optional_path_field(object, "workspace")?;
    let budget = budget_from_document(object)?;
    let speed = speed_from_document(object)?;
    let (profile, renderer, mut output_degraded) = output_from_document(object)?;
    degraded.append(&mut output_degraded);
    let filters = extract_query_filters(object)?;
    let pagination = pagination_from_document(object);

    Ok(QueryFileRequest {
        workspace_path,
        query,
        profile,
        max_tokens: budget.max_tokens,
        candidate_pool: budget.candidate_pool,
        max_results: budget.max_results,
        speed,
        renderer,
        degraded,
        filters,
        pagination,
    })
}

fn pagination_from_document(
    object: &serde_json::Map<String, serde_json::Value>,
) -> crate::models::QueryPagination {
    object
        .get("pagination")
        .map(crate::models::parse_pagination)
        .unwrap_or_default()
}

fn unknown_field_degradations(
    object: &serde_json::Map<String, serde_json::Value>,
) -> Result<Vec<ContextResponseDegradation>, QueryFileError> {
    let mut degraded = Vec::new();
    for key in object.keys() {
        if !QUERY_FILE_TOP_LEVEL_FIELDS.contains(&key.as_str()) {
            let entry = ContextResponseDegradation::new(
                "query_unknown_field",
                ContextResponseSeverity::Low,
                format!("Unknown ee.query.v1 field '{key}' was ignored."),
                Some(
                    "Remove the field or upgrade ee if the field is from a newer schema."
                        .to_string(),
                ),
            )
            .map_err(|error| {
                QueryFileError::new(
                    QueryFileErrorCode::UnsupportedFeature,
                    error.to_string(),
                    Some("Fix the query document and retry.".to_string()),
                )
            })?;
            degraded.push(entry);
        }
    }
    Ok(degraded)
}

fn validate_query_version(
    object: &serde_json::Map<String, serde_json::Value>,
) -> Result<(), QueryFileError> {
    match object.get("version").and_then(serde_json::Value::as_str) {
        Some(QUERY_SCHEMA_V1) => Ok(()),
        Some(version) => Err(QueryFileError::new(
            QueryFileErrorCode::UnknownVersion,
            format!("Unsupported query schema version '{version}'. Expected {QUERY_SCHEMA_V1}."),
            Some(format!("Set version to \"{QUERY_SCHEMA_V1}\".")),
        )),
        None => Err(QueryFileError::new(
            QueryFileErrorCode::UnknownVersion,
            format!("Missing required query schema version. Expected {QUERY_SCHEMA_V1}."),
            Some(format!(
                "Add \"version\": \"{QUERY_SCHEMA_V1}\" to the query file."
            )),
        )),
    }
}

fn validate_unsupported_query_features(
    object: &serde_json::Map<String, serde_json::Value>,
) -> Result<(), QueryFileError> {
    // Validate filter syntax (filters are now wired into pack execution)
    if let Some(filters) = object.get("filters") {
        validate_filters(filters)?;
    }

    if let Some(tags) = object.get("tags") {
        validate_tags_object(tags)?;
    }

    if let Some(graph) = object.get("graph") {
        validate_graph_object(graph)?;
    }

    if let Some(pagination) = object.get("pagination") {
        validate_pagination_object(pagination)?;
    }

    if let Some(trust) = object.get("trust") {
        validate_trust_object(trust)?;
    }

    if let Some(redaction) = object.get("redaction") {
        validate_redaction_object(redaction)?;
    }

    Ok(())
}

fn extract_query_filters(
    object: &serde_json::Map<String, serde_json::Value>,
) -> Result<crate::models::QueryFilters, QueryFileError> {
    let mut filters = object
        .get("filters")
        .and_then(crate::models::parse_filters)
        .unwrap_or_default();

    if let Some(tags_value) = object.get("tags") {
        filters.tags = crate::models::parse_tags(tags_value);
    }

    if let Some(trust_value) = object.get("trust") {
        filters.trust = crate::models::parse_trust(trust_value);
    }

    if let Some(redaction_value) = object.get("redaction") {
        filters.redaction = crate::models::parse_redaction(redaction_value);
    }

    filters.temporal = temporal_filters_from_document(object)?;
    filters.graph = graph_hints_from_document(object)?;

    Ok(filters)
}

fn validate_graph_object(value: &serde_json::Value) -> Result<(), QueryFileError> {
    let Some(object) = value.as_object() else {
        return Err(QueryFileError::new(
            QueryFileErrorCode::MalformedJson,
            "graph must be an object with seedMemories, traversal, maxHops, linkTypes, or includeOrphans.",
            Some(
                "Use graph: { seedMemories: [\"mem_...\"], traversal: \"bidirectional\", maxHops: 1 }."
                    .to_string(),
            ),
        ));
    };

    for key in object.keys() {
        if ![
            "seedMemories",
            "traversal",
            "maxHops",
            "linkTypes",
            "includeOrphans",
        ]
        .contains(&key.as_str())
        {
            return Err(QueryFileError::new(
                QueryFileErrorCode::MalformedJson,
                format!(
                    "Unknown graph field '{key}'. Expected seedMemories, traversal, maxHops, linkTypes, or includeOrphans."
                ),
                Some("Use only documented ee.query.v1 graph hint fields inside graph.".to_string()),
            ));
        }
    }

    if let Some(seeds) = object.get("seedMemories") {
        let arr = seeds.as_array().ok_or_else(|| {
            QueryFileError::new(
                QueryFileErrorCode::MalformedJson,
                "graph.seedMemories must be an array of memory ID strings.",
                Some("Use graph.seedMemories: [\"mem_...\"]".to_string()),
            )
        })?;
        for item in arr {
            let seed = item.as_str().ok_or_else(|| {
                QueryFileError::new(
                    QueryFileErrorCode::MalformedJson,
                    "graph.seedMemories array elements must be strings.",
                    Some("Use graph.seedMemories: [\"mem_...\"]".to_string()),
                )
            })?;
            if seed.trim().is_empty() {
                return Err(QueryFileError::new(
                    QueryFileErrorCode::MalformedJson,
                    "graph.seedMemories entries cannot be empty.",
                    Some("Remove empty graph seed values.".to_string()),
                ));
            }
        }
    }

    if let Some(traversal) = object.get("traversal") {
        let raw = traversal.as_str().ok_or_else(|| {
            QueryFileError::new(
                QueryFileErrorCode::MalformedJson,
                "graph.traversal must be a string.",
                Some("Use outbound, inbound, or bidirectional.".to_string()),
            )
        })?;
        if crate::models::QueryGraphTraversal::parse(raw).is_none() {
            return Err(QueryFileError::new(
                QueryFileErrorCode::MalformedJson,
                format!("Unsupported graph.traversal '{raw}'."),
                Some("Use outbound, inbound, or bidirectional.".to_string()),
            ));
        }
    }

    if let Some(max_hops) = object.get("maxHops") {
        let value = max_hops.as_u64().ok_or_else(|| {
            QueryFileError::new(
                QueryFileErrorCode::MalformedJson,
                "graph.maxHops must be a non-negative integer.",
                Some("Use graph.maxHops: 1.".to_string()),
            )
        })?;
        if value > 8 {
            return Err(QueryFileError::new(
                QueryFileErrorCode::MalformedJson,
                format!("graph.maxHops {value} exceeds the bounded maximum of 8."),
                Some("Use graph.maxHops <= 8 to keep query-file expansion bounded.".to_string()),
            ));
        }
    }

    if let Some(link_types) = object.get("linkTypes") {
        let arr = link_types.as_array().ok_or_else(|| {
            QueryFileError::new(
                QueryFileErrorCode::MalformedJson,
                "graph.linkTypes must be an array of memory link relation strings.",
                Some("Use graph.linkTypes: [\"supports\", \"related\"].".to_string()),
            )
        })?;
        for item in arr {
            let relation = item.as_str().ok_or_else(|| {
                QueryFileError::new(
                    QueryFileErrorCode::MalformedJson,
                    "graph.linkTypes array elements must be strings.",
                    Some("Use graph.linkTypes: [\"supports\", \"related\"].".to_string()),
                )
            })?;
            if crate::db::MemoryLinkRelation::parse(relation).is_none() {
                return Err(QueryFileError::new(
                    QueryFileErrorCode::MalformedJson,
                    format!("Unknown graph.linkTypes relation '{relation}'."),
                    Some(
                        "Use one of: supports, contradicts, derived_from, supersedes, related, co_tag, co_mention."
                            .to_string(),
                    ),
                ));
            }
        }
    }

    if let Some(include_orphans) = object.get("includeOrphans")
        && !include_orphans.is_boolean()
    {
        return Err(QueryFileError::new(
            QueryFileErrorCode::MalformedJson,
            "graph.includeOrphans must be a boolean.",
            Some("Use graph.includeOrphans: true or false.".to_string()),
        ));
    }

    Ok(())
}

fn graph_hints_from_document(
    object: &serde_json::Map<String, serde_json::Value>,
) -> Result<crate::models::QueryGraphHints, QueryFileError> {
    let Some(graph) = object.get("graph") else {
        return Ok(crate::models::QueryGraphHints::default());
    };
    let graph = graph.as_object().ok_or_else(|| {
        QueryFileError::new(
            QueryFileErrorCode::MalformedJson,
            "graph must be an object.",
            Some("Use graph: { seedMemories: [\"mem_...\"] }.".to_string()),
        )
    })?;

    let seed_memories = graph
        .get("seedMemories")
        .and_then(serde_json::Value::as_array)
        .map(|arr| {
            arr.iter()
                .filter_map(serde_json::Value::as_str)
                .map(str::trim)
                .filter(|value| !value.is_empty())
                .map(String::from)
                .collect()
        })
        .unwrap_or_default();
    let traversal = graph
        .get("traversal")
        .and_then(serde_json::Value::as_str)
        .and_then(crate::models::QueryGraphTraversal::parse)
        .unwrap_or_default();
    let max_hops = graph
        .get("maxHops")
        .and_then(serde_json::Value::as_u64)
        .and_then(|value| u32::try_from(value).ok())
        .unwrap_or(1)
        .min(8);
    let link_types = graph
        .get("linkTypes")
        .and_then(serde_json::Value::as_array)
        .map(|arr| {
            arr.iter()
                .filter_map(serde_json::Value::as_str)
                .map(String::from)
                .collect()
        })
        .unwrap_or_default();
    let include_orphans = graph
        .get("includeOrphans")
        .and_then(serde_json::Value::as_bool)
        .unwrap_or(true);

    Ok(crate::models::QueryGraphHints {
        enabled: true,
        seed_memories,
        traversal,
        max_hops,
        link_types,
        include_orphans,
    })
}

fn validate_tags_object(value: &serde_json::Value) -> Result<(), QueryFileError> {
    let Some(object) = value.as_object() else {
        return Err(QueryFileError::new(
            QueryFileErrorCode::MalformedJson,
            "tags must be an object with require, requireAny, or exclude arrays.",
            Some("Use tags: { require: [...], requireAny: [...], exclude: [...] }.".to_string()),
        ));
    };

    for (key, arr_value) in object {
        if !["require", "requireAny", "exclude"].contains(&key.as_str()) {
            return Err(QueryFileError::new(
                QueryFileErrorCode::MalformedJson,
                format!("Unknown tags field '{key}'. Expected require, requireAny, or exclude."),
                Some("Use only require, requireAny, or exclude inside tags.".to_string()),
            ));
        }
        let Some(arr) = arr_value.as_array() else {
            return Err(QueryFileError::new(
                QueryFileErrorCode::MalformedJson,
                format!("tags.{key} must be an array of strings."),
                Some(format!("Use tags.{key}: [\"tag1\", \"tag2\"].")),
            ));
        };
        for item in arr {
            if !item.is_string() {
                return Err(QueryFileError::new(
                    QueryFileErrorCode::MalformedJson,
                    format!("tags.{key} array elements must be strings."),
                    Some(format!("Use tags.{key}: [\"tag1\", \"tag2\"].")),
                ));
            }
        }
    }

    Ok(())
}

fn validate_trust_object(value: &serde_json::Value) -> Result<(), QueryFileError> {
    let Some(object) = value.as_object() else {
        return Err(QueryFileError::new(
            QueryFileErrorCode::MalformedJson,
            "trust must be an object with minClass, excludeClasses, or requirePosture.",
            Some(
                "Use trust: { minClass: \"human_explicit\", excludeClasses: [...], requirePosture: \"authoritative\" }."
                    .to_string(),
            ),
        ));
    };

    let valid_trust_classes = [
        "human_explicit",
        "agent_validated",
        "agent_assertion",
        "cass_evidence",
        "legacy_import",
    ];
    let valid_postures = ["authoritative", "provisional", "untrusted"];

    for key in object.keys() {
        if !["minClass", "excludeClasses", "requirePosture"].contains(&key.as_str()) {
            return Err(QueryFileError::new(
                QueryFileErrorCode::MalformedJson,
                format!(
                    "Unknown trust field '{key}'. Expected minClass, excludeClasses, or requirePosture."
                ),
                Some(
                    "Use only minClass, excludeClasses, or requirePosture inside trust."
                        .to_string(),
                ),
            ));
        }
    }

    if let Some(min_class) = object.get("minClass") {
        let value = min_class.as_str().ok_or_else(|| {
            QueryFileError::new(
                QueryFileErrorCode::MalformedJson,
                "trust.minClass must be a string.",
                Some("Use trust.minClass: \"human_explicit\".".to_string()),
            )
        })?;
        if !valid_trust_classes.contains(&value) {
            return Err(QueryFileError::new(
                QueryFileErrorCode::MalformedJson,
                format!("Unknown trust class '{value}'."),
                Some(format!("Use one of: {}.", valid_trust_classes.join(", "))),
            ));
        }
    }

    if let Some(exclude) = object.get("excludeClasses") {
        let arr = exclude.as_array().ok_or_else(|| {
            QueryFileError::new(
                QueryFileErrorCode::MalformedJson,
                "trust.excludeClasses must be an array of strings.",
                Some("Use trust.excludeClasses: [\"agent_inferred\"].".to_string()),
            )
        })?;
        for item in arr {
            let value = item.as_str().ok_or_else(|| {
                QueryFileError::new(
                    QueryFileErrorCode::MalformedJson,
                    "trust.excludeClasses array elements must be strings.",
                    Some("Use trust.excludeClasses: [\"legacy_import\"].".to_string()),
                )
            })?;
            if !valid_trust_classes.contains(&value) {
                return Err(QueryFileError::new(
                    QueryFileErrorCode::MalformedJson,
                    format!("Unknown trust class '{value}' in excludeClasses."),
                    Some(format!("Use one of: {}.", valid_trust_classes.join(", "))),
                ));
            }
        }
    }

    if let Some(posture) = object.get("requirePosture") {
        let value = posture.as_str().ok_or_else(|| {
            QueryFileError::new(
                QueryFileErrorCode::MalformedJson,
                "trust.requirePosture must be a string.",
                Some("Use trust.requirePosture: \"authoritative\".".to_string()),
            )
        })?;
        if !valid_postures.contains(&value) {
            return Err(QueryFileError::new(
                QueryFileErrorCode::MalformedJson,
                format!("Unknown trust posture '{value}'."),
                Some(format!("Use one of: {}.", valid_postures.join(", "))),
            ));
        }
    }

    Ok(())
}

fn validate_redaction_object(value: &serde_json::Value) -> Result<(), QueryFileError> {
    let Some(object) = value.as_object() else {
        return Err(QueryFileError::new(
            QueryFileErrorCode::MalformedJson,
            "redaction must be an object with policy or allowCategories.",
            Some("Use redaction: { policy: \"respect\", allowCategories: [...] }.".to_string()),
        ));
    };

    for key in object.keys() {
        if !["policy", "allowCategories"].contains(&key.as_str()) {
            return Err(QueryFileError::new(
                QueryFileErrorCode::MalformedJson,
                format!("Unknown redaction field '{key}'. Expected policy or allowCategories."),
                Some("Use only policy or allowCategories inside redaction.".to_string()),
            ));
        }
    }

    if let Some(policy) = object.get("policy") {
        let value = policy.as_str().ok_or_else(|| {
            QueryFileError::new(
                QueryFileErrorCode::MalformedJson,
                "redaction.policy must be a string.",
                Some("Use redaction.policy: \"respect\" or \"bypass\".".to_string()),
            )
        })?;
        if !["respect", "bypass"].contains(&value) {
            return Err(QueryFileError::new(
                QueryFileErrorCode::MalformedJson,
                format!("Unknown redaction policy '{value}'."),
                Some("Use \"respect\" or \"bypass\".".to_string()),
            ));
        }
    }

    if let Some(allow) = object.get("allowCategories") {
        let arr = allow.as_array().ok_or_else(|| {
            QueryFileError::new(
                QueryFileErrorCode::MalformedJson,
                "redaction.allowCategories must be an array of strings.",
                Some("Use redaction.allowCategories: [\"internal\"].".to_string()),
            )
        })?;
        for item in arr {
            if !item.is_string() {
                return Err(QueryFileError::new(
                    QueryFileErrorCode::MalformedJson,
                    "redaction.allowCategories array elements must be strings.",
                    Some("Use redaction.allowCategories: [\"internal\"].".to_string()),
                ));
            }
        }
    }

    Ok(())
}

fn validate_pagination_object(value: &serde_json::Value) -> Result<(), QueryFileError> {
    let Some(object) = value.as_object() else {
        return Err(QueryFileError::new(
            QueryFileErrorCode::MalformedJson,
            "pagination must be an object with limit and/or cursor.",
            Some("Use pagination: { limit: 25, cursor: \"...\" }.".to_string()),
        ));
    };

    for key in object.keys() {
        if !["limit", "cursor"].contains(&key.as_str()) {
            return Err(QueryFileError::new(
                QueryFileErrorCode::MalformedJson,
                format!("Unknown pagination field '{key}'. Expected limit or cursor."),
                Some("Use only limit or cursor inside pagination.".to_string()),
            ));
        }
    }

    if let Some(limit) = object.get("limit") {
        let value = limit.as_u64().ok_or_else(|| {
            QueryFileError::new(
                QueryFileErrorCode::MalformedJson,
                "pagination.limit must be a positive integer.",
                Some("Use pagination.limit: 25.".to_string()),
            )
        })?;
        if value == 0 {
            return Err(QueryFileError::new(
                QueryFileErrorCode::ZeroBudget,
                "pagination.limit cannot be zero.",
                Some("Use a positive integer for pagination.limit.".to_string()),
            ));
        }
        if value > 200 {
            return Err(QueryFileError::new(
                QueryFileErrorCode::MalformedJson,
                format!("pagination.limit {value} exceeds maximum of 200."),
                Some("Use pagination.limit <= 200.".to_string()),
            ));
        }
    }

    if let Some(cursor) = object.get("cursor") {
        if !cursor.is_string() {
            return Err(QueryFileError::new(
                QueryFileErrorCode::MalformedJson,
                "pagination.cursor must be a string.",
                Some(
                    "Use pagination.cursor: \"eyJ...\" (opaque token from previous response)."
                        .to_string(),
                ),
            ));
        }
    }

    Ok(())
}

fn temporal_filters_from_document(
    object: &serde_json::Map<String, serde_json::Value>,
) -> Result<crate::models::QueryTemporalFilters, QueryFileError> {
    let mut filters = crate::models::QueryTemporalFilters::default();

    if let Some(time) = object.get("time") {
        let time = time.as_object().ok_or_else(|| {
            QueryFileError::new(
                QueryFileErrorCode::InvalidTimestamp,
                "time must be an object with after and/or before timestamps.",
                Some("Use time: { \"after\": \"2026-05-01T00:00:00Z\" }.".to_string()),
            )
        })?;
        for key in time.keys() {
            if !matches!(key.as_str(), "after" | "before") {
                return Err(QueryFileError::new(
                    QueryFileErrorCode::UnsupportedFeature,
                    format!("Unsupported time field '{key}'. Expected after or before."),
                    Some("Use only time.after and time.before.".to_string()),
                ));
            }
        }
        filters.after = optional_query_timestamp(time, "time.after", "after")?;
        filters.before = optional_query_timestamp(time, "time.before", "before")?;
    }

    if let Some(as_of) = object.get("asOf") {
        filters.as_of = Some(parse_query_timestamp_value("asOf", as_of)?);
    }

    if let Some(validity) = object.get("temporalValidity") {
        let validity = validity.as_object().ok_or_else(|| {
            QueryFileError::new(
                QueryFileErrorCode::UnsupportedFeature,
                "temporalValidity must be an object.",
                Some(
                    "Use temporalValidity: { \"posture\": \"strict\", \"referenceTime\": \"2026-05-01T00:00:00Z\" }."
                        .to_string(),
                ),
            )
        })?;
        for key in validity.keys() {
            if !matches!(key.as_str(), "posture" | "referenceTime") {
                return Err(QueryFileError::new(
                    QueryFileErrorCode::UnsupportedFeature,
                    format!(
                        "Unsupported temporalValidity field '{key}'. Expected posture or referenceTime."
                    ),
                    Some(
                        "Use temporalValidity.posture and temporalValidity.referenceTime."
                            .to_string(),
                    ),
                ));
            }
        }
        let posture = match validity.get("posture") {
            Some(value) => {
                let raw = value.as_str().ok_or_else(|| {
                    QueryFileError::new(
                        QueryFileErrorCode::UnsupportedFeature,
                        "temporalValidity.posture must be a string.",
                        Some("Use strict, relaxed, or ignore.".to_string()),
                    )
                })?;
                crate::models::QueryTemporalValidityPosture::parse(raw).ok_or_else(|| {
                    QueryFileError::new(
                        QueryFileErrorCode::UnsupportedFeature,
                        format!("Unsupported temporalValidity.posture '{raw}'."),
                        Some("Use strict, relaxed, or ignore.".to_string()),
                    )
                })?
            }
            None => crate::models::QueryTemporalValidityPosture::Relaxed,
        };
        let reference_time =
            optional_query_timestamp(validity, "temporalValidity.referenceTime", "referenceTime")?;
        filters.validity = Some(crate::models::QueryTemporalValidity {
            posture,
            reference_time,
        });
    }

    Ok(filters)
}

fn optional_query_timestamp(
    object: &serde_json::Map<String, serde_json::Value>,
    field: &str,
    key: &str,
) -> Result<Option<chrono::DateTime<chrono::Utc>>, QueryFileError> {
    object
        .get(key)
        .map(|value| parse_query_timestamp_value(field, value))
        .transpose()
}

fn parse_query_timestamp_value(
    field: &str,
    value: &serde_json::Value,
) -> Result<chrono::DateTime<chrono::Utc>, QueryFileError> {
    let raw = value.as_str().ok_or_else(|| {
        QueryFileError::new(
            QueryFileErrorCode::InvalidTimestamp,
            format!("{field} must be an RFC 3339 timestamp string."),
            Some("Use timestamps such as 2026-05-01T00:00:00Z.".to_string()),
        )
    })?;
    chrono::DateTime::parse_from_rfc3339(raw)
        .map(|timestamp| timestamp.with_timezone(&chrono::Utc))
        .map_err(|error| {
            QueryFileError::new(
                QueryFileErrorCode::InvalidTimestamp,
                format!("{field} must be an RFC 3339 timestamp: {error}"),
                Some("Use timestamps such as 2026-05-01T00:00:00Z.".to_string()),
            )
        })
}

fn validate_filters(value: &serde_json::Value) -> Result<(), QueryFileError> {
    let filters = value.as_object().ok_or_else(|| {
        QueryFileError::new(
            QueryFileErrorCode::InvalidOperator,
            "filters must be a JSON object.",
            Some("Use {\"field\": {\"operator\": value}} filter objects.".to_string()),
        )
    })?;
    for (field, predicate) in filters {
        let predicate = predicate.as_object().ok_or_else(|| {
            QueryFileError::new(
                QueryFileErrorCode::InvalidOperator,
                format!("Filter '{field}' must be an object of operators."),
                Some("Use supported operators such as eq, in, gte, or exists.".to_string()),
            )
        })?;
        for (operator, filter_value) in predicate {
            if !QUERY_FILE_FILTER_OPERATORS.contains(&operator.as_str()) {
                return Err(QueryFileError::new(
                    QueryFileErrorCode::InvalidOperator,
                    format!("Invalid filter operator '{operator}' for field '{field}'."),
                    Some(format!(
                        "Use one of: {}.",
                        QUERY_FILE_FILTER_OPERATORS.join(", ")
                    )),
                ));
            }
            let parsed_operator = FilterOperator::parse_name(operator).ok_or_else(|| {
                QueryFileError::new(
                    QueryFileErrorCode::InvalidOperator,
                    format!("Invalid filter operator '{operator}' for field '{field}'."),
                    Some(format!(
                        "Use one of: {}.",
                        QUERY_FILE_FILTER_OPERATORS.join(", ")
                    )),
                )
            })?;
            if !parsed_operator.accepts_json_value(filter_value) {
                return Err(QueryFileError::new(
                    QueryFileErrorCode::InvalidFilterValue,
                    format!(
                        "Invalid value for filter '{field}.{operator}': expected {}.",
                        parsed_operator.expected_json_value()
                    ),
                    Some(
                        "Use typed ee.query.v1 filter values; exists requires true or false."
                            .to_string(),
                    ),
                ));
            }
        }
    }
    Ok(())
}

fn query_text_from_document(
    object: &serde_json::Map<String, serde_json::Value>,
) -> Result<String, QueryFileError> {
    let query = object.get("query").ok_or_else(|| {
        QueryFileError::new(
            QueryFileErrorCode::EmptyQuery,
            "Missing required query.text field.",
            Some("Add {\"query\": {\"text\": \"...\"}} to the query file.".to_string()),
        )
    })?;
    let query_object = query.as_object().ok_or_else(|| {
        QueryFileError::new(
            QueryFileErrorCode::EmptyQuery,
            "query must be an object with a text field.",
            Some("Use {\"query\": {\"text\": \"...\"}}.".to_string()),
        )
    })?;
    let text = query_object
        .get("text")
        .and_then(serde_json::Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .ok_or_else(|| {
            QueryFileError::new(
                QueryFileErrorCode::EmptyQuery,
                "query.text is required and must not be empty.",
                Some("Provide a non-empty query.text value.".to_string()),
            )
        })?;

    if let Some(mode) = query_object
        .get("mode")
        .and_then(serde_json::Value::as_str)
        .filter(|mode| *mode != "hybrid")
    {
        return Err(QueryFileError::new(
            QueryFileErrorCode::UnsupportedFeature,
            format!(
                "query.mode '{mode}' is recognized but only hybrid mode is currently supported."
            ),
            Some("Set query.mode to \"hybrid\" or omit it.".to_string()),
        ));
    }

    Ok(text.to_string())
}

fn optional_path_field(
    object: &serde_json::Map<String, serde_json::Value>,
    field: &str,
) -> Result<Option<PathBuf>, QueryFileError> {
    let Some(value) = object.get(field) else {
        return Ok(None);
    };
    let path = value
        .as_str()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .ok_or_else(|| {
            QueryFileError::new(
                QueryFileErrorCode::UnsafePath,
                format!("{field} must be a non-empty string path."),
                Some(format!("Set {field} to a direct workspace path.")),
            )
        })?;
    let path = PathBuf::from(path);
    if path_has_parent_dir(&path) {
        return Err(QueryFileError::new(
            QueryFileErrorCode::UnsafePath,
            format!("Unsafe {field} path contains '..': {}", path.display()),
            Some(
                "Use a direct absolute path or path relative to the current directory.".to_string(),
            ),
        ));
    }
    Ok(Some(path))
}

fn budget_from_document(
    object: &serde_json::Map<String, serde_json::Value>,
) -> Result<QueryFileBudget, QueryFileError> {
    let Some(budget) = object.get("budget") else {
        return Ok(QueryFileBudget::default());
    };
    let budget = budget.as_object().ok_or_else(|| {
        QueryFileError::new(
            QueryFileErrorCode::ZeroBudget,
            "budget must be a JSON object.",
            Some("Use {\"budget\": {\"maxTokens\": 4000, \"candidatePool\": 100}}.".to_string()),
        )
    })?;
    let max_tokens = optional_positive_u32(budget, "maxTokens")?;
    let candidate_pool = optional_positive_u32(budget, "candidatePool")?;
    let max_results = optional_positive_u32(budget, "maxResults")?;
    Ok(QueryFileBudget {
        max_tokens,
        candidate_pool,
        max_results,
    })
}

fn speed_from_document(
    object: &serde_json::Map<String, serde_json::Value>,
) -> Result<crate::search::SpeedMode, QueryFileError> {
    let Some(value) = object.get("speed") else {
        return Ok(crate::search::SpeedMode::Default);
    };
    let speed = value.as_str().map(str::trim).ok_or_else(|| {
        QueryFileError::new(
            QueryFileErrorCode::UnsupportedFeature,
            "speed must be a string.",
            Some("Use instant, default, or quality.".to_string()),
        )
    })?;
    parse_speed_mode_arg(speed).map_err(|error| {
        QueryFileError::new(
            QueryFileErrorCode::UnsupportedFeature,
            error,
            Some("Use instant, default, or quality.".to_string()),
        )
    })
}

fn optional_positive_u32(
    object: &serde_json::Map<String, serde_json::Value>,
    field: &str,
) -> Result<Option<u32>, QueryFileError> {
    let Some(value) = object.get(field) else {
        return Ok(None);
    };
    let Some(raw) = value.as_u64() else {
        return Err(QueryFileError::new(
            QueryFileErrorCode::ZeroBudget,
            format!("budget.{field} must be a positive integer."),
            Some("Use non-zero integer budget values.".to_string()),
        ));
    };
    if raw == 0 || raw > u64::from(u32::MAX) {
        return Err(QueryFileError::new(
            QueryFileErrorCode::ZeroBudget,
            format!("budget.{field} must be between 1 and {}.", u32::MAX),
            Some("Use non-zero integer budget values.".to_string()),
        ));
    }
    Ok(Some(raw as u32))
}

fn output_from_document(
    object: &serde_json::Map<String, serde_json::Value>,
) -> Result<QueryOutputControls, QueryFileError> {
    let Some(output) = object.get("output") else {
        return Ok((None, None, Vec::new()));
    };
    let output = output.as_object().ok_or_else(|| {
        QueryFileError::new(
            QueryFileErrorCode::UnsupportedFeature,
            "output must be a JSON object.",
            Some(
                "Use {\"output\": {\"profile\": \"balanced\", \"format\": \"json\"}}.".to_string(),
            ),
        )
    })?;

    let profile = match output.get("profile").and_then(serde_json::Value::as_str) {
        Some("compact") => Some(ContextPackProfile::Compact),
        Some("balanced") => Some(ContextPackProfile::Balanced),
        Some("thorough" | "wide") => Some(ContextPackProfile::Thorough),
        Some("submodular") => Some(ContextPackProfile::Submodular),
        Some("custom") => {
            return Err(QueryFileError::new(
                QueryFileErrorCode::UnsupportedFeature,
                "output.profile 'custom' requires named custom profile support, which is not wired yet.",
                Some("Use compact, balanced, wide, thorough, or submodular.".to_string()),
            ));
        }
        Some(profile) => {
            return Err(QueryFileError::new(
                QueryFileErrorCode::UnsupportedFeature,
                format!("Unsupported output.profile '{profile}'."),
                Some("Use compact, balanced, wide, thorough, or submodular.".to_string()),
            ));
        }
        None => None,
    };

    let renderer = match output.get("format").and_then(serde_json::Value::as_str) {
        Some("human") => Some(output::Renderer::Human),
        Some("json") => Some(output::Renderer::Json),
        Some("jsonl") => Some(output::Renderer::Jsonl),
        Some("compact") => Some(output::Renderer::Compact),
        Some("hook") => Some(output::Renderer::Hook),
        Some("markdown") => Some(output::Renderer::Markdown),
        Some("toon") => Some(output::Renderer::Toon),
        Some(format) => {
            return Err(QueryFileError::new(
                QueryFileErrorCode::UnsupportedFeature,
                format!("Unsupported output.format '{format}'."),
                Some("Use json, markdown, toon, human, jsonl, compact, or hook.".to_string()),
            ));
        }
        None => None,
    };

    validate_output_fields(output)?;
    let mut degraded = Vec::new();
    if output.contains_key("fields") {
        degraded.push(
            ContextResponseDegradation::new(
                "query_output_fields_cli_controlled",
                ContextResponseSeverity::Low,
                "output.fields was validated; effective field projection is controlled by the global --fields flag.",
                Some("Pass --fields on the ee command line to control projection.".to_string()),
            )
            .map_err(|error| {
                QueryFileError::new(
                    QueryFileErrorCode::UnsupportedFeature,
                    error.to_string(),
                    Some("Fix the query document and retry.".to_string()),
                )
            })?,
        );
    }
    if let Some(explain) = output.get("explain") {
        match explain.as_bool() {
            Some(true) => degraded.push(
                ContextResponseDegradation::new(
                    "query_output_explain_already_included",
                    ContextResponseSeverity::Low,
                    "output.explain was accepted; JSON context packs already include algorithm metadata, the selection audit, and per-item why explanations.",
                    Some("Inspect data.pack.meta.algorithm, data.pack.selectionAudit, and data.pack.items[].why.".to_string()),
                )
                .map_err(|error| {
                    QueryFileError::new(
                        QueryFileErrorCode::UnsupportedFeature,
                        error.to_string(),
                        Some("Fix the query document and retry.".to_string()),
                    )
                })?,
            ),
            Some(false) => {}
            None => {
                return Err(QueryFileError::new(
                    QueryFileErrorCode::UnsupportedFeature,
                    "output.explain must be a boolean.",
                    Some("Use true or false for output.explain.".to_string()),
                ));
            }
        }
    }

    Ok((profile, renderer, degraded))
}

fn validate_output_fields(
    output: &serde_json::Map<String, serde_json::Value>,
) -> Result<(), QueryFileError> {
    let Some(fields) = output.get("fields") else {
        return Ok(());
    };
    match fields.as_str() {
        Some("minimal" | "summary" | "standard" | "full") => Ok(()),
        Some(fields) => Err(QueryFileError::new(
            QueryFileErrorCode::UnsupportedFeature,
            format!("Unsupported output.fields '{fields}'."),
            Some("Use minimal, summary, standard, or full.".to_string()),
        )),
        None => Err(QueryFileError::new(
            QueryFileErrorCode::UnsupportedFeature,
            "output.fields must be a string.",
            Some("Use minimal, summary, standard, or full.".to_string()),
        )),
    }
}

fn effective_pack_renderer(
    cli: &Cli,
    query_renderer: Option<output::Renderer>,
) -> output::Renderer {
    if cli.format != OutputFormat::Human || cli.json || cli.robot {
        cli.renderer()
    } else {
        query_renderer.unwrap_or_else(|| cli.renderer())
    }
}

fn write_query_file_error<W, E>(
    error: &QueryFileError,
    wants_json: bool,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    if wants_json {
        let mut error_json = serde_json::json!({
            "code": error.code.as_str(),
            "message": &error.message,
            "severity": "low",
            "details": {},
        });
        if let Some(repair) = &error.repair {
            if let Some(error_map) = error_json.as_object_mut() {
                error_map.insert(
                    "repair".to_string(),
                    serde_json::Value::String(repair.clone()),
                );
            }
        }
        let json = serde_json::json!({
            "schema": crate::models::ERROR_SCHEMA_V2,
            "error": error_json,
        });
        let _ = stdout.write_all((json.to_string() + "\n").as_bytes());
    } else {
        let _ = writeln!(stderr, "error: {}: {}", error.code.as_str(), error.message);
        if let Some(repair) = &error.repair {
            let _ = writeln!(stderr, "\nNext:\n  {repair}");
        }
    }
    ProcessExitCode::Usage
}

fn handle_review_session<W, E>(
    cli: &Cli,
    args: &ReviewSessionArgs,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    let workspace_path = cli.resolve_workspace();
    let options = ReviewSessionOptions {
        workspace_path: workspace_path.as_path(),
        database_path: args.database.as_deref(),
        session_id: args.session.as_deref(),
        propose: args.propose,
        dry_run: args.dry_run,
        min_confidence: args.min_confidence,
        limit: args.limit,
    };

    match review_session_proposals(&options) {
        Ok(report) => write_review_session_report(cli, &report, stdout),
        Err(error) => write_domain_error(&error, cli.wants_json(), stdout, stderr),
    }
}

fn write_review_session_report<W>(
    cli: &Cli,
    report: &ReviewSessionReport,
    stdout: &mut W,
) -> ProcessExitCode
where
    W: Write,
{
    match cli.renderer() {
        output::Renderer::Human | output::Renderer::Markdown => {
            write_stdout(stdout, &format_review_session_human(report))
        }
        output::Renderer::Toon => write_stdout(
            stdout,
            &(output::render_toon_from_json(&format_review_session_json(report)) + "\n"),
        ),
        output::Renderer::Json
        | output::Renderer::Jsonl
        | output::Renderer::Compact
        | output::Renderer::Hook => {
            write_stdout(stdout, &(format_review_session_json(report) + "\n"))
        }
    }
}

fn format_review_session_json(report: &ReviewSessionReport) -> String {
    serde_json::json!({
        "schema": crate::models::RESPONSE_SCHEMA_V1,
        "success": true,
        "data": report,
    })
    .to_string()
}

fn format_review_session_human(report: &ReviewSessionReport) -> String {
    let mode = if report.dry_run {
        "DRY RUN"
    } else if report.durable_mutation {
        "PROPOSED"
    } else {
        "REVIEW"
    };
    let mut output = format!(
        "{mode}: review session {}\n\n  evidence spans: {}\n  topics: {}\n  candidates: {}\n",
        report.cass_session_id,
        report.evidence_span_count,
        report.topic_count,
        report.candidate_count
    );
    for candidate in &report.candidates {
        output.push_str(&format!(
            "\n  {} [{}] confidence={:.2}\n    target: {}\n    evidence: {}\n    {}\n",
            candidate.candidate_id,
            candidate.topic_key,
            candidate.confidence,
            candidate.target_memory_id,
            candidate.source_ids.join(","),
            candidate.reason
        ));
    }
    output.push_str("\nNext:\n  ");
    output.push_str(&report.next_action);
    output.push('\n');
    output
}

fn handle_search<W, E>(
    cli: &Cli,
    args: &SearchArgs,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    let workspace_path = cli.resolve_workspace();
    let options = SearchOptions {
        workspace_path,
        database_path: args.database.clone(),
        index_dir: args.index_dir.clone(),
        query: args.query.clone(),
        limit: args.limit,
        speed: args.speed,
        explain: args.explain,
        as_of: args.as_of,
        include_tombstoned: args.include_tombstoned,
        include_expired: args.include_expired,
        include_future: args.include_future,
        include_stale: args.include_stale,
        relevance_floor: args.relevance_floor,
        source_mode: args.source_mode,
        strict_source_mode: args.strict_source_mode,
        memory_scope: args.memory_scope,
        strict_scope: args.strict_scope,
    };

    match run_search(&options) {
        Ok(report) if args.explain_performance => write_stdout(
            stdout,
            &(report
                .performance_explain_json(args.speed, args.explain)
                .to_string()
                + "\n"),
        ),
        Ok(report) => match cli.renderer() {
            output::Renderer::Human | output::Renderer::Markdown => {
                write_stdout(stdout, &report.human_summary())
            }
            output::Renderer::Toon => write_stdout(stdout, &(format_search_toon(&report) + "\n")),
            output::Renderer::Json
            | output::Renderer::Jsonl
            | output::Renderer::Compact
            | output::Renderer::Hook => write_stdout(stdout, &(format_search_json(&report) + "\n")),
        },
        Err(error) => {
            let domain_error = DomainError::SearchIndex {
                message: error.to_string(),
                repair: error.repair_hint().map(str::to_string),
            };
            write_domain_error(
                &domain_error,
                cli.wants_json() || args.explain_performance,
                stdout,
                stderr,
            )
        }
    }
}

fn format_search_json(report: &SearchReport) -> String {
    serde_json::json!({
        "schema": crate::models::RESPONSE_SCHEMA_V1,
        "success": true,
        "data": report.data_json(),
    })
    .to_string()
}

fn format_search_toon(report: &SearchReport) -> String {
    output::render_toon_from_json(&format_search_json(report))
}

fn handle_outcome<W, E>(
    cli: &Cli,
    args: &OutcomeArgs,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    let workspace_path = cli.resolve_workspace();
    let database_path = args
        .database
        .clone()
        .unwrap_or_else(|| workspace_path.join(".ee").join("ee.db"));
    let options = OutcomeRecordOptions {
        database_path: &database_path,
        target_type: args.target_type.clone(),
        target_id: args.target_id.clone(),
        workspace_id: args.workspace_id.clone(),
        signal: args.signal.clone(),
        weight: args.weight,
        source_type: args.source_type.clone(),
        source_id: args.source_id.clone(),
        reason: args.reason.clone(),
        evidence_json: args.evidence_json.clone(),
        session_id: args.session_id.clone(),
        event_id: args.event_id.clone(),
        actor: args.actor.clone(),
        agent_name: crate::core::memory_scope::current_agent_name(),
        dry_run: args.dry_run,
        harmful_per_source_per_hour: args.harmful_per_source_per_hour,
        harmful_burst_window_seconds: args.harmful_burst_window_seconds,
    };

    match record_outcome(&options) {
        Ok(report) => match cli.renderer() {
            output::Renderer::Human | output::Renderer::Markdown => {
                write_stdout(stdout, &report.human_summary())
            }
            output::Renderer::Toon => write_stdout(
                stdout,
                &format!(
                    "OUTCOME|{}|{}|{}|{}\n",
                    report.status.as_str(),
                    report.target_type,
                    report.target_id,
                    report.event_id.as_deref().unwrap_or("")
                ),
            ),
            output::Renderer::Json
            | output::Renderer::Jsonl
            | output::Renderer::Compact
            | output::Renderer::Hook => {
                let json = serde_json::json!({
                    "schema": crate::models::RESPONSE_SCHEMA_V1,
                    "success": true,
                    "data": report.data_json(),
                });
                write_stdout(stdout, &(json.to_string() + "\n"))
            }
        },
        Err(error) => write_domain_error(&error, cli.wants_json(), stdout, stderr),
    }
}

