fn handle_certificate_sign<W, E>(
    cli: &Cli,
    args: &CertificateSignArgs,
    stdout: &mut W,
    _stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    let workspace_path = args
        .workspace
        .clone()
        .or_else(|| cli.workspace.clone())
        .unwrap_or_else(|| std::path::PathBuf::from("."));
    let options = crate::core::certificate::SignOptions {
        certificate_id: args.certificate_id.clone(),
        manifest_path: args.manifest.clone(),
        key_path: args.key.clone(),
        workspace_path: Some(workspace_path),
    };
    let report = crate::core::certificate::sign_certificate(&options);
    match cli.renderer() {
        output::Renderer::Json => write_stdout(
            stdout,
            &(crate::core::serialize_pretty_or_error(&report.data_json()) + "\n"),
        ),
        _ => write_stdout(stdout, &(report.human_summary() + "\n")),
    };
    if report.success {
        ProcessExitCode::Success
    } else {
        ProcessExitCode::Storage
    }
}

fn handle_certificate_keygen<W, E>(
    cli: &Cli,
    args: &CertificateKeygenArgs,
    stdout: &mut W,
    stderr: &mut E,
) -> ProcessExitCode
where
    W: Write,
    E: Write,
{
    let workspace_path = args.workspace.clone().or_else(|| cli.workspace.clone());
    let options = crate::core::certificate::KeygenOptions {
        workspace_path,
        force: args.force,
        show_only: args.show,
    };
    match crate::core::certificate::keygen(&options) {
        Ok(report) => {
            match cli.renderer() {
                output::Renderer::Json => write_stdout(
                    stdout,
                    &(crate::core::serialize_pretty_or_error(&report.data_json()) + "\n"),
                ),
                _ => write_stdout(stdout, &(report.human_summary() + "\n")),
            };
            ProcessExitCode::Success
        }
        Err(err) => {
            let _ = writeln!(stderr, "error: {err}");
            ProcessExitCode::Storage
        }
    }
}

fn resolve_certificate_store_source(
    cli: &Cli,
    explicit_manifest: Option<&Path>,
) -> CertificateStoreSource {
    if let Some(manifest_path) = explicit_manifest {
        return CertificateStoreSource::Manifest(manifest_path.to_path_buf());
    }

    let workspace_path =
        resolve_cli_workspace_path(cli.workspace.as_deref().unwrap_or_else(|| Path::new(".")));
    let manifest_path = workspace_path.join(CERTIFICATE_DEFAULT_MANIFEST_FILE);
    if manifest_path.exists() {
        CertificateStoreSource::Manifest(manifest_path)
    } else {
        CertificateStoreSource::Database {
            database_path: workspace_path.join(".ee").join("ee.db"),
            workspace_id: crate::core::curate::stable_workspace_id(&workspace_path),
        }
    }
}

