    fn ensure_repair_command_parses(repair: &str, context: &str) -> TestResult {
        if !repair.starts_with("ee ") || repair.contains('<') || repair.contains('>') {
            return Ok(());
        }

        let args = repair.split_whitespace().collect::<Vec<_>>();
        match Cli::try_parse_from(args) {
            Ok(_) => Ok(()),
            Err(error)
                if matches!(
                    error.kind(),
                    clap::error::ErrorKind::DisplayHelp | clap::error::ErrorKind::DisplayVersion
                ) =>
            {
                Ok(())
            }
            Err(error) => Err(format!(
                "{context}: repair hint {repair:?} must parse, got {:?}",
                error.kind()
            )),
        }
    }

    #[test]
    fn registry_repair_hints_reference_current_cli_surface() -> TestResult {
        for code in ALL_ERROR_CODES {
            if let Some(repair) = code.default_repair {
                ensure_repair_command_parses(repair, code.id)?;
            }
        }
        for code in ALL_DEGRADATION_CODES {
            if let Some(repair) = code.repair {
                ensure_repair_command_parses(repair, code.id)?;
            }
        }
        Ok(())
    }

    #[test]
    fn parser_accepts_global_json_before_or_after_command() -> TestResult {
        let before = Cli::try_parse_from(["ee", "--json", "status"])
            .map(|cli| (cli.json, cli.command))
            .map_err(|error| format!("failed to parse --json before status: {:?}", error.kind()))?;
        let after = Cli::try_parse_from(["ee", "status", "--json"])
            .map(|cli| (cli.json, cli.command))
            .map_err(|error| format!("failed to parse --json after status: {:?}", error.kind()))?;

        ensure_equal(
            &before,
            &(true, Some(Command::Status(StatusArgs::default()))),
            "--json before status parse",
        )?;
        ensure_equal(
            &after,
            &(true, Some(Command::Status(StatusArgs::default()))),
            "--json after status parse",
        )
    }

