    #[test]
    fn context_renderer_format_flag_detection_handles_global_forms() -> TestResult {
        let split = [
            OsString::from("ee"),
            OsString::from("--format"),
            OsString::from("human"),
            OsString::from("context"),
            OsString::from("test"),
        ];
        ensure(
            super::args_contain_format_flag(&split),
            "split --format value should be detected",
        )?;

        let equals = [
            OsString::from("ee"),
            OsString::from("context"),
            OsString::from("test"),
            OsString::from("--format=human"),
        ];
        ensure(
            super::args_contain_format_flag(&equals),
            "--format=value should be detected",
        )?;

        let separator = [
            OsString::from("ee"),
            OsString::from("context"),
            OsString::from("--"),
            OsString::from("--format"),
        ];
        ensure(
            !super::args_contain_format_flag(&separator),
            "format-looking positional query after -- should not be detected",
        )
    }

    #[test]
    fn pack_command_parses_query_file() -> TestResult {
        let parsed = Cli::try_parse_from([
            "ee",
            "pack",
            "build",
            "--query-file",
            "task.eeq.json",
            "--max-tokens",
            "3000",
            "--candidate-pool",
            "42",
            "--speed",
            "quality",
            "--profile",
            "compact",
        ])
        .map_err(|e| format!("failed to parse pack: {:?}", e.kind()))?;

        match parsed.command {
            Some(Command::Pack(ref args)) => match &args.command {
                Some(PackCommand::Build(args)) => {
                    ensure_equal(
                        &args.query_file,
                        &std::path::PathBuf::from("task.eeq.json"),
                        "pack query file",
                    )?;
                    ensure_equal(&args.max_tokens, &Some(3000), "pack max tokens")?;
                    ensure_equal(&args.candidate_pool, &Some(42), "pack candidate pool")?;
                    ensure_equal(
                        &args.speed,
                        &Some(crate::search::SpeedMode::Quality),
                        "pack speed",
                    )?;
                    ensure_equal(&args.profile, &Some("compact".to_string()), "pack profile")
                }
                _ => Err("expected Pack Build command".to_string()),
            },
            _ => Err("expected Pack command".to_string()),
        }
    }

