    #[test]
    fn pack_json_missing_query_file_writes_machine_error_to_stdout() -> TestResult {
        let missing = format!(
            "/tmp/ee-missing-query-file-{}-{}.json",
            std::process::id(),
            "query"
        );
        let (exit, stdout, stderr) =
            invoke(&["ee", "--json", "pack", "--query-file", missing.as_str()]);
        ensure_equal(&exit, &ProcessExitCode::Usage, "pack missing file exit")?;
        ensure_starts_with(
            &stdout,
            "{\"schema\":\"ee.error.v2\"",
            "pack missing file error schema",
        )?;
        ensure_contains(
            &stdout,
            "\"code\":\"ERR_QUERY_FILE_NOT_FOUND\"",
            "query-file-specific error code",
        )?;
        let json: serde_json::Value = serde_json::from_str(&stdout)
            .map_err(|error| format!("query-file error parses: {error}"))?;
        let low = serde_json::json!("low");
        let empty_details = serde_json::json!({});
        ensure_equal(
            &json.pointer("/error/severity"),
            &Some(&low),
            "query-file error severity",
        )?;
        ensure_equal(
            &json.pointer("/error/details"),
            &Some(&empty_details),
            "query-file error details",
        )?;
        ensure(stderr.is_empty(), "pack json error stderr must be empty")
    }

