    #[test]
    fn memory_revise_dry_run_json_reports_preview_without_persistence() -> TestResult {
        let tempdir = tempfile::tempdir().map_err(|error| error.to_string())?;
        let workspace = tempdir.path().to_string_lossy().into_owned();
        let (init_exit, _init_stdout, init_stderr) =
            invoke(&["ee", "--workspace", &workspace, "init", "--json"]);
        ensure_equal(&init_exit, &ProcessExitCode::Success, "init exit")?;
        ensure(init_stderr.is_empty(), "init json stderr clean")?;

        let (remember_exit, remember_stdout, remember_stderr) = invoke(&[
            "ee",
            "--workspace",
            &workspace,
            "remember",
            "Run cargo fmt --check before release.",
            "--level",
            "procedural",
            "--kind",
            "rule",
            "--json",
        ]);
        ensure_equal(&remember_exit, &ProcessExitCode::Success, "remember exit")?;
        ensure(remember_stderr.is_empty(), "remember json stderr clean")?;
        let remembered: serde_json::Value =
            serde_json::from_str(&remember_stdout).map_err(|error| error.to_string())?;
        let memory_id = remembered["data"]["memory_id"]
            .as_str()
            .ok_or_else(|| "remember output missing memory_id".to_string())?;

        let (exit, stdout, stderr) = invoke(&[
            "ee",
            "--workspace",
            &workspace,
            "--json",
            "memory",
            "revise",
            memory_id,
            "--content",
            "Run cargo fmt --check and clippy before release.",
            "--reason",
            "correction",
            "--dry-run",
        ]);
        ensure_equal(&exit, &ProcessExitCode::Success, "revise dry-run exit")?;
        ensure(stderr.is_empty(), "revise dry-run json stderr clean")?;

        let value: serde_json::Value =
            serde_json::from_str(&stdout).map_err(|error| error.to_string())?;
        ensure_equal(
            &value["schema"],
            &serde_json::json!("ee.response.v1"),
            "response schema",
        )?;
        ensure_equal(
            &value["data"]["command"],
            &serde_json::json!("memory revise"),
            "command",
        )?;
        ensure_equal(
            &value["data"]["dry_run"],
            &serde_json::json!(true),
            "dry_run",
        )?;
        ensure_equal(
            &value["data"]["persisted"],
            &serde_json::json!(false),
            "persisted",
        )?;
        ensure_equal(
            &value["data"]["new_id"],
            &serde_json::Value::Null,
            "no stub new_id",
        )?;
        ensure_equal(
            &value["data"]["revision_number"],
            &serde_json::Value::Null,
            "no stub revision number",
        )?;
        ensure_equal(
            &value["data"]["changed_fields"],
            &serde_json::json!(["content"]),
            "changed fields",
        )?;
        // N15.2 (bd-17c65.14.15.3): the dry-run no longer carries a
        // honesty-only degraded code; the abstention is conveyed by
        // `policy: "dry_run_only"` already present in the envelope.
        ensure_equal(
            &value["data"]["degraded"],
            &serde_json::json!([]),
            "degraded code",
        )
    }

    #[test]
    fn memory_revise_non_dry_run_persists_new_revision() -> TestResult {
        // N15.2 (bd-17c65.14.15.3): non-dry-run revisions are real
        // writes. The CLI returns a success envelope with the new
        // memory id, the revision_group_id (= logical_id), and the
        // changed fields list.
        let tempdir = tempfile::tempdir().map_err(|error| error.to_string())?;
        let workspace = tempdir.path().to_string_lossy().into_owned();
        let (init_exit, _init_stdout, init_stderr) =
            invoke(&["ee", "--workspace", &workspace, "init", "--json"]);
        ensure_equal(&init_exit, &ProcessExitCode::Success, "init exit")?;
        ensure(init_stderr.is_empty(), "init json stderr clean")?;

        let (remember_exit, remember_stdout, remember_stderr) = invoke(&[
            "ee",
            "--workspace",
            &workspace,
            "remember",
            "Prefer deterministic context packs.",
            "--level",
            "procedural",
            "--kind",
            "rule",
            "--json",
        ]);
        ensure_equal(&remember_exit, &ProcessExitCode::Success, "remember exit")?;
        ensure(remember_stderr.is_empty(), "remember json stderr clean")?;
        let remembered: serde_json::Value =
            serde_json::from_str(&remember_stdout).map_err(|error| error.to_string())?;
        let memory_id = remembered["data"]["memory_id"]
            .as_str()
            .ok_or_else(|| "remember output missing memory_id".to_string())?;

        let (exit, stdout, stderr) = invoke(&[
            "ee",
            "--workspace",
            &workspace,
            "--json",
            "memory",
            "revise",
            memory_id,
            "--content",
            "Prefer deterministic context packs with provenance.",
        ]);
        ensure_equal(&exit, &ProcessExitCode::Success, "revise exit")?;
        ensure(stderr.is_empty(), "revise json stderr clean")?;

        let value: serde_json::Value =
            serde_json::from_str(&stdout).map_err(|error| error.to_string())?;
        ensure_equal(
            &value["schema"],
            &serde_json::json!("ee.response.v1"),
            "response schema",
        )?;
        ensure_equal(
            &value["data"]["dry_run"],
            &serde_json::json!(false),
            "dry_run is false",
        )?;
        ensure_equal(
            &value["data"]["persisted"],
            &serde_json::json!(true),
            "persisted",
        )?;
        ensure(
            value["data"]["new_id"]
                .as_str()
                .map(|s| !s.is_empty())
                .unwrap_or(false),
            "new_id is a non-empty string",
        )?;
        ensure_equal(
            &value["data"]["revision_group_id"],
            &serde_json::json!(memory_id),
            "revision_group_id equals original id (singleton chain → revision 2)",
        )?;
        ensure_equal(
            &value["data"]["revision_number"],
            &serde_json::json!(2),
            "revision_number = 2 (original was 1, this revision is 2)",
        )?;
        ensure_equal(
            &value["data"]["changed_fields"],
            &serde_json::json!(["content"]),
            "changed_fields = [content]",
        )?;
        ensure_equal(
            &value["data"]["degraded"],
            &serde_json::json!([]),
            "no degraded codes on successful revision",
        )
    }

